SK_SpellTR = {
   ["A balanced combat stance that increases the armor penetration of all of your attacks by {1}%."] = "Tüm saldırılarınızın zırh delme oranını %{1} artıran dengeli bir savaş duruşu.",
   ["A brutal instant attack that deals {1}% weapon damage plus {2}, total damage increased {3}.{4}% per each of your diseases on the target, but consumes the diseases."] = "%{1} silah hasarı artı {2} veren, hedefindeki her hastalığın için toplam hasarı %{3}.{4} artan ama hastalıkları tüketen acımasız anında bir saldırı.",
   ["A burst of Holy energy fills the caster, increasing armor by {1} and spell power by {2}. Each melee or ranged damage hit against the priest will remove one charge. Lasts {3} min or until {4} charges are used."] = "Büyücüyü bir Kutsal enerji patlaması doldurarak zırhı {1}, büyü gücünü {2} artırır. Priest'e gelen her yakın dövüş veya menzilli hasar vuruşu bir yük kaldırır. {3} dk veya {4} yük kullanılana kadar sürer.",
   ["A burst of Holy energy fills the caster, increasing armor by {1}. Each melee or ranged damage hit against the priest will remove one charge. Lasts {2} min or until {3} charges are used."] = "Büyücüyü bir Kutsal enerji patlaması doldurarak zırhı {1} artırır. Priest'e gelen her yakın dövüş veya menzilli hasar vuruşu bir yük kaldırır. {2} dk veya {3} yük kullanılana kadar sürer.",
   ["A concussive strike that reduces movement speed by {1}%."] = "Hareket hızını %{1} azaltan sersemletici bir vuruş.",
   ["A deadly attack that deals {1}% weapon damage plus {2} and heals the Death Knight for {3}% of her maximum health for each of her diseases on the target."] = "%{1} silah hasarı artı {2} veren ve hedefteki her hastalığı için Death Knight'ı azami canının %{3} kadarı iyileştiren ölümcül bir saldırı.",
   ["A deadly attack that deals {1}% weapon damage plus {2} and heals the Death Knight for {3}% of his maximum health for each of his diseases on the target."] = "%{1} silah hasarı artı {2} veren ve hedefindeki her hastalığı için Death Knight'ı maksimum sağlığının %{3}'ü kadar iyileştiren ölümcül bir saldırı.",
   ["A defensive combat stance. Decreases damage taken by {1}% and damage caused by {2}%. Increases threat generated."] = "Savunma amaçlı bir savaş duruşu. Alınan hasarı %{1}, verilen hasarı %{2} azaltır. Üretilen tehdidi artırır.",
   ["A disease dealing {1} Frost damage every {2} sec and reducing the target's melee and ranged attack speed by {3}% for {4} sec. Caused by Icy Touch and other spells. Base damage {5} Bonus from attack power {6}"] = "Her {2} sn'de {1} Buz hasarı veren ve hedefin yakın dövüş ve menzilli saldırı hızını {4} sn boyunca %{3} azaltan bir hastalık. Icy Touch ve diğer büyüler tarafından oluşturulur. Temel hasar {5} Saldırı gücünden bonus {6}",
   ["A disease dealing {1} Shadow damage every {2} sec for {3} sec. Caused by Plague Strike and other abilities. Base damage {4} Bonus from attack power {5}"] = "{3} sn boyunca her {2} sn'de {1} Gölge hasarı veren bir hastalık. Plague Strike ve diğer yetenekler tarafından oluşturulur. Temel hasar {4} Saldırı gücünden bonus {5}",
   ["A mocking attack that causes a moderate amount of threat and forces the target to focus attacks on you for {1} sec. If the target is tauntable, also deals weapon damage."] = "Orta düzeyde tehdit oluşturan ve hedefi {1} sn boyunca saldırılarını size yöneltmeye zorlayan alaycı bir saldırı. Hedef alay edilebilirse silah hasarı da verir.",
   ["A powerful prayer heals the friendly target's party members within {1} yards for {2} to {3}."] = "Güçlü bir dua, dost hedefin {1} yard içindeki grup üyelerini {2} ila {3} iyileştirir.",
   ["A quick kick that interrupts spellcasting and prevents any spell in that school from being cast for {1} sec."] = "Büyü yapmayı kesen ve o okuldaki herhangi bir büyünün {1} sn boyunca yapılmasını engelleyen hızlı bir tekme.",
   ["A short-range shot that deals {1}% weapon damage and disorients the target for {2} sec. Any damage caused will remove the effect. Turns off your attack when used."] = "Silah hasarının %{1} kadarını veren ve hedefi {2} sn boyunca şaşırtan kısa menzilli bir atış. Verilen herhangi bir hasar etkiyi kaldırır. Kullanıldığında saldırını kapatır.",
   ["A slow casting spell that heals a single target for {1} to {2}."] = "Tek bir hedefi {1} ila {2} iyileştiren yavaş okunan bir büyü.",
   ["A steady shot that causes unmodified weapon damage, plus ammo, plus {1}. Causes an additional {2} against Dazed targets."] = "Değiştirilmemiş silah hasarı artı cephane artı {1} veren sabit bir atış. Sersemlemiş hedeflere ek {2} verir.",
   ["A stinging shot that puts the target to sleep for {1} sec. Any damage will cancel the effect. When the target wakes up, the Sting causes {2} Nature damage over {3} sec. Only usable out of combat. Only one Sting per Hunter can be active on the target at a time."] = "Hedefi {1} sn boyunca uyutan acı verici bir atış. Herhangi bir hasar etkiyi iptal eder. Hedef uyandığında, Sting {3} sn boyunca {2} Doğa hasarı verir. Yalnızca savaş dışında kullanılabilir. Bir Hunter'ın bir hedefte aynı anda yalnızca bir Sting'i aktif olabilir.",
   ["A strike that becomes active after parrying an opponent's attack. This attack deals {1} damage and immobilizes the target for {2} sec. Counterattack cannot be blocked, dodged, or parried."] = "Rakibin saldırısını savuşturduktan sonra aktif hale gelen bir vuruş. Bu saldırı {1} hasar verir ve hedefi {2} sn boyunca hareketsiz bırakır. Counterattack bloklanamaz, sıyrılamaz veya savuşturulamaz.",
   ["A strike that becomes active after parrying an opponent's attack. This attack deals {1}% weapon damage and disarms the target for {2} sec."] = "Rakibin saldırısını savuşturduktan sonra aktif hale gelen bir vuruş. Bu saldırı silah hasarının %{1} kadarını verir ve hedefi {2} sn boyunca silahsız bırakır.",
   ["A strike that deals {1}% weapon damage and increases your chance to dodge by {2}% for {3} sec. Awards {4} combo point."] = "Silah hasarının %{1} kadarını veren ve {3} sn boyunca sıyırma şansını %{2} artıran bir vuruş. {4} combo puanı kazandırır.",
   ["A strong attack that increases melee damage by {1} and causes a high amount of threat."] = "Yakın dövüş hasarını {1} artıran ve yüksek miktarda tehdit oluşturan güçlü bir saldırı.",
   ["A strong attack that increases melee damage by {1} and causes a high amount of threat. Causes {2} additional damage against Dazed targets."] = "Yakın dövüş hasarını {1} artıran ve yüksek miktarda tehdit oluşturan güçlü bir saldırı. Sersemlemiş hedeflere {2} ek hasar verir.",
   ["A strong attack that increases melee damage by {1} and causes a high amount of threat. Effects which increase Bleed damage also increase Maul damage."] = "Yakın dövüş hasarını {1} artıran ve yüksek miktarda tehdit oluşturan güçlü bir saldırı. Kanama hasarını artıran etkiler Maul hasarını da artırır.",
   ["A strong attack that increases melee damage by {1}."] = "Yakın dövüş hasarını {1} artıran güçlü bir saldırı.",
   ["A sweeping attack that does your weapon damage plus {1} to the target and his nearest ally."] = "Hedefe ve onun en yakın müttefikine silah hasarınız artı {1} veren geniş bir saldırı.",
   ["A targeted party or raid member is protected from all physical attacks for {1} sec, but during that time they cannot attack or use physical abilities. Players may only have one Hand on them per Paladin at any one time. Once protected, the target cannot be targeted by Divine Shield, Divine Protection, or Hand of Protection again for {2} min. Cannot be targeted on players who have used Avenging Wrath within the last {3} sec."] = "Hedeflenen bir grup veya raid üyesi {1} sn boyunca tüm fiziksel saldırılardan korunur, ancak bu süre boyunca saldıramaz veya fiziksel yetenek kullanamaz. Oyuncuların üzerinde Paladin başına aynı anda yalnızca bir Hand bulunabilir. Korunduktan sonra hedef {2} dk boyunca tekrar Divine Shield, Divine Protection veya Hand of Protection ile hedeflenemez. Son {3} sn içinde Avenging Wrath kullanmış oyuncularda hedeflenemez.",
   ["A vicious strike that deals weapon damage plus {1} and wounds the target, reducing the effectiveness of any healing by {2}% for {3} sec."] = "Silah hasarına ek olarak {1} hasar veren ve hedefi yaralayarak {3} sn boyunca tüm iyileştirmelerin etkinliğini %{2} azaltan acımasız bir vuruş.",
   ["A vicious strike that deals {1}% weapon damage plus {2} and infects the target with Blood Plague, a disease dealing Shadow damage over time."] = "Hedefe %{1} silah hasarı artı {2} veren ve onu zamanla Gölge hasarı veren bir hastalık olan Blood Plague ile enfekte eden acımasız bir vuruş.",
   ["A wave of flame radiates outward from the caster, damaging all enemies caught within the blast for {1} to {2} Fire damage, and dazing them for {3} sec."] = "Büyüyü yapandan dışa doğru yayılan bir alev dalgası, patlamanın menzilindeki tüm düşmanlara {1} ila {2} Ateş hasarı verir ve onları {3} sn boyunca sersemletir.",
   ["A word of dark binding that inflicts {1} to {2} Shadow damage to the target. If the target is not killed by Shadow Word: Death, the caster takes damage equal to the damage inflicted upon the target."] = "Hedefe {1} ila {2} Gölge hasarı veren karanlık bir bağlama sözü. Hedef Shadow Word: Death ile öldürülmezse büyücü, hedefe verilen hasara eşit hasar alır.",
   ["A word of darkness that causes {1} Shadow damage over {2} sec."] = "{2} sn boyunca {1} Gölge hasarı veren karanlık bir söz.",
   ["Absorbs {1} damage, draining mana instead. Drains {2}.{3} mana per damage absorbed. Lasts {4} min."] = "{1} hasar emer, bunun yerine mana tüketir. Emilen her hasar için {2}.{3} mana tüketir. {4} dk sürer.",
   ["Absorbs {1} Fire damage. Lasts {2} sec."] = "{1} Ateş hasarı emer. {2} sn sürer.",
   ["Absorbs {1} Frost damage. Lasts {2} sec."] = "{1} Buz hasarı emer. {2} sn sürer.",
   ["Absorbs {1} shadow damage. Lasts {2} sec."] = "{1} Gölge hasarı emer. {2} sn sürer.",
   ["Adds a chill effect to your Blizzard spell. This effect lowers the target's movement speed by {1}%. Lasts {2}.{3} sec."] = "Blizzard büyüne bir soğukluk etkisi ekler. Bu etki hedefin hareket hızını %{1} azaltır. {2}.{3} sn sürer.",
   ["Affixes your one-handed rune weapon with a rune that deflects {1}% of all spell damage and reduces the duration of Silence effects by {2}% (not cumulative with additional Silence duration reduction). Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Tek elli rün silahınıza, tüm büyü hasarının %{1} kadarını saptıran ve susturma etkilerinin süresini %{2} azaltan bir rün ekler (ek susturma süresi azaltmasıyla birikmez). Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your one-handed rune weapon with a rune that increases Parry chance by {1}% and reduces the duration of Disarm effects by {2}%. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Tek elli rün silahınıza, savuşturma şansını %{1} artıran ve Disarm etkilerinin süresini %{2} azaltan bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your rune weapon with a rune that adds {1}% extra weapon damage as Fire damage or {2}% versus Undead targets. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Rün silahınıza, %{1} ek silah hasarını Ateş hasarı olarak ekleyen veya Undead hedeflere karşı %{2} ekleyen bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your rune weapon with a rune that has a chance to heal you for {1}% and increase total Strength by {2}% for {3} sec. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Rün silahınıza, sizi %{1} iyileştirme ve toplam Strength'i {3} sn boyunca %{2} artırma şansı olan bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your rune weapon with a rune that has a chance to increase the damage by {1}% for your next {2} attacks that deal Frost or Shadow damage. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Rün silahınıza, Buz veya Gölge hasarı veren sonraki {2} saldırınızın hasarını %{1} artırma şansı olan bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your rune weapon with a rune that increases Defense by {1} and total Stamina by {2}%. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Rün silahınıza, Defense'i {1} ve toplam Stamina'yı %{2} artıran bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your two-handed rune weapon with a rune that deflects {1}% of all spell damage and reduces the duration of Silence effects by {2}%. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "İki elli rün silahınıza, tüm büyü hasarının %{1} kadarını saptıran ve susturma etkilerinin süresini %{2} azaltan bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your two-handed rune weapon with a rune that increases Defense by {1} and total Stamina by {2}%. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "İki elli rün silahınıza, Defense'i {1} ve toplam Stamina'yı %{2} artıran bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your two-handed rune weapon with a rune that increases Parry chance by {1}% and reduces the duration of Disarm effects by {2}%. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "İki elli rün silahınıza, savuşturma şansını %{1} artıran ve Disarm etkilerinin süresini %{2} azaltan bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Affixes your weapon with a rune that causes {1}% extra weapon damage as Frost damage and increases enemies' vulnerability to your Frost attacks. Modifying your rune weapon requires a Rune Forge in Ebon Hold."] = "Silahınıza, %{1} ek silah hasarını Buz hasarı olarak veren ve düşmanların Buz saldırılarınıza karşı savunmasızlığını artıran bir rün ekler. Rün silahınızı değiştirmek Ebon Hold'da bir Rune Forge gerektirir.",
   ["Afflicts the target with a disease that causes {1} Shadow damage over {2} sec. {3}% of damage caused by the Devouring Plague heals the caster. This spell can only affect one target at a time."] = "Hedefi, {2} sn boyunca {1} Gölge hasarı veren bir hastalıkla etkiler. Devouring Plague'in verdiği hasarın %{3} kadarı büyücüyü iyileştirir. Bu büyü aynı anda yalnızca bir hedefi etkileyebilir.",
   ["Afflicts your target with Shadow energy that causes all party members to be healed for {1}% of any Shadow spell damage you deal for {2} min."] = "Hedefini Gölge enerjisiyle etkiler; {2} dk boyunca verdiğin tüm Gölge büyü hasarının %{1} kadarı tüm grup üyelerini iyileştirir.",
   ["After being struck by a melee or ranged critical hit, heal {1}% of the damage taken over {2} sec."] = "Bir yakın dövüş veya menzilli kritik vuruş aldıktan sonra, alınan hasarın %{1} kadarını {2} sn boyunca iyileştirir.",
   ["After getting a critical effect from your Flash of Light, Holy Light, or Holy Shock heal spell, gives you a {1}% chance to gain Mana equal to the base cost of the spell."] = "Flash of Light, Holy Light veya Holy Shock iyileştirme büyünden kritik bir etki aldıktan sonra, sana büyünün temel maliyeti kadar Mana kazanma şansı %{1} verir.",
   ["After killing an opponent that yields experience or honor, gives you a {1}% increased critical strike chance on your next Sinister Strike, Backstab, Ambush, or Ghostly Strike. Lasts {2} sec."] = "Deneyim veya onur veren bir rakibi öldürdükten sonra, bir sonraki Sinister Strike, Backstab, Ambush veya Ghostly Strike saldırında sana %{1} artırılmış kritik vurma şansı verir. {2} sn sürer.",
   ["After landing a melee critical strike, you enter a Focused state. The Focused state reduces the mana cost of your next Shock spell by {1}%."] = "Bir yakın dövüş kritik vuruşu yaptıktan sonra Focused durumuna girersiniz. Focused durumu sonraki Shock büyünüzün mana maliyetini %{1} azaltır.",
   ["After taking a critical hit you gain the Focused Will effect, reducing all damage taken by {1}% and increasing healing effects on you by {2}%. Stacks up to {3} times. Lasts {4} sec."] = "Bir kritik vuruş aldıktan sonra Focused Will etkisini kazanırsınız; alınan tüm hasarı %{1} azaltır ve üzerinizdeki iyileştirme etkilerini %{2} artırır. {3} kata kadar birikir. {4} sn sürer.",
   ["All criticals against you cause a percentage of the damage taken to the attacker as well. The damage caused by Eye for an Eye will not exceed {1}% of the Paladin's total health."] = "Size karşı yapılan tüm kritikler, alınan hasarın bir yüzdesini saldırgana da verir. Eye for an Eye'ın verdiği hasar, Paladin'in toplam canının %{1} kadarını aşmaz.",
   ["All party or raid members within {1} yards lose {2}% less casting or channeling time when damaged. Players may only have one Aura on them per Paladin at any one time."] = "{1} yard içindeki tüm grup veya raid üyeleri, hasar aldıklarında %{2} daha az okuma veya kanalize etme süresi kaybeder. Oyuncuların üzerinde Paladin başına aynı anda yalnızca bir Aura bulunabilir.",
   ["All spell criticals against you cause {1}% of the damage taken to the caster as well. The damage caused by Eye for an Eye will not exceed {2}% of the Paladin's total health."] = "Sana karşı yapılan tüm büyü kritikleri, alınan hasarın %{1} kadarını büyüyü yapana da verir. Eye for an Eye'ın verdiği hasar Paladin'in toplam canının %{2} kadarını aşmaz.",
   ["All spell criticals grace you with a blessing of nature, reducing the casting time of your next spell by {1}.{2} sec."] = "Tüm büyü kritikleri sana bir doğa kutsaması bahşeder; bir sonraki büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Allows a jewelcrafter to make fantastic jewelry, up to a maximum potential skill of {1}."] = "Bir jewelcrafter'ın {1} azami potansiyel beceriye kadar muhteşem mücevherler yapmasına olanak tanır.",
   ["Allows a physician to make and use bandages up to a potential skill of {1}. The cloth used to make those bandages are found on humanoids in the world."] = "Bir sağlıkçının {1} potansiyel beceriye kadar bandaj yapıp kullanmasını sağlar. Bu bandajları yapmak için kullanılan kumaş, dünyadaki humanoidlerde bulunur.",
   ["Allows an engineer to make bombs and gizmos that very often work as intended up to a maximum potential skill of {1}."] = "Bir engineer'in {1} azami potansiyel beceriye kadar çoğu zaman amaçlandığı gibi çalışan bombalar ve aletler yapmasına olanak tanır.",
   ["Allows opening of locked chests and doors."] = "Kilitli sandıkların ve kapıların açılmasına olanak tanır.",
   ["Allows the caster to see through the target's eyes for {1} min."] = "Büyücünün {1} dk boyunca hedefin gözlerinden görmesine olanak tanır.",
   ["Allows the caster to see through the target's eyes for {1} min. Will not work if the target is in another instance or on another continent."] = "Büyücünün {1} dk boyunca hedefin gözlerinden görmesine olanak tanır. Hedef başka bir instance'da veya başka bir kıtadaysa çalışmaz.",
   ["Allows the Death Knight to emblazon their weapon with runes."] = "Death Knight'ın silahını rünlerle süslemesine olanak tanır.",
   ["Allows the Druid to prowl around, but reduces your movement speed by {1}%. Lasts until cancelled."] = "Druid'in sinsice dolaşmasına olanak tanır, ancak hareket hızınızı %{1} azaltır. İptal edilene kadar sürer.",
   ["Allows the friendly party or raid target to levitate, floating a few feet above the ground. While levitating, the target will fall at a reduced speed and travel over water. Any damage will cancel the effect. Lasts {1} min."] = "Dost grup veya raid hedefinin yerden birkaç ayak yukarıda süzülmesine olanak tanır. Süzülürken hedef azalan bir hızla düşer ve su üzerinde ilerler. Herhangi bir hasar etkiyi iptal eder. {1} dk sürer.",
   ["Allows the friendly target to detect lesser invisibility for {1} min."] = "Dost hedefin {1} dk boyunca düşük görünmezliği tespit etmesine olanak tanır.",
   ["Allows the friendly target to walk across water for {1} min. Any damage will cancel the effect."] = "Dost hedefin {1} dk boyunca su üzerinde yürümesine olanak tanır. Herhangi bir hasar etkiyi iptal eder.",
   ["Allows the player to ride flying mounts in Northrend."] = "Oyuncunun Northrend'de uçan bineklere binmesine olanak tanır.",
   ["Allows the rogue to sneak around, but reduces your speed by {1}%. Lasts until cancelled."] = "Rogue'un sinsice dolaşmasına olanak tanır, ancak hızınızı %{1} azaltır. İptal edilene kadar sürer.",
   ["Allows the rogue to vanish from sight, entering an improved stealth mode for {1} sec. Also breaks movement impairing effects."] = "Rogue'un gözden kaybolup {1} sn boyunca gelişmiş bir gizlilik moduna girmesine olanak tanır. Ayrıca hareket engelleyici etkileri kırar.",
   ["Allows the rogue to vanish from sight, entering an improved stealth mode for {1} sec. Also breaks movement impairing effects. More effective than Vanish (Rank {2})."] = "Rogue'un gözden kaybolup {1} sn boyunca gelişmiş bir gizlilik moduna girmesine olanak tanır. Ayrıca hareket engelleyici etkileri kırar. Vanish (Rank {2}) büyüsünden daha etkilidir.",
   ["Allows the target to breathe underwater for {1} min."] = "Hedefin {1} dk boyunca su altında nefes almasına olanak tanır.",
   ["Allows you to resurrect yourself upon death with {1}% health and mana."] = "Öldüğünüzde kendinizi %{1} can ve manayla diriltmenize olanak tanır.",
   ["Allows you to use Two-Handed Axes and Two-Handed Maces."] = "İki El Baltaları ve İki El Topuzları kullanmanı sağlar.",
   ["Allows your Shield Block ability to block an additional attack and increases the duration by {1} second."] = "Shield Block yeteneğinin ek bir saldırıyı bloklamasını sağlar ve süresini {1} saniye artırır.",
   ["Allows your Shield Block ability to block an additional attack and increases the duration by {1} seconds."] = "Shield Block yeteneğinin ek bir saldırıyı bloklamasını sağlar ve süresini {1} saniye artırır.",
   ["Allows your Shield Block ability to block an additional attack and increases the duration by {1}.{2} second."] = "Shield Block yeteneğinin ek bir saldırıyı bloklamasını sağlar ve süresini {1}.{2} saniye artırır.",
   ["Allows {1}% of your Mana regeneration to continue while casting."] = "Mana yenilenmenin %{1} kadarının büyü yaparken devam etmesini sağlar.",
   ["Ambush the target, causing {1}% weapon damage plus {2} to the target. Must be stealthed and behind the target. Requires a dagger in the main hand. Awards {3} combo points."] = "Hedefe pusu kurarak %{1} silah hasarı artı {2} verir. Gizlenmiş ve hedefin arkasında olmalısınız. Ana elde bir hançer gerektirir. {3} combo point kazandırır.",
   ["Amplifies magic used against the targeted party member, increasing damage taken from spells by up to {1} and healing spells by up to {2}. Lasts {3} min."] = "Hedeflenen grup üyesine karşı kullanılan büyüyü güçlendirir; büyülerden alınan hasarı {1} kadar ve iyileştirme büyülerini {2} kadar artırır. {3} dk sürer.",
   ["An aggressive stance. Critical hit chance is increased by {1}% and all damage taken is increased by {2}%."] = "Saldırgan bir duruş. Kritik vurma şansı %{1} ve alınan tüm hasar %{2} artar.",
   ["An aimed shot that increases ranged damage by {1}."] = "Menzilli hasarı {1} artıran nişanlı bir atış.",
   ["An instant shot that causes {1} Arcane damage."] = "{1} Arcane hasarı veren anında bir atış.",
   ["An instant strike that causes {1} damage in addition to {2}% of your normal weapon damage. Awards {3} combo point."] = "Normal silah hasarınızın %{2} kadarına ek olarak {1} hasar veren anında bir vuruş. {3} combo point kazandırır.",
   ["An instant strike that causes {1}% weapon damage."] = "%{1} silah hasarı veren anında bir vuruş.",
   ["An instant strike that damages the opponent and causes the target to hemorrhage, increasing any Physical damage dealt to the target by up to {1}. Lasts {2} charges or {3} sec. Awards {4} combo points."] = "Rakibe hasar veren ve hedefin kanamasına neden olan anlık bir vuruş; hedefe verilen tüm Fiziksel hasarı {1} kadar artırır. {2} şarj veya {3} sn sürer. {4} combo puanı kazandırır.",
   ["Assault the target's mind with Shadow energy, causing {1} Shadow damage over {2} sec and slowing their movement speed by {3}%."] = "Hedefin zihnine Gölge enerjisiyle saldırır; {2} sn boyunca {1} Gölge hasarı verir ve hareket hızlarını %{3} yavaşlatır.",
   ["Assault the target's mind with Shadow energy, causing {1} Shadow damage over {2}.{3} sec and slowing their movement speed by {4}%."] = "Hedefin zihnine Gölge enerjisiyle saldırarak {2}.{3} sn boyunca {1} Gölge hasarı verir ve hareket hızını %{4} yavaşlatır.",
   ["Assume a Shadowform, increasing your Shadow damage by {1}% and reducing Physical damage done to you by {2}%. However, you may not cast Holy spells while in this form."] = "Bir Shadowform'a bürünürsün; Gölge hasarını %{1} artırır ve sana verilen Fiziksel hasarı %{2} azaltır. Ancak bu formdayken Kutsal büyüler yapamazsın.",
   ["Attack the enemy for {1} damage."] = "Düşmana {1} hasar verir.",
   ["Attack with an equipped wand."] = "Kuşanılmış bir wand ile saldırır.",
   ["Attempt to finish off a wounded foe, causing damage and converting each extra point of rage into additional damage. Only usable on enemies that have less than {1}% health."] = "Yaralı bir düşmanı bitirmeye çalışır; hasar verir ve her ekstra öfke puanını ek hasara dönüştürür. Yalnızca canı %{1} değerinin altında olan düşmanlarda kullanılabilir.",
   ["Attempt to finish off a wounded foe, causing {1} damage and converting each extra point of rage into {2} additional damage (up to a maximum cost of {3} rage). Only usable on enemies that have less than {4}% health."] = "Yaralı bir düşmanı bitirmeye çalışır; {1} hasar verir ve her ekstra öfke puanını {2} ek hasara dönüştürür (azami {3} öfke maliyetine kadar). Yalnızca canı %{4} değerinin altında olan düşmanlarda kullanılabilir.",
   ["Attempts to cure {1} disease effect on the target, and {2} more disease effect every {3} seconds for {4} sec."] = "Hedefteki {1} hastalık etkisini, ayrıca {4} sn boyunca her {3} sn'de bir {2} hastalık etkisini daha iyileştirmeye çalışır.",
   ["Attempts to cure {1} poison effect on the target, and {2} more poison effect every {3} seconds for {4} sec."] = "Hedefteki {1} zehir etkisini, ayrıca {4} sn boyunca her {3} sn'de bir {2} zehir etkisini daha iyileştirmeye çalışır.",
   ["Attempts to remove {1} Enrage and {2} Magic effect from an enemy target."] = "Bir düşman hedeften {1} Enrage etkisini ve {2} büyü etkisini kaldırmaya çalışır.",
   ["Automatically attacks a target in melee with an equipped weapon until cancelled."] = "İptal edilene kadar kuşanılmış bir silahla bir hedefe yakın dövüşte otomatik olarak saldırır.",
   ["Automatically shoots the target until cancelled. Ranged attacks fired by a Hunter all have {1}% increased attack speed."] = "İptal edilene kadar hedefe otomatik olarak ateş eder. Bir Hunter tarafından yapılan menzilli saldırıların tümü %{1} artmış saldırı hızına sahiptir.",
   ["Backstab the target, causing {1}% weapon damage plus {2} to the target. Must be behind the target. Requires a dagger in the main hand. Awards {3} combo point."] = "Hedefi arkadan bıçaklayarak %{1} silah hasarı artı {2} verir. Hedefin arkasında olmalısınız. Ana elde bir hançer gerektirir. {3} combo point kazandırır.",
   ["Banishes the enemy target, preventing all action but making it invulnerable for up to {1} sec. Only one target can be banished at a time. Casting Banish on a banished target will cancel the spell. Only works on Demons and Elementals."] = "Düşman hedefi sürgün eder; tüm eylemleri engeller ancak onu {1} sn'ye kadar dokunulmaz yapar. Aynı anda yalnızca bir hedef sürgün edilebilir. Sürgün edilmiş bir hedefe Banish büyüsü yapmak büyüyü iptal eder. Yalnızca Demon ve Elemental'larda çalışır.",
   ["Bash the target with your shield dazing them and interrupting spellcasting, which prevents any spell in that school from being cast for {1} sec."] = "Hedefi kalkanınızla vurarak sersemletir ve büyü yapmayı keser; bu, o okuldaki herhangi bir büyünün {1} sn boyunca yapılmasını engeller.",
   ["Begins a ritual that creates a refreshment table. Raid members can click the table to acquire Conjured Mana Biscuits. The tables lasts for {1} min or {2} charges. Requires the caster and {3} additional party members to complete the ritual. In order to participate, all players must right-click the refreshment portal and not move until the ritual is complete."] = "Bir ikram masası oluşturan bir ritüel başlatır. Raid üyeleri Conjured Mana Biscuits almak için masaya tıklayabilir. Masa {1} dk veya {2} yük boyunca sürer. Ritüeli tamamlamak için büyücü ve {3} ek grup üyesi gerekir. Katılmak için tüm oyuncular ikram portalına sağ tıklamalı ve ritüel tamamlanana kadar hareket etmemelidir.",
   ["Begins a ritual that creates a refreshment table. Raid members can click the table to acquire Conjured Mana Strudels. The tables lasts for {1} min or {2} charges. Requires the caster and {3} additional party members to complete the ritual. In order to participate, all players must right-click the refreshment portal and not move until the ritual is complete."] = "Bir ikram masası oluşturan bir ritüel başlatır. Raid üyeleri Conjured Mana Strudels almak için masaya tıklayabilir. Masa {1} dk veya {2} yük boyunca sürer. Ritüeli tamamlamak için büyücü ve {3} ek grup üyesi gerekir. Katılmak için tüm oyuncular ikram portalına sağ tıklamalı ve ritüel tamamlanana kadar hareket etmemelidir.",
   ["Begins a ritual that creates a Soulwell. Raid members can click the Soulwell to acquire a Fel Healthstone. The Soulwell lasts for {1} min or {2} charges. Requires the caster and {3} additional party members to complete the ritual. In order to participate, all players must right-click the soul portal and not move until the ritual is complete."] = "Bir Soulwell oluşturan bir ritüel başlatır. Raid üyeleri Fel Healthstone almak için Soulwell'e tıklayabilir. Soulwell {1} dk veya {2} yük boyunca sürer. Ritüeli tamamlamak için büyücü ve {3} ek grup üyesi gerekir. Katılmak için tüm oyuncular ruh portalına sağ tıklamalı ve ritüel tamamlanana kadar hareket etmemelidir.",
   ["Begins a ritual that creates a Soulwell. Raid members can click the Soulwell to acquire a Master Healthstone. The Soulwell lasts for {1} min or {2} charges. Requires the caster and {3} additional party members to complete the ritual. In order to participate, all players must right-click the soul portal and not move until the ritual is complete."] = "Bir Soulwell oluşturan bir ritüel başlatır. Raid üyeleri Master Healthstone almak için Soulwell'e tıklayabilir. Soulwell {1} dk veya {2} yük boyunca sürer. Ritüeli tamamlamak için büyücü ve {3} ek grup üyesi gerekir. Katılmak için tüm oyuncular ruh portalına sağ tıklamalı ve ritüel tamamlanana kadar hareket etmemelidir.",
   ["Begins a ritual that creates a summoning portal. The summoning portal can be used by {1} party or raid members to summon a targeted party or raid member. The ritual portal requires the caster and {2} additional party or raid members to complete. In order to participate, all players must be out of combat and right-click the portal and not move until the ritual is complete."] = "Bir çağırma portalı oluşturan bir ritüel başlatır. Çağırma portalı, hedeflenen bir grup veya raid üyesini çağırmak için {1} grup veya raid üyesi tarafından kullanılabilir. Ritüel portalı tamamlamak için büyücü ve {2} ek grup veya raid üyesi gerektirir. Katılmak için tüm oyuncular savaş dışında olmalı, portala sağ tıklamalı ve ritüel tamamlanana kadar hareket etmemelidir.",
   ["Begins a ritual that sacrifices a random participant's health to summon a doomguard. Requires the caster and {1} additional party members to complete the ritual. In order to participate, all players must right-click the portal and not move until the ritual is complete."] = "Rastgele bir katılımcının canını feda ederek bir doomguard çağıran bir ritüel başlatır. Ritüeli tamamlamak için büyücü ve {1} ek grup üyesi gerekir. Katılmak için tüm oyuncular portala sağ tıklamalı ve ritüel tamamlanana kadar hareket etmemelidir.",
   ["Begins taming a beast to be your companion. Your armor is reduced by {1}% while you focus on taming the beast for {2} sec. If you lose the beast's attention for any reason, the taming process will fail. Once tamed, the beast will be very unhappy and disloyal. Try feeding the pet immediately to make it happy."] = "Bir canavarı yoldaşınız olması için evcilleştirmeye başlar. Canavarı evcilleştirmeye {2} sn boyunca odaklanırken zırhınız %{1} azalır. Canavarın dikkatini herhangi bir nedenle kaybederseniz evcilleştirme süreci başarısız olur. Evcilleştirildikten sonra canavar çok mutsuz ve sadakatsiz olacaktır. Onu mutlu etmek için pet'i hemen beslemeyi deneyin.",
   ["Blasts enemies near the caster for {1} to {2} Frost damage and freezes them in place for up to {3} sec. Damage caused may interrupt the effect."] = "Büyücünün yakınındaki düşmanlara bir patlamayla {1} ila {2} Buz hasarı verir ve onları {3} sn'ye kadar oldukları yerde dondurur. Verilen hasar etkiyi kesebilir.",
   ["Blasts nearby enemies increasing the time between their attacks by {1}% for {2} sec and doing {3} damage to them. Damage increased by attack power. This ability causes additional threat."] = "Yakındaki düşmanlara patlama yaparak saldırıları arasındaki süreyi {2} sn boyunca %{1} artırır ve onlara {3} hasar verir. Hasar saldırı gücüyle artar. Bu yetenek ek tehdit oluşturur.",
   ["Blasts the enemy for {1} to {2} Fire damage."] = "Düşmana bir patlamayla {1} ila {2} Ateş hasarı verir.",
   ["Blasts the target for {1} to {2} Shadow damage."] = "Hedefe bir patlamayla {1} ila {2} Gölge hasarı verir.",
   ["Blasts the target with energy, dealing {1} to {2} Arcane damage. Each time you cast Arcane Blast, the damage of all Arcane spells is increased by {3}% and mana cost of Arcane Blast is increased by {4}%. Effect stacks up to {5} times and lasts {6} sec or until any Arcane damage spell except Arcane Blast is cast."] = "Hedefe enerjiyle bir patlama yaparak {1} ila {2} Arcane hasarı verir. Arcane Blast büyüsünü her yaptığınızda tüm Arcane büyülerinin hasarı %{3} ve Arcane Blast'ın mana maliyeti %{4} artar. Etki {5} kata kadar birikir ve {6} sn boyunca ya da Arcane Blast dışında herhangi bir Arcane hasar büyüsü yapılana kadar sürer.",
   ["Blasts the target with Holy energy, causing {1} to {2} Holy damage to an enemy, or {3} to {4} healing to an ally."] = "Hedefi Kutsal enerjiyle vurur; bir düşmana {1} ila {2} Kutsal hasar veya bir dosta {3} ila {4} iyileştirme uygular.",
   ["Blinds the target, causing it to wander disoriented for up to {1} sec. Any damage caused will remove the effect."] = "Hedefi kör eder; {1} sn'ye kadar şaşkın bir şekilde dolaşmasına neden olur. Verilen herhangi bir hasar etkiyi kaldırır.",
   ["Boils the blood of all enemies within {1} yards, dealing {2} to {3} Shadow damage. Deals additional damage to targets infected with Blood Plague or Frost Fever."] = "{1} yarda içindeki tüm düşmanların kanını kaynatır; {2} ila {3} Gölge hasarı verir. Blood Plague ya da Frost Fever ile enfekte olmuş hedeflere ek hasar verir.",
   ["Brings a dead player back to life with {1} health and {2} mana. Cannot be cast when in combat."] = "Ölü bir oyuncuyu {1} can ve {2} manayla yaşama döndürür. Savaştayken büyü yapılamaz.",
   ["Brings party members within {1} yards back to life with {2} health and {3} mana. Cannot be cast when in combat."] = "{1} yard içindeki grup üyelerini {2} can ve {3} manayla yaşama döndürür. Savaştayken büyü yapılamaz.",
   ["Burn the enemy's soul, causing {1} to {2} Fire damage."] = "Düşmanın ruhunu yakarak {1} ila {2} Ateş hasarı verir.",
   ["Burns the enemy for {1} Fire damage and then an additional {2} Fire damage over {3} sec."] = "Düşmanı {1} Ateş hasarıyla yakar ve ardından {3} sn boyunca ek {2} Ateş hasarı verir.",
   ["Burns the enemy for {1} to {2} Arcane damage and then an additional {3} Arcane damage over {4} sec."] = "Düşmanı {1} ila {2} Arcane hasarıyla yakar ve ardından {4} sn boyunca ek {3} Arcane hasarı verir.",
   ["Calls down a fiery rain to burn enemies in the area of effect for {1} Fire damage over {2} sec."] = "Etki alanındaki düşmanları {2} sn boyunca {1} Ateş hasarıyla yakmak için ateşli bir yağmur indirir.",
   ["Calls down a fiery rain to burn enemies in the area of effect for {1} Fire damage over {2}.{3} sec."] = "Etki alanındaki düşmanları {2}.{3} sn boyunca {1} Ateş hasarıyla yakmak için ateşli bir yağmur indirir.",
   ["Calls down a pillar of fire, burning all enemies within the area for {1} to {2} Fire damage and an additional {3} Fire damage over {4} sec."] = "Bir ateş sütunu indirir; alandaki tüm düşmanları {1} ila {2} Ateş hasarı ve {4} sn boyunca ek {3} Ateş hasarıyla yakar.",
   ["Casts a bolt of lightning at the target for {1} to {2} Nature damage."] = "Hedefe bir yıldırım oku fırlatarak {1} ila {2} Doğa hasarı verir.",
   ["Causes all enemies near the warrior to be dazed, reducing movement speed by {1}% for {2} sec."] = "Savaşçının yakınındaki tüm düşmanların sersemlemesine neden olur; {2} sn boyunca hareket hızını %{1} azaltır.",
   ["Causes an explosion of arcane magic around the caster, causing {1} to {2} Arcane damage to all targets within {3} yards."] = "Büyücünün etrafında bir Arcane büyü patlaması oluşturarak {3} yard içindeki tüm hedeflere {1} ila {2} Arcane hasarı verir.",
   ["Causes an explosion of holy light around the caster, causing {1} to {2} Holy damage to all enemy targets within {3} yards and healing all party members within {4} yards for {5} to {6}. These effects cause no threat."] = "Büyüyü yapanın etrafında bir kutsal ışık patlamasına neden olur; {3} metre içindeki tüm düşman hedeflere {1} ila {2} Kutsal hasar verir ve {4} metre içindeki tüm grup üyelerini {5} ila {6} iyileştirir. Bu etkiler tehdit oluşturmaz.",
   ["Causes an explosion of shadow magic around the enemy target, causing {1} to {2} Shadow damage every {3} sec for {4} sec to all enemies within {5} yards around the target."] = "Düşman hedefin etrafında bir Gölge büyü patlaması oluşturur; hedefin etrafındaki {5} yard içindeki tüm düşmanlara {4} sn boyunca her {3} sn'de {1} ila {2} Gölge hasarı verir.",
   ["Causes an explosion of shadow magic around the enemy target, causing {1} to {2} Shadow damage every {3}.{4} sec for {5}.{6} sec to all enemies within {7} yards around the target."] = "Düşman hedefin etrafında bir Gölge büyü patlaması oluşturur; hedefin etrafındaki {7} yard içindeki tüm düşmanlara {5}.{6} sn boyunca her {3}.{4} sn'de {1} ila {2} Gölge hasarı verir.",
   ["Causes Shadow damage to your target and causes all party members to gain mana equal to a percentage of any Shadow spell damage you deal."] = "Hedefinize Gölge hasarı verir ve tüm grup üyelerinin, verdiğiniz herhangi bir Gölge büyü hasarının bir yüzdesine eşit mana kazanmasını sağlar.",
   ["Causes the enemy target to run in horror for {1} sec and causes {2} Shadow damage. The caster gains {3}% of the damage caused in health."] = "Düşman hedefin {1} sn boyunca dehşet içinde kaçmasına neden olur ve {2} Gölge hasarı verir. Büyücü, verilen hasarın %{3} kadarını can olarak kazanır.",
   ["Causes the shaman's active Fire totem to emit a wave of flames, inflicting {1} to {2} Fire damage to enemies within {3} yards of the totem."] = "Shaman'ın aktif Ateş toteminin bir alev dalgası yaymasına neden olur; totemin {3} yard içindeki düşmanlara {1} ila {2} Ateş hasarı verir.",
   ["Causes the target to regenerate mana equal to {1}% of the casting Druid's base mana pool over {2} sec."] = "Hedefin, {2} sn boyunca büyüyü yapan Druid'in temel mana havuzunun %{1} kadarına eşit mana yenilemesine neden olur.",
   ["Causes you to charge an enemy, immobilizing and interrupting any spell being cast for {1} sec."] = "Bir düşmana hücum etmene neden olur; {1} sn boyunca onu hareketsiz bırakır ve yapılan herhangi bir büyüyü keser.",
   ["Causes your attacks to ignore {1} of your target's Armor and increases the damage dealt by your Rupture ability by {2}%. The amount of Armor reduced increases with your level."] = "Saldırılarının hedefinin Zırhının {1} kadarını yok saymasına neden olur ve Rupture yeteneğinin verdiği hasarı %{2} artırır. Azaltılan Zırh miktarı seviyenle birlikte artar.",
   ["Causes your Fire Ward to have a {1}% chance to reflect Fire spells while active."] = "Fire Ward'ının aktifken Ateş büyülerini yansıtma şansını %{1} verir.",
   ["Causes {1} damage, incapacitating the opponent for {2} sec, and turns off your attack. Target must be facing you. Any damage caused will revive the target. Awards {3} combo point."] = "{1} hasar verir, rakibi {2} sn boyunca etkisiz hale getirir ve saldırınızı kapatır. Hedef size dönük olmalıdır. Verilen herhangi bir hasar hedefi ayıltır. {3} combo point kazandırır.",
   ["Causes {1} Fire damage when hit, increases your chance to critically hit with spells by {2}% of your Spirit, and reduces the chance you are critically hit by {3}%. Only one type of Armor spell can be active on the Mage at any time. Lasts {4} min."] = "Vurulduğunda {1} Ateş hasarı verir, büyülerle kritik vurma şansınızı Spirit'inizin %{2} kadarı oranında artırır ve kritik vurulma şansınızı %{3} azaltır. Mage'in üzerinde aynı anda yalnızca bir tür Armor büyüsü aktif olabilir. {4} dk sürer.",
   ["Causes {1} Fire damage when hit, increases your chance to critically hit with spells by {2}%of your Spirit, and reduces the chance you are critically hit by {3}%. Only one type of Armor spell can be active on the Mage at any time. Lasts {4} min."] = "Vurulduğunda {1} Ateş hasarı verir, büyülerle kritik vurma şansınızı Spirit'inizin %{2} kadarı oranında artırır ve kritik vurulma şansınızı %{3} azaltır. Mage'in üzerinde aynı anda yalnızca bir tür Armor büyüsü aktif olabilir. {4} dk sürer.",
   ["Causes {1} Fire damage when hit, increases your critical strike rating by {2}% of your Spirit, and reduces the chance you are critically hit by {3}%. Only one type of Armor spell can be active on the Mage at any time. Lasts {4} min."] = "Vurulduğunda {1} Ateş hasarı verir, kritik vurma derecenizi Spirit'inizin %{2} kadarı oranında artırır ve kritik vurulma şansınızı %{3} azaltır. Mage'in üzerinde aynı anda yalnızca bir tür Armor büyüsü aktif olabilir. {4} dk sürer.",
   ["Causes {1} Holy damage to any enemy that strikes a party or raid member within {2} yards. Players may only have one Aura on them per Paladin at any one time."] = "{2} yard içindeki bir grup veya raid üyesine vuran herhangi bir düşmana {1} Kutsal hasar verir. Oyuncuların üzerinde Paladin başına aynı anda yalnızca bir Aura bulunabilir.",
   ["Causes {1} to {2} Arcane damage to the target."] = "Hedefe {1} ila {2} Arcane hasarı verir.",
   ["Causes {1} to {2} Holy damage to an enemy target. If the target is Undead or Demon, it will always critically hit."] = "Bir düşman hedefe {1} ila {2} Kutsal hasar verir. Hedef Undead veya Demon ise her zaman kritik vurur.",
   ["Causes {1} to {2} Nature damage to the target."] = "Hedefe {1} ila {2} Doğa hasarı verir.",
   ["Causes {1}% of the Mana drained by your Drain Mana spell to damage the opponent."] = "Drain Mana büyünün emdiği Mananın %{1} kadarının rakibe hasar vermesine neden olur.",
   ["Changes the caster's viewpoint to the targeted location. Lasts {1} min. Only useable outdoors."] = "Büyücünün bakış açısını hedeflenen konuma değiştirir. {1} dk sürer. Yalnızca açık alanda kullanılabilir.",
   ["Charge an enemy, causing {1} damage (based on attack power) and stunning it for {2} sec."] = "Bir düşmana atılır; {1} hasar verir (saldırı gücüne bağlı) ve onu {2} sn boyunca sersemletir.",
   ["Charge an enemy, generate {1} rage, and stun it for {2}.{3} sec. Cannot be used in combat."] = "Bir düşmana atılır, {1} öfke üretir ve onu {2}.{3} sn boyunca sersemletir. Savaşta kullanılamaz.",
   ["Chills the target for {1} to {2} Frost damage and infects them with Frost Fever, a disease that deals periodic damage and reduces melee and ranged attack speed by {3}% for {4} sec. Very high threat when in Frost Presence."] = "Hedefi {1} ila {2} Buz hasarıyla üşütür ve onlara Frost Fever bulaştırır; bu, periyodik hasar veren ve yakın dövüş ve menzilli saldırı hızını {4} sn boyunca %{3} azaltan bir hastalıktır. Frost Presence'teyken çok yüksek tehdit oluşturur.",
   ["Chills the target for {1}.{2} sec."] = "Hedefi {1}.{2} sn boyunca üşütür.",
   ["Choose one of your stabled pets to replace your current pet. The selected pet busts out of its stable to join you no matter where you are. Cannot be used in combat."] = "Mevcut pet'inizi değiştirmek için ahırdaki pet'lerinizden birini seçin. Seçilen pet, nerede olursanız olun size katılmak için ahırından fırlar. Savaşta kullanılamaz.",
   ["Claw the enemy, causing {1} additional damage. Awards {2} combo point."] = "Düşmanı pençeler; {1} ek hasar verir. {2} combo point kazandırır.",
   ["Cleanses a friendly target, removing {1} poison effect, {2} disease effect, and {3} magic effect."] = "Dost bir hedefi arındırır; {1} zehir etkisini, {2} hastalık etkisini ve {3} büyü etkisini kaldırır.",
   ["Come to the defense of a friendly target, commanding up to {1} enemies attacking the target to attack the Paladin instead."] = "Dost bir hedefin savunmasına gelir; hedefe saldıran en fazla {1} düşmanı, onun yerine Paladin'e saldırmaya zorlar.",
   ["Command your pet to intimidate the target on the next successful melee attack, causing a high amount of threat and stunning the target for {1} sec."] = "Evcil hayvanına, bir sonraki başarılı yakın dövüş saldırısında hedefi gözünü korkutmasını emreder; yüksek miktarda tehdit oluşturur ve hedefi {1} sn boyunca sersemletir.",
   ["Conjures a mana agate that can be used to instantly restore {1} to {2} mana."] = "Bir Mana Agate büyüyle yaratır; anında {1} ila {2} mana geri kazandırmak için kullanılabilir.",
   ["Conjures a mana citrine that can be used to instantly restore {1} to {2} mana."] = "Bir Mana Citrine büyüyle yaratır; anında {1} ila {2} mana geri kazandırmak için kullanılabilir.",
   ["Conjures a mana emerald that can be used to instantly restore {1} to {2} mana. {3} charges."] = "Bir Mana Emerald büyüyle yaratır; anında {1} ila {2} mana geri kazandırmak için kullanılabilir. {3} kullanım.",
