   ["Conjures {1} sweet rolls, providing the mage and her allies with something to eat. Conjured items disappear if logged out for more than {2} minutes."] = "Mage ve müttefiklerine yiyecek sağlayan {1} tatlı çörek büyüyle yaratır. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Conjures {1} sweet rolls, providing the mage and his allies with something to eat. Conjured items disappear if logged out for more than {2} minutes."] = "Mage ve müttefiklerine yiyecek sağlayan {1} tatlı çörek büyüyle yaratır. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Consecrates the land beneath Paladin, doing {1} Holy damage over {2} sec to enemies who enter the area."] = "Paladin'in altındaki toprağı kutsar; alana giren düşmanlara {2} sn boyunca {1} Kutsal hasar verir.",
   ["Consecrates the land beneath the Paladin, doing {1} Holy damage over {2} sec to enemies who enter the area."] = "Paladin'in altındaki toprağı kutsar; alana giren düşmanlara {2} sn boyunca {1} Kutsal hasar verir.",
   ["Consumes a Rejuvenation or Regrowth effect on a friendly target to instantly heal them an amount equal to {1} sec. of Rejuvenation or {2} sec. of Regrowth."] = "Bir dosttaki Rejuvenation veya Regrowth etkisini tüketerek onları anında {1} sn'lik Rejuvenation veya {2} sn'lik Regrowth kadar iyileştirir.",
   ["Consumes the enemy in Holy flames that cause {1} to {2} Holy damage and an additional {3} Holy damage over {4} sec."] = "Düşmanı, {1} ila {2} Kutsal hasar ve {4} sn boyunca ek {3} Kutsal hasar veren Kutsal alevler içinde kavurur.",
   ["Continuously fires a volley of ammo at the target area, causing {1} Arcane damage to enemy targets within {2} yards every {3}.{4} second for {5} sec."] = "Hedef alana sürekli mermi yağdırır; {5} sn boyunca, {2} yard içindeki düşman hedeflere her {3}.{4} saniyede bir {1} Arcane hasar verir.",
   ["Continuously fires a volley of ammo at the target area, causing {1} Arcane damage to enemy targets within {2} yards every {3}.{4} second for {5}.{6} sec."] = "Hedef alana sürekli mermi yağdırır; {5}.{6} sn boyunca, {2} yard içindeki düşman hedeflere her {3}.{4} saniyede bir {1} Arcane hasar verir.",
   ["Controls a humanoid mind up to level {1}, but increases the time between its attacks by {2}%. Lasts up to {3} min."] = "{1} seviyeye kadar bir humanoid'in zihnini kontrol eder, ancak saldırıları arasındaki süreyi %{2} artırır. En fazla {3} dk sürer.",
   ["Converts up to {1} rage per second into health for {2} sec. Each point of rage is converted into {3}.{4}% of max health."] = "{2} sn boyunca saniyede en fazla {1} öfkeyi cana dönüştürür. Her bir öfke puanı, azami canın %{3}.{4}'ü kadar cana dönüştürülür.",
   ["Converts {1} health into {2} mana. Spell power increases the amount of mana returned."] = "{1} canı {2} manaya dönüştürür. Büyü gücü, geri kazanılan mana miktarını artırır.",
   ["Corrupts the ground targeted by the Death Knight, causing {1} Shadow damage every sec that targets remain in the area for {2} sec. This ability produces a high amount of threat."] = "Death Knight'ın hedeflediği yeri bozar; hedefler alanda kaldıkça {2} sn boyunca saniyede {1} Gölge hasarı verir. Bu yetenek yüksek miktarda tehdit üretir.",
   ["Corrupts the target, causing {1} Shadow damage over {2} sec."] = "Hedefi yozlaştırarak {2} sn boyunca {1} Gölge hasar verir.",
   ["Counters the enemy's spellcast, preventing any spell from that school of magic from being cast for {1} sec. Generates a high amount of threat."] = "Düşmanın yaptığı büyüyü keser; {1} sn boyunca o büyü okulundan hiçbir büyünün yapılmasını engeller. Yüksek miktarda tehdit oluşturur.",
   ["Cower, causing no damage but lowering your threat a large amount, making the enemy less likely to attack you."] = "Sinerek hasar vermez ancak tehdidini büyük ölçüde azaltır; böylece düşmanın sana saldırma olasılığı düşer.",
   ["Cower, causing no damage but lowering your threat a medium amount, making the enemy less likely to attack you."] = "Sinerek hasar vermez ancak tehdidini orta ölçüde azaltır; böylece düşmanın sana saldırma olasılığı düşer.",
   ["Cower, causing no damage but lowering your threat a small amount, making the enemy less likely to attack you."] = "Sinerek hasar vermez ancak tehdidini az miktarda azaltır; böylece düşmanın sana saldırma olasılığı düşer.",
   ["Creates a Demonic Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Demonic Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Demonic Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Demonic Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Fel Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Fel Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Greater Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Greater Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Greater Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Greater Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a holy Lightwell near the priest. Members of your raid or party can click the Lightwell to restore {1} health over {2} sec. Being attacked cancels the effect. Lightwell lasts for {3} min or {4} charges."] = "Rahibin yakınında kutsal bir Lightwell oluşturur. Akın veya grup üyelerin Lightwell'e tıklayarak {2} sn boyunca {1} can yenileyebilir. Saldırıya uğramak etkiyi iptal eder. Lightwell {3} dk veya {4} şarj sürer.",
   ["Creates a Holy Lightwell. Friendly players can click the Lightwell to restore {1} health over {2} sec. Attacks done to you equal to {3}% of your total health will cancel the effect. Lightwell lasts for {4} min or {5} charges."] = "Bir Holy Lightwell yaratır. Dost oyuncular, {2} sn boyunca {1} can geri kazanmak için Lightwell'e tıklayabilir. Toplam canının %{3}'ü kadar sana yapılan saldırılar etkiyi iptal eder. Lightwell {4} dk veya {5} kullanım boyunca sürer.",
   ["Creates a Lesser Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Lesser Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Lesser Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Lesser Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Major Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Major Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Major Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Major Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Master Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Master Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Master Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Master Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Minor Healthstone that can be used to instantly restore {1} health. Conjured items disappear if logged out for more than {2} minutes."] = "Bir Minor Healthstone yaratır; anında {1} can geri kazandırmak için kullanılabilir. Yaratılan eşyalar, {2} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a Minor Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Minor Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a portal, teleporting group members that use it to Dalaran."] = "Bir portal yaratır; kullanan grup üyelerini Dalaran'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Darnassus."] = "Bir portal yaratır; kullanan grup üyelerini Darnassus'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Exodar."] = "Bir portal yaratır; kullanan grup üyelerini Exodar'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Ironforge."] = "Bir portal yaratır; kullanan grup üyelerini Ironforge'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Orgrimmar."] = "Bir portal yaratır; kullanan grup üyelerini Orgrimmar'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Shattrath."] = "Bir portal yaratır; kullanan grup üyelerini Shattrath'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Silvermoon."] = "Bir portal yaratır; kullanan grup üyelerini Silvermoon'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Stonard."] = "Bir portal yaratır; kullanan grup üyelerini Stonard'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Stormwind."] = "Bir portal yaratır; kullanan grup üyelerini Stormwind'e ışınlar.",
   ["Creates a portal, teleporting group members that use it to Theramore."] = "Bir portal yaratır; kullanan grup üyelerini Theramore'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Thunder Bluff."] = "Bir portal yaratır; kullanan grup üyelerini Thunder Bluff'a ışınlar.",
   ["Creates a portal, teleporting group members that use it to Undercity."] = "Bir portal yaratır; kullanan grup üyelerini Undercity'ye ışınlar.",
   ["Creates a shadowy fiend to attack the target. Caster receives {1}% mana when the Shadowfiend attacks. Damage taken by area of effect attacks is reduced. Lasts {2} sec."] = "Hedefe saldırması için gölgemsi bir yaratık oluşturur. Shadowfiend saldırdığında büyücü %{1} mana kazanır. Alan etkili saldırılardan alınan hasar azalır. {2} sn sürer.",
   ["Creates a Soulstone. The Soulstone can be used to store one target's soul. If the target dies while his soul is stored, he will be able to resurrect with {1} health and {2} mana. Conjured items disappear if logged out for more than {3} minutes."] = "Bir Soulstone yaratır. Soulstone, bir hedefin ruhunu saklamak için kullanılabilir. Hedef, ruhu saklıyken ölürse {1} can ve {2} mana ile dirilebilir. Yaratılan eşyalar, {3} dakikadan uzun süre oyundan çıkılırsa kaybolur.",
   ["Creates a violent storm in the target area causing {1} Nature damage to enemies every {2} sec, and increasing the time between attacks by {3}%. Lasts {4} sec. Druid must channel to maintain the spell."] = "Hedef alanda şiddetli bir fırtına oluşturur; düşmanlara her {2} sn'de bir {1} Doğa hasar verir ve saldırıları arasındaki süreyi %{3} artırır. {4} sn sürer. Büyüyü sürdürmek için Druid kanalize etmelidir.",
   ["Creates a violent storm in the target area causing {1} Nature damage to enemies every {2} sec, and increasing the time between attacks of enemies by {3}%. Lasts {4} sec. Druid must channel to maintain the spell."] = "Hedef alanda şiddetli bir fırtına oluşturur; düşmanlara her {2} sn'de bir {1} Doğa hasar verir ve düşmanların saldırıları arasındaki süreyi %{3} artırır. {4} sn sürer. Büyüyü sürdürmek için Druid kanalize etmelidir.",
   ["Creates a violent storm in the target area causing {1} Nature damage to enemies every {2}.{3} sec, and increasing the time between attacks by {4}%. Lasts {5}.{6} sec. Druid must channel to maintain the spell."] = "Hedef alanda şiddetli bir fırtına oluşturur; düşmanlara her {2}.{3} sn'de bir {1} Doğa hasar verir ve saldırıları arasındaki süreyi %{4} artırır. {5}.{6} sn sürer. Büyüyü sürdürmek için Druid kanalize etmelidir.",
   ["Creates a violent storm in the target area causing {1} Nature damage to enemies every {2}.{3} sec, and increasing the time between attacks of enemies by {4}%. Lasts {5}.{6} sec. Druid must channel to maintain the spell."] = "Hedef alanda şiddetli bir fırtına oluşturur; düşmanlara her {2}.{3} sn'de bir {1} Doğa hasar verir ve düşmanların saldırıları arasındaki süreyi %{4} artırır. {5}.{6} sn sürer. Büyüyü sürdürmek için Druid kanalize etmelidir.",
   ["Creates {1} copies of the caster nearby, which cast spells and attack the mage's enemies. Lasts {2} sec."] = "Yakında büyücünün {1} kopyasını oluşturur; bunlar büyü yapar ve Mage'in düşmanlarına saldırır. {2} sn sürer.",
   ["Creates {1} Vials of Anti-Venom."] = "{1} şişe Anti-Venom yaratır.",
   ["Critical hits made against you have a chance to prevent you from being critically hit again for {1} sec."] = "Sana yapılan kritik vuruşların, {1} sn boyunca tekrar kritik vurulmanı engelleme şansı vardır.",
   ["Cures {1} poison effect on the target."] = "Hedef üzerindeki {1} zehir etkisini giderir.",
   ["Curse the target with idiocy, reducing Intellect and Spirit by {1} every {2} seconds until each is reduced by a total of {3}. Only one Curse per Warlock can be active on any one target."] = "Hedefi aptallıkla lanetler; her {2} saniyede bir Intellect ve Spirit'i {1} azaltır, ta ki her biri toplam {3} azalana kadar. Bir hedef üzerinde her Warlock için yalnızca bir Curse aktif olabilir.",
   ["Curses the target for {1} min, reducing Arcane, Fire, Frost, Nature and Shadow resistances by {2} and increasing magic damage taken by {3}%. Only one Curse per Warlock can be active on any one target."] = "Hedefi {1} dk boyunca lanetler; Arcane, Ateş, Buz, Doğa ve Gölge dirençlerini {2} azaltır ve alınan büyü hasarını %{3} artırır. Bir hedef üzerinde her Warlock için yalnızca bir Curse aktif olabilir.",
   ["Curses the target for {1} min, reducing Arcane, Fire, Frost, Nature, and Shadow resistances by {2} and increasing magic damage taken by {3}%. Only one Curse per Warlock can be active on any one target."] = "Hedefi {1} dk boyunca lanetler; Arcane, Ateş, Buz, Doğa ve Gölge dirençlerini {2} azaltır ve alınan büyü hasarını %{3} artırır. Bir hedef üzerinde her Warlock için yalnızca bir Curse aktif olabilir.",
   ["Curses the target with agony, causing {1} Shadow damage over {2} sec. This damage is dealt slowly at first, and builds up as the Curse reaches its full duration. Only one Curse per Warlock can be active on any one target."] = "Hedefi ıstırapla lanetler; {2} sn boyunca {1} Gölge hasar verir. Bu hasar başlangıçta yavaş verilir ve Curse tam süresine ulaştıkça giderek artar. Bir hedef üzerinde her Warlock için yalnızca bir Curse aktif olabilir.",
   ["Curses the target with impending doom, causing {1} Shadow damage after {2} min. If the target yields experience or honor when it dies from this damage, a Doomguard will be summoned. Cannot be cast on players."] = "Hedefi yaklaşan kıyametle lanetler; {2} dk sonra {1} Gölge hasar verir. Hedef bu hasardan öldüğünde deneyim veya onur veriyorsa, bir Doomguard çağrılır. Oyunculara büyü yapılamaz.",
   ["Damage dealt by Death Knight, Hunter and Warlock pets increased by {1}%."] = "Death Knight, Hunter ve Warlock petlerinin verdiği hasar %{1} artırılır.",
   ["Damage dealt by pets increased by {1}%."] = "Petlerin verdiği hasar %{1} artar.",
   ["Dampens magic used against the targeted party member, decreasing damage taken from spells by up to {1} and healing spells by up to {2}. Lasts {3} min."] = "Hedeflenen grup üyesine karşı kullanılan büyüyü zayıflatır; büyülerden alınan hasarı en fazla {1}, iyileştirme büyülerinin iyileştirmesini en fazla {2} azaltır. {3} dk sürer.",
   ["Dazes the target, slowing movement speed by {1}% for {2} sec."] = "Hedefi sersemleterek hareket hızını {2} sn boyunca %{1} yavaşlatır.",
   ["Deals {1} Holy damage to an enemy, increased by {2}% for each application of Blood Corruption on the target."] = "Bir düşmana {1} Kutsal hasar verir; hedefteki her Blood Corruption uygulaması için bu hasar %{2} artar.",
   ["Deals {1} to {2} Fire damage to your target and an additional {3} to {4} Fire damage if the target is affected by an Immolate spell."] = "Hedefine {1} ila {2} Ateş hasar verir; hedef Immolate büyüsünün etkisindeyse ek olarak {3} ila {4} Ateş hasar verir.",
   ["Deals {1} to {2} Frost damage to an enemy target. Causes triple damage against Frozen targets."] = "Bir düşman hedefe {1} ila {2} Buz hasar verir. Donmuş hedeflere üç kat hasar verir.",
   ["Decrease the armor of the target by {1} for {2} sec. While affected, the target cannot stealth or turn invisible."] = "Hedefin zırhını {2} sn boyunca {1} azaltır. Etki altındayken hedef gizlenemez veya görünmez olamaz.",
   ["Decrease the armor of the target by {1}% for {2} min. While affected, the target cannot stealth or turn invisible."] = "Hedefin zırhını {2} dk boyunca %{1} azaltır. Etki altındayken hedef gizlenemez veya görünmez olamaz.",
   ["Decrease the armor of the target by {1}% for {2} min. While affected, the target cannot stealth or turn invisible. Deals {3} damage and additional threat when used in Bear Form or Dire Bear Form."] = "Hedefin zırhını {2} dk boyunca %{1} azaltır. Etki altındayken hedef gizlenemez veya görünmez olamaz. Bear Form veya Dire Bear Form'dayken kullanıldığında {3} hasar ve ek tehdit verir.",
   ["Decreases damage taken from all sources by {1}%. Decreases damage caused by {2}%. Increases threat generated by {3}%."] = "Tüm kaynaklardan alınan hasarı %{1} azaltır. Verilen hasarı %{2} azaltır. Oluşturulan tehdidi %{3} artırır.",
   ["Decreases the casting time of your Slam ability by {1}.{2} sec."] = "Slam yeteneğinin okuma süresini {1}.{2} sn azaltır.",
   ["Decreases the chance enemies will resist trap effects by {1}%."] = "Düşmanların tuzak etkilerine direnme şansını %{1} azaltır.",
   ["Decreases the cooldown of your Fade ability by {1} sec."] = "Fade yeteneğinin bekleme süresini {1} sn azaltır.",
   ["Decreases the cooldown of your Hammer of Justice spell by {1} sec."] = "Hammer of Justice büyünün bekleme süresini {1} sn azaltır.",
   ["Decreases the cooldown of your Judgement spell by {1} sec."] = "Judgement büyünün bekleme süresini {1} sn azaltır.",
   ["Decreases the mana lost per point of damage taken when Mana Shield is active by {1}%."] = "Mana Shield aktifken alınan her hasar puanı başına kaybedilen manayı %{1} azaltır.",
   ["Decreases threat generated by {1}%."] = "Oluşturulan tehdidi %{1} azaltır.",
   ["Destroy {1}% of the target's mana (up to a maximum of {2}% of your own maximum mana). For each mana destroyed in this way, the target takes {3}.{4} Shadow damage."] = "Hedefin manasının %{1}'ini yok eder (kendi azami mananın en fazla %{2}'si kadar). Bu şekilde yok edilen her mana için hedef {3}.{4} Gölge hasar alır.",
   ["Disarm the enemy's main hand and ranged weapons for {1} sec."] = "Düşmanın ana el ve menzilli silahlarını {1} sn boyunca devre dışı bırakır.",
   ["Disarm the enemy, removing all weapons, shield or other equipment carried for {1} sec."] = "Düşmanı silahsızlandırır; taşıdığı tüm silahları, kalkanı veya diğer ekipmanı {1} sn boyunca elinden alır.",
   ["Dismiss your pet. Dismissing your pet will reduce its happiness by {1}."] = "Petini geri gönderir. Peti geri göndermek mutluluğunu {1} azaltır.",
   ["Dispels magic in a {1} yard radius, removing {2} harmful spell from each friendly target and {3} beneficial spell from each enemy target. Affects a maximum of {4} friendly targets and {5} enemy targets. This dispel is potent enough to remove Magic effects that are normally undispellable."] = "{1} yard yarıçapındaki büyüyü temizler; her dost hedeften {2} zararlı büyü, her düşman hedeften {3} faydalı büyü kaldırır. En fazla {4} dost ve {5} düşman hedefi etkiler. Bu temizleme, normalde temizlenemeyen büyü etkilerini bile kaldıracak kadar güçlüdür.",
   ["Dispels magic on the target, removing {1} harmful spell from a friend or {2} beneficial spell from an enemy."] = "Hedefteki büyüyü temizler; bir dosttan {1} zararlı büyü veya bir düşmandan {2} faydalı büyü kaldırır.",
   ["Dispels {1} Curse from a friendly target."] = "Dost bir hedeften {1} lanet temizler.",
   ["Distracts the target to attack you, but has no effect if the target is already attacking you. Lasts {1} sec."] = "Hedefin dikkatini çekerek seni hedef almasını sağlar, ancak hedef zaten sana saldırıyorsa etkisi olmaz. {1} sn sürer.",
   ["Drains the soul of the target, causing {1} Shadow damage over {2} sec. If the target is at or below {3}% health, Drain Soul causes four times the normal damage. If the target dies while being drained, and yields experience or honor, the caster gains a Soul Shard. Each time the Drain Soul damages the target, it also has a chance to generate a Soul Shard. Soul Shards are required for other spells."] = "Hedefin ruhunu emer; {2} sn boyunca {1} Gölge hasar verir. Hedefin canı %{3} veya altındaysa Drain Soul normalin dört katı hasar verir. Hedef emilirken ölür ve deneyim ya da onur verirse büyücü bir Soul Shard kazanır. Drain Soul hedefe her hasar verdiğinde ayrıca bir Soul Shard üretme şansı vardır. Soul Shard'lar diğer büyüler için gereklidir.",
   ["Drains the soul of the target, causing {1} Shadow damage over {2}.{3} sec. If the target is at or below {4}% health, Drain Soul causes four times the normal damage. If the target dies while being drained, and yields experience or honor, the caster gains a Soul Shard. Each time the Drain Soul damages the target, it also has a chance to generate a Soul Shard. Soul Shards are required for other spells."] = "Hedefin ruhunu emer; {2}.{3} sn boyunca {1} Gölge hasar verir. Hedefin canı %{4} veya altındaysa Drain Soul normalin dört katı hasar verir. Hedef emilirken ölür ve deneyim ya da onur verirse büyücü bir Soul Shard kazanır. Drain Soul hedefe her hasar verdiğinde ayrıca bir Soul Shard üretme şansı vardır. Soul Shard'lar diğer büyüler için gereklidir.",
   ["Drains {1} of your pet's Mana, returning {2}% to you."] = "Evcil hayvanının Manasının {1} kadarını emer ve %{2} kadarını sana geri verir.",
   ["Draws on the soul of the friendly target to shield them, absorbing {1} damage. Lasts {2} sec. While the shield holds, spellcasting will not be interrupted by damage. Once shielded, the target cannot be shielded again for {3} sec."] = "Dost hedefin ruhundan güç çekerek onu korur ve {1} hasarı emer. {2} sn sürer. Kalkan dayandığı sürece büyü yapma hasarla kesilmez. Bir kez kalkanlandıktan sonra hedef {3} sn boyunca tekrar kalkanlanamaz.",
   ["Draws your target before you with a beam of unholy power. This will also taunt the target, forcing enemies to attack you for {1} sec."] = "Hedefini kutsal olmayan bir güç ışınıyla önüne çeker. Bu ayrıca hedefi kışkırtarak onu {1} sn boyunca sana saldırmaya zorlar.",
   ["Duration of Stun effects reduced by an additional {1}%."] = "Stun etkilerinin süresi ek olarak %{1} azaltılır.",
   ["Each time the target takes damage they gain a Sacred Shield, absorbing {1} damage and increasing the paladin's chance to critically hit with Flash of Light by {2}% for up to {3} sec. They cannot gain this effect more than once every {4} sec. Lasts {5} min. This spell cannot be on more than one target at any one time."] = "Hedef her hasar aldığında bir Sacred Shield kazanır; bu {1} hasarı emer ve paladinin Flash of Light ile kritik vurma şansını {3} sn'ye kadar %{2} artırır. Bu etki {4} sn'de birden fazla kazanılamaz. {5} dk sürer. Bu büyü aynı anda birden fazla hedefte bulunamaz.",
   ["Each time the target takes damage they gain a Sacred Shield, absorbing {1} damage and increasing the paladin's chance to critically hit with Flash of Light by {2}% for up to {3} sec. They cannot gain this effect more than once every {4} sec. Lasts {5} sec. This spell cannot be on more than one target at any one time."] = "Hedef her hasar aldığında bir Sacred Shield kazanır; bu {1} hasarı emer ve paladinin Flash of Light ile kritik vurma şansını {3} sn'ye kadar %{2} artırır. Bu etki {4} sn'de birden fazla kazanılamaz. {5} sn sürer. Bu büyü aynı anda birden fazla hedefte bulunamaz.",
   ["Each time you deal a critical strike while in Bear Form or Dire Bear Form, you gain Savage Defense, reducing the damage taken from the next physical attack that strikes you by {1}% of your attack power."] = "Bear Form veya Dire Bear Form'dayken her kritik vuruş yaptığında Savage Defense kazanırsın; bu, sana isabet eden bir sonraki fiziksel saldırıdan alınan hasarı saldırı gücünün %{1}'i kadar azaltır.",
   ["Empower your rune weapon, immediately activating all your runes and generating {1} runic power."] = "Rün silahını güçlendirir, tüm rünlerini anında etkinleştirir ve {1} runic power üretir.",
   ["Enslaves the target demon, up to level {1}, forcing it to do your bidding. While enslaved, the time between the demon's attacks is increased by {2}% and its casting speed is slowed by {3}%. Lasts up to {4} min."] = "{1} seviyeye kadar olan hedef iblisi köleleştirir ve onu emrine uymaya zorlar. Köleyken iblisin saldırıları arasındaki süre %{2} artar ve büyü yapma hızı %{3} yavaşlar. {4} dk'ya kadar sürer.",
   ["Expertise with Fist Weapons, Axes and Two-Handed Axes increased by {1}."] = "Yumruk Silahları, Baltalar ve İki Elli Baltalar ile uzmanlık {1} artırılır.",
   ["Expertise with Maces and Two-Handed Maces increased by {1}."] = "Maces ve Two-Handed Maces ile expertise {1} artar.",
   ["Expertise with Swords and Two-Handed Swords increased by {1}."] = "Swords ve Two-Handed Swords ile expertise {1} artar.",
   ["Exposes all hidden and invisible enemies within {1} yards of the targeted area for {2} sec."] = "Hedeflenen alanın {1} yard içindeki tüm gizli ve görünmez düşmanları {2} sn boyunca açığa çıkarır.",
   ["Fade out, temporarily reducing all your threat for {1} sec."] = "Soluklaşır, tüm tehdidini {1} sn boyunca geçici olarak azaltır.",
   ["Feed your pet the selected item. Feeding your pet increases happiness. Using food close to the pet's level will have a better result."] = "Seçili eşyayı evcil hayvanına yedirir. Evcil hayvanını beslemek mutluluğunu artırır. Evcil hayvanın seviyesine yakın yiyecek kullanmak daha iyi sonuç verir.",
   ["Feign death which may trick enemies into ignoring you. Lasts up to {1} min."] = "Ölü taklidi yaparak düşmanları seni görmezden gelmeye kandırabilir. {1} dk'ya kadar sürer.",
   ["Fills the Paladin with divine light for {1} min, giving each melee attack a chance to heal the Paladin for {2} to {3}. Only one Seal can be active on the Paladin at any one time. Unleashing this Seal's energy will judge an enemy for {4} sec, granting attacks made against the judged enemy a chance of healing the attacker for {5}% of their maximum health. Only one Judgement per Paladin can be active at any one time."] = "Paladini {1} dk boyunca kutsal ışıkla doldurur, her yakın dövüş saldırısına Paladini {2} ila {3} iyileştirme şansı verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. Bu Seal'in enerjisini boşaltmak bir düşmanı {4} sn boyunca yargılar ve yargılanan düşmana yapılan saldırılara, saldırganı azami canının %{5}'i kadar iyileştirme şansı verir. Her Paladinde aynı anda yalnızca bir Judgement etkin olabilir.",
   ["Fills the Paladin with divine light for {1} min, giving each melee attack a chance to heal the Paladin for {2}. Only one Seal can be active on the Paladin at any one time. Unleashing this Seal's energy will deal {3} Holy damage to an enemy."] = "Paladini {1} dk boyunca kutsal ışıkla doldurur, her yakın dövüş saldırısına Paladini {2} iyileştirme şansı verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. Bu Seal'in enerjisini boşaltmak bir düşmana {3} Kutsal hasar verir.",
   ["Fills the Paladin with divine wisdom for {1} min, giving each melee attack a chance to restore {2}% of the paladin's maximum mana. Only one Seal can be active on the Paladin at any one time. Unleashing this Seal's energy will deal {3} Holy damage to an enemy."] = "Paladini {1} dk boyunca kutsal bilgelikle doldurur, her yakın dövüş saldırısına paladinin azami manasının %{2}'sini geri kazandırma şansı verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. Bu Seal'in enerjisini boşaltmak bir düşmana {3} Kutsal hasar verir.",
   ["Fills the Paladin with holy power, causing attacks to apply Blood Corruption, which deals {1} additional Holy damage over {2} sec. Once stacked to {3} times, each of the Paladins attacks also deals {4} to {5}% weapon damage as additional Holy damage. Blood Corruption can stack up to {6} times. Only one Seal can be active on the Paladin at any one time. Lasts {7} min. Unleashing this Seal's energy will deal {8} Holy damage to an enemy, increased by {9}% for each application of Blood Corruption on the target."] = "Paladini kutsal güçle doldurur, saldırıların Blood Corruption uygulamasına neden olur; bu {2} sn boyunca {1} ek Kutsal hasar verir. {3} kez üst üste bindiğinde, Paladinin her saldırısı ayrıca %{4} ila %{5} silah hasarı kadar ek Kutsal hasar verir. Blood Corruption en fazla {6} kez üst üste binebilir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. {7} dk sürer. Bu Seal'in enerjisini boşaltmak bir düşmana {8} Kutsal hasar verir; bu, hedefteki her Blood Corruption uygulaması için %{9} artar.",
   ["Fills the Paladin with holy power, causing attacks to apply Blood Corruption, which deals {1} additional Holy damage over {2} sec. Once stacked to {3} times, each of the Paladins attacks also deals {4}% weapon damage as additional Holy damage. Blood Corruption can stack up to {5} times. Only one Seal can be active on the Paladin at any one time. Lasts {6} min. Unleashing this Seal's energy will deal {7} Holy damage to an enemy, increased by {8}% for each application of Blood Corruption on the target."] = "Paladini kutsal güçle doldurur, saldırıların Blood Corruption uygulamasına neden olur; bu {2} sn boyunca {1} ek Kutsal hasar verir. {3} kez üst üste bindiğinde, Paladinin her saldırısı ayrıca %{4} silah hasarı kadar ek Kutsal hasar verir. Blood Corruption en fazla {5} kez üst üste binebilir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. {6} dk sürer. Bu Seal'in enerjisini boşaltmak bir düşmana {7} Kutsal hasar verir; bu, hedefteki her Blood Corruption uygulaması için %{8} artar.",
   ["Fills the Paladin with holy power, causing attacks to apply Holy Vengeance, which deals {1} additional Holy damage over {2} sec. Holy Vengeance can stack up to {3} times. Once stacked to {4} times, each of the Paladin's attacks also deals {5} to {6}% weapon damage as additional Holy damage. Only one Seal can be active on the Paladin at any one time. Lasts {7} min. Unleashing this Seal's energy will deal {8} Holy damage to an enemy, increased by {9}% for each application of Holy Vengeance on the target."] = "Paladini kutsal güçle doldurur, saldırıların Holy Vengeance uygulamasına neden olur; bu {2} sn boyunca {1} ek Kutsal hasar verir. Holy Vengeance en fazla {3} kez üst üste binebilir. {4} kez üst üste bindiğinde, Paladinin her saldırısı ayrıca %{5} ila %{6} silah hasarı kadar ek Kutsal hasar verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. {7} dk sürer. Bu Seal'in enerjisini boşaltmak bir düşmana {8} Kutsal hasar verir; bu, hedefteki her Holy Vengeance uygulaması için %{9} artar.",
   ["Fills the Paladin with holy power, causing attacks to apply Holy Vengeance, which deals {1} additional Holy damage over {2} sec. Holy Vengeance can stack up to {3} times. Once stacked to {4} times, each of the Paladin's attacks also deals {5}% weapon damage as additional Holy damage. Only one Seal can be active on the Paladin at any one time. Lasts {6} min. Unleashing this Seal's energy will deal {7} Holy damage to an enemy, increased by {8}% for each application of Holy Vengeance on the target."] = "Paladini kutsal güçle doldurur, saldırıların Holy Vengeance uygulamasına neden olur; bu {2} sn boyunca {1} ek Kutsal hasar verir. Holy Vengeance en fazla {3} kez üst üste binebilir. {4} kez üst üste bindiğinde, Paladinin her saldırısı ayrıca %{5} silah hasarı kadar ek Kutsal hasar verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. {6} dk sürer. Bu Seal'in enerjisini boşaltmak bir düşmana {7} Kutsal hasar verir; bu, hedefteki her Holy Vengeance uygulaması için %{8} artar.",
   ["Fills the Paladin with holy spirit for {1} min, granting each melee attack an additional {2} Holy damage. Only one Seal can be active on the Paladin at any one time. Unleashing this Seal's energy will cause {3} Holy damage to an enemy."] = "Paladini {1} dk boyunca kutsal ruhla doldurur, her yakın dövüş saldırısına {2} ek Kutsal hasar verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. Bu Seal'in enerjisini boşaltmak bir düşmana {3} Kutsal hasar verir.",
   ["Fills the Paladin with holy spirit for {1} min, granting each melee attack {2} additional Holy damage. Only one Seal can be active on the Paladin at any one time."] = "Paladini {1} dk boyunca kutsal ruhla doldurur, her yakın dövüş saldırısına {2} ek Kutsal hasar verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir.",
   ["Fills the Paladin with holy spirit for {1} min, granting each melee attack {2} additional Holy damage. Only one Seal can be active on the Paladin at any one time. Unleashing this Seal's energy will cause {3} Holy damage to an enemy."] = "Paladini {1} dk boyunca kutsal ruhla doldurur, her yakın dövüş saldırısına {2} ek Kutsal hasar verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. Bu Seal'in enerjisini boşaltmak bir düşmana {3} Kutsal hasar verir.",
   ["Fills the Paladin with the spirit of justice for {1} min, giving each melee attack a chance to stun for {2} sec. Only one Seal can be active on the Paladin at any one time. Unleashing this Seal's energy will deal {3} Holy damage to an enemy."] = "Paladini {1} dk boyunca adalet ruhuyla doldurur, her yakın dövüş saldırısına {2} sn sersemletme şansı verir. Paladinde aynı anda yalnızca bir Seal etkin olabilir. Bu Seal'in enerjisini boşaltmak bir düşmana {3} Kutsal hasar verir.",
   ["Finishing move that causes damage and stuns the target. Non-player victim spellcasting is also interrupted for {1} sec. Causes more damage and lasts longer per combo point: {2} point : {3}-{4} damage, {5} sec {6} points: {7}-{8} damage, {9} sec {10} points: {11}-{12} damage, {13} sec {14} points: {15}-{16} damage, {17} sec {18} points: {19}-{20} damage, {21} sec"] = "Hasar veren ve hedefi sersemleten bitirici hamle. Oyuncu olmayan kurbanın büyü yapması da {1} sn boyunca kesilir. Her combo puanı ile daha fazla hasar verir ve daha uzun sürer: {2} puan: {3}-{4} hasar, {5} sn {6} puan: {7}-{8} hasar, {9} sn {10} puan: {11}-{12} hasar, {13} sn {14} puan: {15}-{16} hasar, {17} sn {18} puan: {19}-{20} hasar, {21} sn",
   ["Finishing move that causes damage over time, increased by your attack power. Lasts longer per combo point: {1} point : {2} damage over {3} secs {4} points: {5} damage over {6} secs {7} points: {8} damage over {9} secs {10} points: {11} damage over {12} secs {13} points: {14} damage over {15} secs"] = "Zamana yayılı hasar veren bitirici hamle; saldırı gücünle artar. Her combo puanı ile daha uzun sürer: {1} puan: {3} sn boyunca {2} hasar {4} puan: {6} sn boyunca {5} hasar {7} puan: {9} sn boyunca {8} hasar {10} puan: {12} sn boyunca {11} hasar {13} puan: {15} sn boyunca {14} hasar",
   ["Finishing move that causes damage over time. Damage increases per combo point and by your attack power: {1} point: {2} damage over {3} sec. {4} points: {5} damage over {6} sec. {7} points: {8} damage over {9} sec. {10} points: {11} damage over {12} sec. {13} points: {14} damage over {15} sec."] = "Zamana yayılı hasar veren bitirici hamle. Hasar her combo puanı ile ve saldırı gücünle artar: {1} puan: {3} sn boyunca {2} hasar. {4} puan: {6} sn boyunca {5} hasar. {7} puan: {9} sn boyunca {8} hasar. {10} puan: {12} sn boyunca {11} hasar. {13} puan: {15} sn boyunca {14} hasar.",
   ["Finishing move that causes damage per combo point and converts each extra point of energy (up to a maximum of {1} extra energy) into {2}.{3} additional damage. Damage is increased by your attack power. {4} point : {5}-{6} damage {7} points: {8}-{9} damage {10} points: {11}-{12} damage {13} points: {14}-{15} damage {16} points: {17}-{18} damage"] = "Her combo puanı başına hasar veren ve her fazladan enerji puanını (en fazla {1} fazla enerji) {2}.{3} ek hasara dönüştüren bitirici hamle. Hasar saldırı gücünle artar. {4} puan: {5}-{6} hasar {7} puan: {8}-{9} hasar {10} puan: {11}-{12} hasar {13} puan: {14}-{15} hasar {16} puan: {17}-{18} hasar",
   ["Finishing move that causes damage per combo point: {1} point : {2}-{3} damage {4} points: {5}-{6} damage {7} points: {8}-{9} damage {10} points: {11}-{12} damage {13} points: {14}-{15} damage"] = "Her combo puanı başına hasar veren bitirici hamle: {1} puan: {2}-{3} hasar {4} puan: {5}-{6} hasar {7} puan: {8}-{9} hasar {10} puan: {11}-{12} hasar {13} puan: {14}-{15} hasar",
   ["Finishing move that consumes your Deadly Poison doses on the target and deals instant poison damage. Following the Envenom attack you have an additional {1}% chance to apply Deadly Poison and a {2}% increased frequency of applying Instant Poison for {3} sec plus an additional {4} sec per combo point. One dose is consumed for each combo point: {5} dose: {6} damage {7} doses: {8} damage {9} doses: {10} damage {11} doses: {12} damage {13} doses: {14} damage"] = "Hedefteki Deadly Poison dozlarını tüketen ve anında zehir hasarı veren bitirici hamle. Envenom saldırısının ardından {3} sn artı her combo puanı için {4} sn boyunca Deadly Poison uygulama şansın %{1} ve Instant Poison uygulama sıklığın %{2} artar. Her combo puanı için bir doz tüketilir: {5} doz: {6} hasar {7} doz: {8} hasar {9} doz: {10} hasar {11} doz: {12} hasar {13} doz: {14} hasar",
   ["Finishing move that exposes the target, reducing armor by {1}% and lasting longer per combo point: {2} point : {3} sec. {4} points: {5} sec. {6} points: {7} sec. {8} points: {9} sec. {10} points: {11} sec."] = "Hedefi açığa çıkaran, zırhı %{1} azaltan ve her combo puanı ile daha uzun süren bitirici hamle: {2} puan: {3} sn. {4} puan: {5} sn. {6} puan: {7} sn. {8} puan: {9} sn. {10} puan: {11} sn.",
   ["Finishing move that increases melee attack speed by {1}%. Lasts longer per combo point: {2} point : {3} seconds {4} points: {5} seconds {6} points: {7} seconds {8} points: {9} seconds {10} points: {11} seconds"] = "Yakın dövüş saldırı hızını %{1} artıran bitirici hamle. Her combo puanı ile daha uzun sürer: {2} puan: {3} sn {4} puan: {5} sn {6} puan: {7} sn {8} puan: {9} sn {10} puan: {11} sn",
   ["Finishing move that increases physical damage done by {1}%. Only useable while in Cat Form. Lasts longer per combo point: {2} point : {3} seconds {4} points: {5} seconds {6} points: {7} seconds {8} points: {9} seconds {10} points: {11} seconds"] = "Verilen fiziksel hasarı %{1} artıran bitirici hamle. Yalnızca Cat Form'dayken kullanılabilir. Her combo puanı ile daha uzun sürer: {2} puan: {3} sn {4} puan: {5} sn {6} puan: {7} sn {8} puan: {9} sn {10} puan: {11} sn",
   ["Finishing move that reduces the movement of the target by {1}% for {2} sec and causes increased thrown weapon damage: {3} point : {4} - {5} damage {6} points: {7} - {8} damage {9} points: {10} - {11} damage {12} points: {13} - {14} damage {15} points: {16} - {17} damage"] = "Hedefin hareketini {2} sn boyunca %{1} azaltan ve fırlatma silahı hasarını artıran bitirici hamle: {3} puan: {4}-{5} hasar {6} puan: {7}-{8} hasar {9} puan: {10}-{11} hasar {12} puan: {13}-{14} hasar {15} puan: {16}-{17} hasar",
   ["Finishing move that stuns the target. Lasts longer per combo point: {1} point : {2} second {3} points: {4} seconds {5} points: {6} seconds {7} points: {8} seconds {9} points: {10} seconds"] = "Hedefi sersemleten bitirici hamle. Her combo puanı ile daha uzun sürer: {1} puan: {2} sn {3} puan: {4} sn {5} puan: {6} sn {7} puan: {8} sn {9} puan: {10} sn",
   ["Finishing move that stuns the target. Lasts longer per combo point: {1} point : {2} seconds {3} points: {4} seconds {5} points: {6} seconds {7} points: {8} seconds {9} points: {10} seconds"] = "Hedefi sersemleten bitirici hamle. Her combo puanı ile daha uzun sürer: {1} puan: {2} sn {3} puan: {4} sn {5} puan: {6} sn {7} puan: {8} sn {9} puan: {10} sn",
   ["Fire a blast of unholy energy, causing Shadow damage to an enemy target or healing damage from a friendly Undead target."] = "Kutsal olmayan bir enerji patlaması fırlatır; düşman bir hedefe Gölge hasarı verir veya dost bir Undead hedefi iyileştirir.",
   ["Fire a blast of unholy energy, causing {1} Shadow damage to an enemy target or healing {2} damage from a friendly Undead target."] = "Kutsal olmayan bir enerji patlaması fırlatır; düşman bir hedefe {1} Gölge hasarı verir ya da dost bir Undead hedefi {2} iyileştirir.",
   ["Fire a freezing arrow that places a Freezing Trap at the target location, freezing the first enemy that approaches, preventing all action for up to {1} sec. Any damage caused will break the ice. Trap will exist for {2} sec. Only one trap can be active at a time."] = "Hedef konuma bir Freezing Trap yerleştiren donduran bir ok atar; yaklaşan ilk düşmanı dondurarak {1} sn'ye kadar tüm eylemlerini engeller. Verilen herhangi bir hasar buzu kırar. Tuzak {2} sn boyunca var olur. Aynı anda yalnızca bir tuzak etkin olabilir.",
   ["Fires a Black Arrow at the target, increasing all damage done by you to the target by {1}% and dealing {2} Shadow damage over {3} sec. Black Arrow shares a cooldown with Trap spells."] = "Hedefe bir Black Arrow atar; senin hedefe verdiğin tüm hasarı %{1} artırır ve {3} sn boyunca {2} Gölge hasarı verir. Black Arrow, tuzak büyüleriyle bekleme süresi paylaşır.",
   ["Fires several missiles, hitting {1} targets for an additional {2} damage."] = "Birkaç füze fırlatır; {1} hedefe {2} ek hasar verir.",
   ["Fires several missiles, hitting {1} targets."] = "Birkaç füze fırlatır; {1} hedefe isabet eder.",
   ["Focus your protective gaze on a group or raid target, reducing their damage taken by {1}% and transfers -{2}% of the threat they cause to you. In addition, each time they are hit by an attack your Taunt cooldown is refreshed. Lasts {3} min. This effect can only be on one target at a time."] = "Koruyucu bakışını bir grup veya raid hedefine odaklar; aldıkları hasarı %{1} azaltır ve oluşturdukları tehdidin -%{2}'sini sana aktarır. Ayrıca, her saldırı aldıklarında Taunt bekleme süren yenilenir. {3} dk sürer. Bu etki aynı anda yalnızca bir hedefte bulunabilir.",
   ["Forces all enemies within {1} yards to focus attacks on you for {2} sec."] = "{1} yard içindeki tüm düşmanları {2} sn boyunca saldırılarını sana yöneltmeye zorlar.",
   ["Forces all nearby enemies within {1} yards to focus attacks on you for {2} sec."] = "{1} yard içindeki yakındaki tüm düşmanları {2} sn boyunca saldırılarını sana yöneltmeye zorlar.",
   ["Forces the enemy target to sleep for up to {1} sec. Any damage will awaken the target. Only one target can be forced to hibernate at a time. Only works on Beasts and Dragonkin."] = "Düşman hedefi {1} sn'ye kadar uyumaya zorlar. Herhangi bir hasar hedefi uyandırır. Aynı anda yalnızca bir hedef hibernasyona zorlanabilir. Yalnızca Beast ve Dragonkin üzerinde işe yarar.",
   ["Forces the target to speak in Demonic, increasing the casting time of all spells by {1}%. Only one Curse per Warlock can be active on any one target. Lasts {2} sec."] = "Hedefi Demonic dilinde konuşmaya zorlar; tüm büyülerin okuma süresini %{1} artırır. Her Warlock'tan aynı hedefte yalnızca bir Curse etkin olabilir. {2} sn sürer.",
   ["Garrote the enemy, causing {1} damage over {2} sec, increased by your attack power. Must be stealthed and behind the target. Awards {3} combo point."] = "Garrote ile düşmanı boğazlar; {2} sn boyunca {1} hasar verir, saldırı gücünle artar. Gizlenmiş ve hedefin arkasında olmalısın. {3} combo puanı kazandırır.",
   ["Garrote the enemy, silencing them for {1} sec and causing {2} damage over {3} sec, increased by attack power. Must be stealthed and behind the target. Awards {4} combo point."] = "Garrote ile düşmanı boğazlar; onu {1} sn boyunca susturur ve {3} sn boyunca {2} hasar verir, saldırı gücüyle artar. Gizlenmiş ve hedefin arkasında olmalısın. {4} combo puanı kazandırır.",
   ["Garrote the enemy, silencing them for {1} sec causing {2} damage over {3} sec, increased by attack power. Must be stealthed and behind the target. Awards {4} combo point."] = "Garrote ile düşmanı boğazlar; onu {1} sn boyunca susturur ve {3} sn boyunca {2} hasar verir, saldırı gücüyle artar. Gizlenmiş ve hedefin arkasında olmalısın. {4} combo puanı kazandırır.",
   ["Gather information about the target beast. The tooltip will display damage, health, armor, any special resistances, and diet. In addition, Beast Lore will reveal whether or not the creature is tameable and what abilities the tamed creature has."] = "Hedef canavar hakkında bilgi toplar. Araç ipucu hasarı, canı, zırhı, varsa özel dirençleri ve beslenme türünü gösterir. Ayrıca Beast Lore, yaratığın evcilleştirilebilir olup olmadığını ve evcilleştirilen yaratığın hangi yeteneklere sahip olduğunu ortaya çıkarır.",
   ["Generates {1} rage at the cost of health, and then generates an additional {2} rage over {3} sec."] = "Can karşılığında {1} öfke üretir ve ardından {3} sn boyunca {2} ek öfke üretir.",
   ["Generates {1} rage, and then generates an additional {2} rage over {3} sec, but reduces base armor by {4}% in Bear Form and {5}% in Dire Bear Form."] = "{1} öfke üretir ve ardından {3} sn boyunca {2} ek öfke üretir, ancak temel zırhı Bear Form'da %{4} ve Dire Bear Form'da %{5} azaltır.",
   ["Give the command to kill, increasing your pet's damage done from special attacks by {1}% for {2} sec. Each special attack done by the pet reduces the damage bonus by {3}%."] = "Öldürme emri verir; evcil hayvanının özel saldırılardan verdiği hasarı {2} sn boyunca %{1} artırır. Evcil hayvanın yaptığı her özel saldırı hasar bonusunu %{3} azaltır.",
   ["Gives a chance to block enemy melee and ranged attacks."] = "Düşmanın yakın dövüş ve menzilli saldırılarını engelleme şansı verir.",
   ["Gives a chance to dodge enemy melee attacks."] = "Düşmanın yakın dövüş saldırılarını sıyırma şansı verir.",
   ["Gives a chance to parry enemy melee attacks."] = "Düşman yakın dövüş saldırılarını savuşturma şansı verir.",
   ["Gives a {1}% chance to remove all movement impairing effects when you activate your Sprint ability."] = "Sprint yeteneğini aktive ettiğinde hareketi engelleyen tüm etkileri kaldırma şansını %{1} verir.",
   ["Gives all members of the raid or group that share the same class with the target the Greater Blessing of Kings, increasing total stats by {1}% for {2} min. Players may only have one Blessing on them per Paladin at any one time."] = "Raid veya gruptaki, hedefle aynı sınıfı paylaşan tüm üyelere Greater Blessing of Kings verir; toplam statları {2} dk boyunca %{1} artırır. Oyuncular her Paladin başına aynı anda yalnızca bir Blessing taşıyabilir.",
   ["Gives all members of the raid or group that share the same class with the target the Greater Blessing of Might, increasing attack power by {1} for {2} min. Players may only have one Blessing on them per Paladin at any one time."] = "Raid veya gruptaki, hedefle aynı sınıfı paylaşan tüm üyelere Greater Blessing of Might verir; saldırı gücünü {2} dk boyunca {1} artırır. Oyuncular her Paladin başına aynı anda yalnızca bir Blessing taşıyabilir.",
   ["Gives all members of the raid or group that share the same class with the target the Greater Blessing of Sanctuary, reducing damage taken from all sources by {1}% for {2} min and increasing strength and stamina by {3}%. In addition, when the target blocks, parries, or dodges a melee attack the target will gain {4}% of maximum displayed mana. Players may only have one Blessing on them per Paladin at any one time."] = "Raid veya gruptaki, hedefle aynı sınıfı paylaşan tüm üyelere Greater Blessing of Sanctuary verir; tüm kaynaklardan alınan hasarı {2} dk boyunca %{1} azaltır ve strength ile stamina'yı %{3} artırır. Ayrıca hedef bir yakın dövüş saldırısını engellediğinde, savuşturduğunda veya sıyırdığında azami görünen manasının %{4}'ünü kazanır. Oyuncular her Paladin başına aynı anda yalnızca bir Blessing taşıyabilir.",
   ["Gives all members of the raid or group that share the same class with the target the Greater Blessing of Wisdom, restoring {1} mana every {2} seconds for {3} min. Players may only have one Blessing on them per Paladin at any one time."] = "Raid veya gruptaki, hedefle aynı sınıfı paylaşan tüm üyelere Greater Blessing of Wisdom verir; {3} dk boyunca her {2} sn'de {1} mana geri kazandırır. Oyuncular her Paladin başına aynı anda yalnızca bir Blessing taşıyabilir.",
   ["Gives the Gift of the Wild to all party and raid members, increasing armor by {1}, all attributes by {2} and all resistances by {3} for {4} hour."] = "Tüm party ve raid üyelerine Gift of the Wild verir; {4} saat boyunca zırhı {1}, tüm özellikleri {2} ve tüm dirençleri {3} artırır.",
   ["Gives the Jewelcrafter the chance to cut uncommon quality Northrend gems into perfect gems."] = "Jewelcrafter'a, uncommon kalitedeki Northrend gem'lerini perfect gem'lere kesme şansı verir.",
   ["Gives the Mend Pet spell a {1}% chance of cleansing {2} Curse, Disease, Magic or Poison effect from the pet each tick."] = "Mend Pet büyüsüne, her tikte evcil hayvandan {2} Lanet, Hastalık, Büyü veya Zehir etkisini temizleme şansını %{1} verir.",
   ["Gives the Paladin a chance to deal additional Holy damage equal to {1}% of normal weapon damage. Only one Seal can be active on the Paladin at any one time. Lasts {2} sec.Unleashing this Seal's energy will judge an enemy, instantly causing {3} to {4} Holy damage, {5} to {6} if the target is stunned or incapacitated."] = "Paladin'e, normal silah hasarının %{1} kadarına eşit ek Kutsal hasar verme şansı verir. Paladin'de aynı anda yalnızca bir Seal aktif olabilir. {2} sn sürer. Bu Seal'in enerjisini serbest bırakmak bir düşmanı yargılar ve anında {3} ila {4} Kutsal hasar, hedef sersemlemiş veya etkisiz hale getirilmişse {5} ila {6} hasar verir.",
   ["Gives the Paladin's damaging melee attacks a chance to reduce the target's attack poewr by {1} for {2} sec."] = "Paladinin hasar veren yakın dövüş saldırılarına, hedefin saldırı gücünü {2} sn boyunca {1} azaltma şansı verir.",
   ["Gives the Paladin's damaging melee attacks a chance to reduce the target's attack power by {1} for {2} sec."] = "Paladinin hasar veren yakın dövüş saldırılarına, hedefin saldırı gücünü {2} sn boyunca {1} azaltma şansı verir.",
   ["Gives the Paladin's damaging melee attacks a chance to reduce the target's Strength and Agility by {1}% for {2} sec."] = "Paladin'in hasar veren yakın dövüş saldırılarına, hedefin Gücünü ve Çevikliğini {2} sn boyunca %{1} azaltma şansı verir.",
   ["Gives the target of your Lay on Hands spell a {1}% bonus to their armor value from items for {2} min. In addition, the cooldown for your Lay on Hands spell is reduced by {3} min."] = "Lay on Hands büyünün hedefine, eşyalardan gelen zırh değerine {2} dk boyunca %{1} bonus verir. Ayrıca Lay on Hands büyünün bekleme süresi {3} dk azalır.",
   ["Gives you a chance when hit by a melee or ranged attack to increase your movement speed by {1}% and dispel all movement impairing effects. This effect lasts {2} sec."] = "Bir yakın dövüş veya menzilli saldırıyla vurulduğunda hareket hızını %{1} artırma ve tüm hareketi engelleyen etkileri kaldırma şansı verir. Bu etki {2} sn sürer.",
   ["Gives you a {1}% bonus to Physical and Holy damage you deal for {2} sec after dealing a critical strike from a weapon swing, spell, or ability."] = "Bir silah savurması, büyü veya yetenekten kritik bir vuruş yaptıktan sonra, {2} sn boyunca verdiğin Fiziksel ve Kutsal hasara %{1} bonus verir.",
   ["Gives you a {1}% chance of entering a Clearcasting state after any damage spell hits a target. The Clearcasting state reduces the mana cost of your next damage spell by {2}%."] = "Herhangi bir hasar büyüsü bir hedefe isabet ettikten sonra Clearcasting durumuna girme şansını %{1} verir. Clearcasting durumu, bir sonraki hasar büyünün mana maliyetini %{2} azaltır.",
   ["Gives you a {1}% chance to add a combo point to your target after dodging their attack or fully resisting one of their spells."] = "Hedefin saldırısını sıyırdıktan veya büyülerinden birine tamamen direndikten sonra hedefine bir combo puanı ekleme şansını %{1} verir.",
   ["Gives you a {1}% chance to add an additional combo point to your target when using your Ambush, Garrote, or Cheap Shot ability."] = "Ambush, Garrote veya Cheap Shot yeteneğini kullanırken hedefine ek bir combo puanı ekleme şansını %{1} verir.",
   ["Gives you a {1}% chance to avoid interruption caused by damage while casting any healing spell."] = "Herhangi bir iyileştirme büyüsü yaparken hasardan kaynaklanan kesilmeyi önleme şansını %{1} verir.",
   ["Gives you a {1}% chance to avoid interruption caused by damage while casting Entangling Roots."] = "Entangling Roots yaparken hasardan kaynaklanan kesilmeyi önleme şansını %{1} verir.",
   ["Gives you a {1}% chance to avoid interruption caused by damage while casting the Healing Touch, Regrowth and Tranquility spells."] = "Healing Touch, Regrowth ve Tranquility büyülerini yaparken hasardan kaynaklanan kesilmeyi önleme şansını %{1} verir.",
   ["Gives you a {1}% chance to avoid interruption caused by damage while channeling Arcane Missiles."] = "Arcane Missiles'ı kanalize ederken hasardan kaynaklanan kesilmeyi önleme şansını %{1} verir.",
   ["Gives you a {1}% chance to avoid interruption caused by damage while channeling the Drain Life, Drain Mana, or Drain Soul spell."] = "Drain Life, Drain Mana veya Drain Soul büyüsünü kanalize ederken hasardan kaynaklanan kesilmeyi önleme şansını %{1} verir.",
   ["Gives you a {1}% chance to enter a Clearcasting state after casting any Fire, Frost, or Nature damage spell. The Clearcasting state reduces the mana cost of your next damage spell by {2}%."] = "Herhangi bir Ateş, Buz veya Doğa hasar büyüsü yaptıktan sonra Clearcasting durumuna girme şansını %{1} verir. Clearcasting durumu, bir sonraki hasar büyünün mana maliyetini %{2} azaltır.",
   ["Gives you a {1}% chance to gain a {2}% bonus to your Spirit after killing a target that yields experience. For the duration, your Mana will regenerate at a {3}% rate while casting. Lasts {4} sec."] = "Deneyim veren bir hedefi öldürdükten sonra Ruhuna %{2} bonus kazanma şansını %{1} verir. Süre boyunca Manan büyü yaparken %{3} oranında yenilenir. {4} sn sürer.",
   ["Gives you a {1}% chance to gain an additional {2} Rage anytime you get a critical strike while in Bear and Dire Bear Form."] = "Bear ve Dire Bear Form'dayken kritik bir vuruş yaptığında ek {2} Rage kazanma şansını %{1} verir.",
   ["Gives you a {1}% chance to gain an extra attack after being the victim of a critical strike."] = "Bir kritik vuruşun kurbanı olduktan sonra ekstra bir saldırı kazanma şansını %{1} verir.",
   ["Gives you a {1}% chance to gain the Focused Casting effect that lasts for {2} sec after being the victim of a melee or ranged critical strike. The Focused Casting effect prevents you from losing casting time when taking damage and increases resistance to Interrupt effects by {3}%."] = "Bir yakın dövüş veya menzilli kritik vuruşun kurbanı olduktan sonra {2} sn süren Focused Casting etkisini kazanma şansını %{1} verir. Focused Casting etkisi, hasar alırken okuma süresi kaybetmeni önler ve Kesme etkilerine direnci %{3} artırır.",
   ["Gives you a {1}% chance to gain the Focused Casting effect that lasts for {2} sec after being the victim of a melee or ranged critical strike. The Focused Casting effect prevents you from losing casting time when taking damage."] = "Bir yakın dövüş veya menzilli kritik vuruşun kurbanı olduktan sonra {2} sn süren Focused Casting etkisini kazanma şansını %{1} verir. Focused Casting etkisi, hasar alırken okuma süresi kaybetmeni önler.",
   ["Gives you a {1}% chance to generate an additional Rage point when you deal melee damage with a weapon."] = "Bir silahla yakın dövüş hasarı verdiğinde ek bir Rage puanı üretme şansını %{1} verir.",
   ["Gives you a {1}% chance to get a {2}% increase to your Mana regeneration for {3} sec if the target is killed by you while you drain its soul. In addition your Mana may continue to regenerate while casting at {4}% of normal."] = "Ruhunu emerken hedef senin tarafından öldürülürse, {3} sn boyunca Mana yenilenmene %{2} artış kazanma şansını %{1} verir. Ayrıca Manan büyü yaparken normalin %{4} oranında yenilenmeye devam edebilir.",
   ["Gives you a {1}% chance to get an extra attack on the same target after dealing damage with your Sword."] = "Kılıcınla hasar verdikten sonra aynı hedefe ekstra bir saldırı kazanma şansını %{1} verir.",
   ["Gives you a {1}% chance to resist interruption caused by damage while channeling the Rain of Fire, Hellfire or Soul Fire spell."] = "Rain of Fire, Hellfire veya Soul Fire büyüsünü kanalize ederken hasardan kaynaklanan kesilmeye direnme şansını %{1} verir.",
   ["Gives you a {1}% chance to return to stealth mode after using your Sap ability."] = "Sap yeteneğini kullandıktan sonra gizlenme moduna geri dönme şansını %{1} verir.",
   ["Gives you a {1}% chance to stun your target for {2} sec with a Mace."] = "Bir Topuzla hedefini {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives you a {1}% melee damage bonus for {2} sec up to a maximum of {3} swings after being the victim of a critical strike."] = "Bir kritik vuruşun kurbanı olduktan sonra, en fazla {3} savurmaya kadar {2} sn boyunca %{1} yakın dövüş hasarı bonusu verir.",
   ["Gives you an extra attack. In addition, the next {1} sources of Nature damage dealt to the target are increased by {2}%. Lasts {3} sec."] = "Sana ekstra bir saldırı verir. Ayrıca hedefe verilen bir sonraki {1} Doğa hasarı kaynağı %{2} artar. {3} sn sürer.",
   ["Gives you {1}% chance to gain {2} Rage when you shapeshift into Bear and Dire Bear Form or {3} Energy when you shapeshift into Cat Form."] = "Bear ve Dire Bear Form'a dönüştüğünde {2} Rage veya Cat Form'a dönüştüğünde {3} Energy kazanma şansını %{1} verir.",
   ["Gives your Arcane Blast, Arcane Barrage, Fireball, Frostbolt and Frostfire Bolt spells a chance to reduce the channeled duration of the next Arcane Missiles spell by {1}.{2} secs, reduce the mana cost by {3}%, and missiles will fire every .{4} secs."] = "Arcane Blast, Arcane Barrage, Fireball, Frostbolt ve Frostfire Bolt büyülerine, bir sonraki Arcane Missiles büyüsünün kanalize süresini {1}.{2} sn azaltma, mana maliyetini %{3} azaltma ve füzelerin her .{4} sn'de bir ateşlenmesini sağlama şansı verir.",
   ["Gives your Chill effects a chance to freeze the target for {1} sec."] = "Chill etkilerine, hedefi {1} sn boyunca dondurma şansı verir.",
   ["Gives your Chill effects a chance to grant you the Fingers of Frost effect, which treats your next spells cast as if the target were Frozen. Lasts {1} sec."] = "Chill etkilerine, sana Fingers of Frost etkisini kazandırma şansı verir; bu, bir sonraki yaptığın büyüleri hedef Frozen'mış gibi işler. {1} sn sürer.",
   ["Gives your Chill effects a {1}% chance to freeze the target for {2} sec."] = "Chill etkilerine hedefi {2} sn boyunca dondurma şansını %{1} verir.",
   ["Gives your Concussive Shot a {1}% chance to stun the target for {2} sec."] = "Concussive Shot'ına hedefi {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives your Corruption and Drain Life spells a {1}% chance to cause you to enter a Shadow Trance state after damaging the opponent. The Shadow Trance state reduces the casting time of your next Shadow Bolt spell by {2}%."] = "Corruption ve Drain Life büyülerine, rakibe hasar verdikten sonra seni Shadow Trance durumuna sokma şansını %{1} verir. Shadow Trance durumu, bir sonraki Shadow Bolt büyünün okuma süresini %{2} azaltır.",
   ["Gives your Counterspell a {1}% chance to silence the target for {2} sec."] = "Counterspell'ine hedefi {2} sn boyunca susturma şansını %{1} verir.",
   ["Gives your Destruction spells a {1}% chance to daze the target for {2} sec."] = "Destruction büyülerine hedefi {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives your finishing moves a {1}% chance to add a combo point to your target."] = "Bitirme hareketlerine hedefine bir combo puanı ekleme şansını %{1} verir.",
   ["Gives your Fire spells a {1}% chance to not lose casting time when you take damage and reduces the threat caused by your Fire spells by {2}%."] = "Ateş büyülerine, hasar aldığında okuma süresi kaybetmeme şansını %{1} verir ve Ateş büyülerinin oluşturduğu tehdidi %{2} azaltır.",
   ["Gives your Fire spells a {1}% chance to stun the target for {2} sec."] = "Ateş büyülerine hedefi {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives your Flash of Light and Holy Light spells a {1}% chance to not lose casting time when you take damage."] = "Flash of Light ve Holy Light büyülerine, hasar aldığında okuma süresi kaybetmeme şansını %{1} verir.",
   ["Gives your Frost damage spells a {1}% chance to apply the Winter's Chill effect, which increases the chance a Frost spell will critically hit the target by {2}% for {3} sec. Stacks up to {4} times."] = "Buz hasar büyülerine, bir Buz büyüsünün hedefe kritik isabet etme şansını {3} sn boyunca %{2} artıran Winter's Chill etkisini uygulama şansını %{1} verir. {4} defaya kadar üst üste birikir.",
   ["Gives your Hamstring ability a {1}% chance to immobilize the target for {2} sec."] = "Hamstring yeteneğine hedefi {2} sn boyunca hareketsiz bırakma şansını %{1} verir.",
   ["Gives your Holy Light spell a chance to reduce the cast time of your next Holy Light spell by {1}.{2} sec. This effect lasts {3} sec."] = "Holy Light büyüne, bir sonraki Holy Light büyünün okuma süresini {1}.{2} sn azaltma şansı verir. Bu etki {3} sn sürer.",
   ["Gives your Immolation Trap, Frost Trap, and Explosive Trap a {1}% chance to entrap the target, preventing them from moving for {2} sec."] = "Immolation Trap, Frost Trap ve Explosive Trap'ine hedefi tuzağa düşürme şansını %{1} verir; {2} sn boyunca hareket etmelerini önler.",
   ["Gives your Kick ability a {1}% chance to silence the target for {2} sec."] = "Kick yeteneğine hedefi {2} sn boyunca susturma şansını %{1} verir.",
   ["Gives your pet a {1}% chance to gain a {2}% attack speed increase for {3} sec after dealing a critical strike."] = "Evcil hayvanına, kritik bir vuruş yaptıktan sonra {3} sn boyunca %{2} saldırı hızı artışı kazanma şansını %{1} verir.",
   ["Gives your Rain of Fire, Hellfire, and Soul Fire spells a {1}% chance to stun the target for {2} sec."] = "Rain of Fire, Hellfire ve Soul Fire büyülerine hedefi {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives your Revenge ability a {1}% chance to stun the target for {2} sec."] = "Revenge yeteneğine hedefi {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives your Shadow damage spells a {1}% chance to stun the target for {2} sec."] = "Gölge hasar büyülerine hedefi {2} sn boyunca sersemletme şansını %{1} verir.",
   ["Gives your Shield Bash ability a {1}% chance to silence the target for {2} sec."] = "Shield Bash yeteneğine hedefi {2} sn boyunca susturma şansını %{1} verir.",
   ["Gives your Wing Clip ability a {1}% chance to immobilize the target for {2} sec."] = "Wing Clip yeteneğine hedefi {2} sn boyunca hareketsiz bırakma şansını %{1} verir.",
   ["Gives {1} additional armor to party and raid members within {2} yards. Players may only have one Aura on them per Paladin at any one time."] = "{2} yard içindeki party ve raid üyelerine {1} ek zırh verir. Oyuncular her Paladin başına aynı anda yalnızca bir Aura taşıyabilir.",
   ["Gives {1} additional Fire resistance to all party and raid members within {2} yards. Players may only have one Aura on them per Paladin at any one time."] = "{2} yard içindeki tüm party ve raid üyelerine {1} ek Ateş direnci verir. Oyuncular her Paladin başına aynı anda yalnızca bir Aura taşıyabilir.",
   ["Gives {1} additional Frost resistance to all party and raid members within {2} yards. Players may only have one Aura on them per Paladin at any one time."] = "{2} yard içindeki tüm party ve raid üyelerine {1} ek Buz direnci verir. Oyuncular her Paladin başına aynı anda yalnızca bir Aura taşıyabilir.",
   ["Gives {1} additional Shadow resistance to all party and raid members within {2} yards. Players may only have one Aura on them per Paladin at any one time."] = "{2} yard içindeki tüm party ve raid üyelerine {1} ek Gölge direnci verir. Oyuncular her Paladin başına aynı anda yalnızca bir Aura taşıyabilir.",
   ["Gives {1} health to the caster's pet every second for {2} sec as long as the caster channels."] = "Büyücü kanalize ettiği sürece, büyücünün evcil hayvanına {2} sn boyunca her saniye {1} can verir.",
   ["Gives {1} health to the caster's pet every second for {2}.{3} sec as long as the caster channels."] = "Büyücü kanalize ettiği sürece, büyücünün evcil hayvanına {2}.{3} sn boyunca her saniye {1} can verir.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active.Imp - Reduces threat caused by {1}%.Voidwalker - Reduces physical damage taken by {2}%.Succubus - Increases all damage caused by {3}%.Felhunter - Increases all resistances by .{4} per level."] = "Hem Warlock'a hem de çağrılan iblise, o iblis aktif olduğu sürece bir etki verir. Imp - Oluşturulan tehdidi %{1} azaltır. Voidwalker - Alınan fiziksel hasarı %{2} azaltır. Succubus - Verilen tüm hasarı %{3} artırır. Felhunter - Tüm dirençleri seviye başına .{4} artırır.",
   ["Grants both the Warlock and the summoned demon an effect as long as that demon is active.Imp - Reduces threat caused by {1}%.Voidwalker - Reduces physical damage taken by {2}%.Succubus - Increases all damage caused by {3}%.Felhunter - Increases all resistances by {4} per level."] = "Hem Warlock'a hem de çağrılan iblise, o iblis aktif olduğu sürece bir etki verir. Imp - Oluşturulan tehdidi %{1} azaltır. Voidwalker - Alınan fiziksel hasarı %{2} azaltır. Succubus - Verilen tüm hasarı %{3} artırır. Felhunter - Tüm dirençleri seviye başına {4} artırır.",
   ["Greatly increased chance to detect traps."] = "Tuzakları tespit etme şansını büyük ölçüde artırır.",
   ["Greatly increases stealth detection and shows hidden units within detection range on the minimap. Only one form of tracking can be active at a time."] = "Gizlilik tespitini büyük ölçüde artırır ve tespit menzili içindeki gizli birimleri minimap'te gösterir. Aynı anda yalnızca bir takip türü etkin olabilir.",
   ["Harness the unholy energy that surrounds and binds all matter, drawing the target toward the death knight and forcing the enemy to attack the death knight for {1} sec."] = "Tüm maddeyi saran ve bağlayan kutsal olmayan enerjiyi dizginler; hedefi death knight'a doğru çeker ve düşmanı {1} sn boyunca death knight'a saldırmaya zorlar.",
   ["Heal your target for {1} to {2}."] = "Hedefini {1} ila {2} iyileştirir.",
   ["Heals a friendly target and the caster for {1} to {2}. Low threat."] = "Dost bir hedefi ve büyücüyü {1} ila {2} iyileştirir. Düşük tehdit.",
   ["Heals a friendly target for an amount equal to the Paladin's maximum health and restores {1} of their mana. If used on self, the Paladin cannot be targeted by Divine Shield, Divine Protection, Hand of Protection, or self-targeted Lay on Hands again for {2} min. Also cannot be used on self within {3} sec of using Avenging Wrath."] = "Dost bir hedefi Paladinin azami canına eşit miktarda iyileştirir ve manasının {1}'ini geri kazandırır. Kendine kullanılırsa, Paladin {2} dk boyunca Divine Shield, Divine Protection, Hand of Protection veya kendine yönelik Lay on Hands ile tekrar hedeflenemez. Ayrıca Avenging Wrath kullanıldıktan sonra {3} sn içinde kendine kullanılamaz.",
   ["Heals a friendly target for an amount equal to the Paladin's maximum health. If used on self, the Paladin cannot be targeted by Divine Shield, Divine Protection, Hand of Protection, or self-targeted Lay on Hands again for {1} min. Also cannot be used on self within {2} sec of using Avenging Wrath."] = "Dost bir hedefi Paladinin azami canına eşit miktarda iyileştirir. Kendine kullanılırsa, Paladin {1} dk boyunca Divine Shield, Divine Protection, Hand of Protection veya kendine yönelik Lay on Hands ile tekrar hedeflenemez. Ayrıca Avenging Wrath kullanıldıktan sonra {2} sn içinde kendine kullanılamaz.",
   ["Heals a friendly target for {1} to {2} and another {3} over {4} sec."] = "Dost bir hedefi {1} ila {2} iyileştirir ve {4} sn boyunca {3} daha iyileştirir.",
   ["Heals a friendly target for {1} to {2}."] = "Dost bir hedefi {1} ila {2} iyileştirir.",
   ["Heals a friendly target for {1} to {2}. Heals for an additional {3}% if you have a Rejuvenation, Regrowth, Lifebloom, or Wild Growth effect active on the target."] = "Dost bir hedefi {1} ila {2} iyileştirir. Hedefte etkin bir Rejuvenation, Regrowth, Lifebloom veya Wild Growth etkisi varsa %{3} fazla iyileştirir.",
   ["Heals all nearby group members for {1} every {2} seconds for {3} sec. Druid must channel to maintain the spell."] = "Yakındaki tüm grup üyelerini {3} sn boyunca her {2} sn'de {1} iyileştirir. Druid büyüyü sürdürmek için kanalize etmelidir.",
   ["Heals all nearby group members for {1} every {2}.{3} seconds for {4}.{5} sec. Druid must channel to maintain the spell."] = "Yakındaki tüm grup üyelerini {4}.{5} sn boyunca her {2}.{3} sn'de {1} iyileştirir. Druid büyüyü sürdürmek için kanalize etmelidir.",
   ["Heals the friendly target for {1} to {2}, then jumps to heal additional nearby targets. If cast on a party member, the heal will only jump to other party members. Each jump reduces the effectiveness of the heal by {3}%. Heals {4} total targets."] = "Dost hedefi {1} ila {2} iyileştirir, ardından yakındaki ek hedeflere sıçrayarak onları iyileştirir. Bir party üyesine büyü yapıldığında, iyileştirme yalnızca diğer party üyelerine sıçrar. Her sıçrama iyileştirmenin etkinliğini %{3} azaltır. Toplam {4} hedefi iyileştirir.",
   ["Heals the target for {1} over {2} sec."] = "Hedefi {2} sn boyunca {1} iyileştirir.",
   ["Heals the target for {1} over {2} sec. The amount healed is increased by your attack power."] = "Hedefi {2} sn boyunca {1} iyileştirir. İyileştirilen miktar saldırı gücünle artar.",
   ["Heals the target for {1} over {2} sec. The amount healed is increased by your spell power or attack power, whichever is higher."] = "Hedefi {2} sn boyunca {1} iyileştirir. İyileştirilen miktar büyü gücün veya saldırı gücünden hangisi yüksekse onunla artar.",
   ["Heals the target for {1} over {2} sec. The amount healed is increased by your spell power."] = "Hedefi {2} sn boyunca {1} iyileştirir. İyileştirilen miktar büyü gücünle artar.",
   ["Heals the target for {1} over {2} sec. When Lifebloom completes its duration or is dispelled, the target instantly heals themself for {3} and the Druid regains half the cost of the spell. This effect can stack up to {4} times on the same target."] = "Hedefi {2} sn boyunca {1} iyileştirir. Lifebloom süresini tamamladığında veya dağıtıldığında, hedef anında kendini {3} iyileştirir ve Druid büyünün maliyetinin yarısını geri kazanır. Bu etki aynı hedefte en fazla {4} kez üst üste binebilir.",
   ["Heals the target over {1} sec."] = "Hedefi {1} sn boyunca iyileştirir.",
   ["Heals your pet for {1} health over {2} sec."] = "Evcil hayvanını {2} sn boyunca {1} can iyileştirir.",
   ["Heals {1} nearby lowest health friendly party or raid targets within {2} yards for {3} to {4} every {5} sec for {6} sec, and increases healing done to them by {7}% for {8} sec. Maximum of {9} heals. The Priest must channel to maintain the spell."] = "{2} yard içindeki, canı en düşük {1} dost party veya raid hedefini {6} sn boyunca her {5} sn'de {3} ila {4} iyileştirir ve onlara yapılan iyileştirmeyi {8} sn boyunca %{7} artırır. En fazla {9} iyileştirme. Priest büyüyü sürdürmek için kanalize etmelidir.",
   ["Heals {1} nearby lowest health friendly party or raid targets within {2} yards for {3} to {4} every {5}.{6} sec for {7}.{8} sec, and increases healing done to them by {9}% for {10} sec. Maximum of {11} heals. The Priest must channel to maintain the spell."] = "{2} yard içindeki, canı en düşük {1} dost party veya raid hedefini {7}.{8} sn boyunca her {5}.{6} sn'de {3} ila {4} iyileştirir ve onlara yapılan iyileştirmeyi {10} sn boyunca %{9} artırır. En fazla {11} iyileştirme. Priest büyüyü sürdürmek için kanalize etmelidir.",
   ["Holy power infuses the target, increasing their Spirit by {1} for {2} min."] = "Kutsal güç hedefe nüfuz eder; Ruhunu {2} dk boyunca {1} artırır.",
   ["Howl, causing {1} enemies within {2} yds to flee in terror for {3} sec. Damage caused may interrupt the effect."] = "Uluyarak {2} yard içindeki {1} düşmanı {3} sn boyunca dehşet içinde kaçırtır. Verilen hasar etkiyi kesebilir.",
   ["Hurls a fiery ball that causes {1} to {2} Fire damage and an additional {3} Fire damage over {4} sec."] = "Ateşli bir top fırlatır; {1} ila {2} Ateş hasarı ve {4} sn boyunca {3} ek Ateş hasarı verir.",
   ["Hurls a hammer that strikes an enemy for {1} to {2} Holy damage. Only usable on enemies that have {3}% or less health."] = "Bir düşmana çarpan bir çekiç fırlatır; {1} ila {2} Kutsal hasar verir. Yalnızca canı %{3} veya daha az olan düşmanlarda kullanılabilir.",
   ["Hurls a holy shield at the enemy, dealing {1} to {2} Holy damage, Dazing them and then jumping to additional nearby enemies. Affects {3} total targets. Lasts {4} sec."] = "Düşmana kutsal bir kalkan fırlatır; {1} ila {2} Kutsal hasar verir, onları sersemletir ve ardından yakındaki ek düşmanlara sıçrar. Toplam {3} hedefi etkiler. {4} sn sürer.",
   ["Hurls a lightning bolt at the enemy, dealing {1} to {2} Nature damage and then jumping to additional nearby enemies. Each jump reduces the damage by {3}%. Affects {4} total targets."] = "Düşmana bir şimşek oku fırlatır; {1} ila {2} Doğa hasarı verir ve ardından yakındaki ek düşmanlara sıçrar. Her sıçrama hasarı %{3} azaltır. Toplam {4} hedefi etkiler.",
   ["Hurls an immense fiery boulder that causes {1} to {2} Fire damage and an additional {3} Fire damage over {4} sec."] = "{1} ila {2} Ateş hasarı veren ve {4} sn boyunca ek {3} Ateş hasarı uygulayan devasa bir ateşli kaya fırlatır.",
   ["Ice shards pelt the target area doing {1} Frost damage over {2} sec."] = "Buz parçaları hedef alanı döver; {2} sn boyunca {1} Buz hasarı verir.",
   ["Ice shards pelt the target area doing {1} Frost damage over {2}.{3} sec."] = "Buz parçaları hedef alanı döver; {2}.{3} sn boyunca {1} Buz hasarı verir.",
   ["Ignites a target that is already afflicted by Immolate, dealing {1} to {2} Fire damage and consuming the Immolate spell."] = "Zaten Immolate etkisi altında olan bir hedefi tutuşturur; {1} ila {2} Ateş hasarı verir ve Immolate büyüsünü tüketir.",
   ["Ignites the area surrounding the caster, causing {1} Fire damage to herself and {2} Fire damage to all nearby enemies every {3}.{4} sec. Lasts {5}.{6} sec."] = "Büyücünün çevresindeki alanı tutuşturur; her {3}.{4} sn'de büyücüye {1} Ateş hasarı ve yakındaki tüm düşmanlara {2} Ateş hasarı verir. {5}.{6} sn sürer.",
   ["Ignites the area surrounding the caster, causing {1} Fire damage to himself and {2} Fire damage to all nearby enemies every {3} sec. Lasts {4} sec."] = "Büyücünün çevresindeki alanı tutuşturur; her {3} sn'de büyücüye {1} Ateş hasarı ve yakındaki tüm düşmanlara {2} Ateş hasarı verir. {4} sn sürer.",
   ["Imbeds a demon seed in the enemy target, causing {1} Shadow damage over {2} sec. When the target takes {3} total damage or dies, the seed will inflict {4} to {5} Shadow damage to all enemies within {6} yards of the target. Only one Corruption spell per Warlock can be active on any one target."] = "Düşman hedefe bir iblis tohumu yerleştirir; {2} sn boyunca {1} Gölge hasarı verir. Hedef toplam {3} hasar aldığında veya öldüğünde, tohum hedefin {6} yard içindeki tüm düşmanlara {4} ila {5} Gölge hasarı verir. Her Warlock başına aynı hedefte yalnızca bir Corruption büyüsü etkin olabilir.",
   ["Imbue the Shaman's weapon with fire, increasing total spell damage by {1}. Each hit causes {2}.{3} to {4} additional Fire damage, based on the speed of the weapon. Slower weapons cause more fire damage per swing. Lasts {5} minutes."] = "Shaman'ın silahını ateşle güçlendirir; toplam büyü hasarını {1} artırır. Her vuruş, silahın hızına bağlı olarak {2}.{3} ila {4} ek Ateş hasarı verir. Daha yavaş silahlar vuruş başına daha fazla ateş hasarı verir. {5} dk sürer.",
   ["Imbue the Shaman's weapon with fire, increasing total spell damage by {1}. Each hit causes {2}.{3} to {4}.{5} additional Fire damage, based on the speed of the weapon. Slower weapons cause more fire damage per swing. Lasts {6} minutes."] = "Shaman'ın silahını ateşle güçlendirir; toplam büyü hasarını {1} artırır. Her vuruş, silahın hızına bağlı olarak {2}.{3} ila {4}.{5} ek Ateş hasarı verir. Daha yavaş silahlar vuruş başına daha fazla ateş hasarı verir. {6} dk sürer.",
   ["Imbue the Shaman's weapon with frost. Each hit has a chance of causing {1} additional Frost damage and slowing the target's movement speed by {2}% for {3} sec. Lasts {4} minutes."] = "Shaman'ın silahını buzla güçlendirir. Her vuruşun {1} ek Buz hasarı verme ve hedefin hareket hızını {3} sn boyunca %{2} yavaşlatma şansı vardır. {4} dk sürer.",
   ["Imbue the Shaman's weapon with frost. Each hit has a chance of causing {1} to {2} additional Frost damage and slowing the target's movement speed by {3}% for {4} sec. Lasts {5} minutes."] = "Shaman'ın silahını buzla güçlendirir. Her vuruşun {1} ila {2} ek Buz hasarı verme ve hedefin hareket hızını {4} sn boyunca %{3} yavaşlatma şansı vardır. {5} dk sürer.",
   ["Imbue the Shaman's weapon with wind. Each hit has a {1}% chance of dealing additional damage equal to two extra attacks with {2} extra attack power. Lasts {3} minutes."] = "Shaman'ın silahını rüzgarla güçlendirir. Her vuruşun %{1} ihtimalle, {2} ek saldırı gücüyle yapılan iki ek saldırıya eşit ek hasar verme şansı vardır. {3} dk sürer.",
   ["Imbue the Shaman's weapon, increasing its damage per second by {1}. Lasts {2} minutes."] = "Shaman'ın silahını güçlendirir; saniye başına hasarını {1} artırır. {2} dk sürer.",
   ["Imbues the Druid with natural energy. Each of the Druid's melee attacks has a chance of causing the caster to enter a Clearcasting state. The Clearcasting state reduces the Mana, Rage or Energy cost of your next damage or healing spell or offensive ability by {1}%. Lasts {2} min."] = "Druid'i doğal enerjiyle doldurur. Druid'in her yakın dövüş saldırısının, büyüyü yapanı bir Clearcasting durumuna sokma şansı vardır. Clearcasting durumu, bir sonraki hasar veya iyileştirme büyünün ya da saldırı yeteneğinin Mana, Rage veya Energy maliyetini %{1} azaltır. {2} dk sürer.",
   ["Immediately activates a Blood Rune and converts it into a Death Rune for the next {1} sec. Death Runes count as a Blood, Frost or Unholy Rune."] = "Bir Blood Rune'u anında etkinleştirir ve onu {1} sn boyunca bir Death Rune'a dönüştürür. Death Rune'lar Blood, Frost veya Unholy Rune sayılır.",
   ["Improves your chance to get a critical strike with your weapon attacks by {1}%."] = "Silah saldırılarınla kritik vuruş yapma şansını %{1} artırır.",
   ["In a whirlwind of steel you attack up to {1} enemies within {2} yards, causing weapon damage from both melee weapons to each enemy."] = "Bir çelik kasırgasıyla {2} yard içindeki {1} düşmana kadar saldırırsın; her düşmana iki yakın dövüş silahından da silah hasarı verir.",
   ["Incapacitates the target for up to {1} min. Must be stealthed. Only works on Humanoids, Beasts, Demons and Dragonkin that are not in combat. Any damage caused will revive the target. Only {2} target may be sapped at a time."] = "Hedefi {1} dk'ya kadar etkisiz hale getirir. Gizlenmiş olmalısın. Yalnızca savaşta olmayan Humanoid, Beast, Demon ve Dragonkin üzerinde işe yarar. Verilen herhangi bir hasar hedefi canlandırır. Aynı anda yalnızca {2} hedef Sap'lanabilir.",
   ["Incapacitates the target for up to {1} sec. Must be stealthed. Only works on Humanoids that are not in combat. Any damage caused will revive the target. Only {2} target may be sapped at a time."] = "Hedefi {1} sn'ye kadar etkisiz hale getirir. Gizlenmiş olmalısın. Yalnızca savaşta olmayan Humanoid üzerinde işe yarar. Verilen herhangi bir hasar hedefi canlandırır. Aynı anda yalnızca {2} hedef Sap'lanabilir.",
   ["Increases all damage and healing caused by {1}% for {2} sec. Cannot be used within {3} sec of being the target of Divine Shield, Divine Protection, or Hand of Protection, or of using Lay on Hands on oneself."] = "Verilen tüm hasarı ve iyileştirmeyi {2} sn boyunca %{1} artırır. Divine Shield, Divine Protection veya Hand of Protection hedefi olduktan ya da kendine Lay on Hands kullandıktan sonra {3} sn içinde kullanılamaz.",
   ["Increases all damage caused against Beasts, Giants and Dragonkin targets by {1}% and increases critical damage caused against Beasts, Giants and Dragonkin targets by an additional {2}%."] = "Canavarlara, Devlere ve Ejderha soyuna karşı verilen tüm hasarı %{1} artırır ve Canavarlara, Devlere ve Ejderha soyuna karşı verilen kritik hasarı ek olarak %{2} artırır.",
   ["Increases all damage caused against Humanoid targets by {1}% and increases critical damage caused against Humanoid targets by an additional {2}%."] = "İnsansı hedeflere karşı verilen tüm hasarı %{1} artırır ve İnsansı hedeflere karşı verilen kritik hasarı ek olarak %{2} artırır.",
   ["Increases all damage caused against Humanoid, Giant, Beast and Dragonkin targets by {1}%."] = "İnsansı, Dev, Canavar ve Ejderha soyu hedeflere karşı verilen tüm hasarı %{1} artırır.",
   ["Increases all resistances by {1} and causes all spells you fully resist to restore {2}% of your total mana. {3} sec. cooldown."] = "Tüm dirençleri {1} artırır ve tamamen direndiğin tüm büyülerin toplam mananın %{2} kadarını geri kazandırmasına neden olur. {3} sn bekleme süresi.",
   ["Increases Armor by {1} and Frost resistance by {2}. If an enemy strikes the caster, they may have their movement slowed by {3}% and the time between their attacks increased by {4}% for {5} sec. Only one type of Armor spell can be active on the Mage at any time. Lasts {6} min."] = "Zırhı {1} ve Buz direncini {2} artırır. Bir düşman büyücüye vurursa, hareketi {5} sn boyunca %{3} yavaşlayabilir ve saldırıları arasındaki süre %{4} artabilir. Mage üzerinde aynı anda yalnızca bir tür Armor büyüsü etkin olabilir. {6} dk sürer.",
   ["Increases Armor by {1}. If an enemy strikes the caster, they may have their movement slowed by {2}% and the time between their attacks increased by {3}% for {4} sec. Only one type of Armor spell can be active on the Mage at any time. Lasts {5} min."] = "Zırhı {1} artırır. Bir düşman büyücüye vurursa, hareketi {4} sn boyunca %{2} yavaşlayabilir ve saldırıları arasındaki süre %{3} artabilir. Mage üzerinde aynı anda yalnızca bir tür Armor büyüsü etkin olabilir. {5} dk sürer.",
   ["Increases attack power by {1}. Lasts {2} sec."] = "Saldırı gücünü {1} artırır. {2} sn sürer.",
   ["Increases chance to block by {1}% for {2} sec, and deals {3} Holy damage for each attack blocked while active. Damage caused by Holy Shield causes {4}% additional threat. Each block expends a charge. {5} charges."] = "Bloklama şansını {2} sn boyunca %{1} artırır ve aktifken bloklanan her saldırı için {3} Kutsal hasar verir. Holy Shield'in verdiği hasar %{4} ek tehdit oluşturur. Her bloklama bir şarj harcar. {5} şarj.",
   ["Increases chance to hit with all spells and attacks by {1}% for you and all party members within {2} yards."] = "Senin ve {2} yard içindeki tüm party üyelerinin tüm büyü ve saldırılarla isabet şansını %{1} artırır.",
   ["Increases crit chance by {1}%. Increases all damage taken by {2}%. Decreases threat generated by {3}%."] = "Kritik vurma şansını %{1} artırır. Alınan tüm hasarı %{2} artırır. Oluşturulan tehdidi %{3} azaltır.",
   ["Increases damage caused by your Thorns spell by {1}%."] = "Thorns büyünün verdiği hasarı %{1} artırır.",
   ["Increases damage done by {1} for {2} sec."] = "Verilen hasarı {2} sn boyunca {1} artırır.",
   ["Increases hit chance by {1}% and increases the chance movement impairing effects will be resisted by an additional {2}%."] = "İsabet şansını %{1} artırır ve hareketi engelleyen etkilere direnme şansını ek olarak %{2} artırır.",
   ["Increases Holy damage done by party members within {1} yards by {2}%. Players may only have one Aura on them per Paladin at any one time."] = "{1} metre içindeki grup üyelerinin verdiği Kutsal hasarı %{2} artırır. Oyuncularda aynı anda Paladin başına yalnızca bir Aura bulunabilir.",
   ["Increases maximum health of all party and raid members within {1} yards by {2}. Lasts {3} min."] = "{1} yard içindeki tüm grup ve akın üyelerinin azami canını {2} artırır. {3} dk sürer.",
   ["Increases melee attack power by {1} and your spell damage by {2}. Lasts {3} sec."] = "Yakın dövüş saldırı gücünü {1}, büyü hasarını {2} artırır. {3} sn sürer.",
   ["Increases melee, ranged, and spell casting speed by {1}% for all party and raid members. Lasts {2} sec. After the completion of this effect, those affected will become Exhausted and unable to benefit from Heroism again for {3} min."] = "Tüm grup ve akın üyeleri için yakın dövüş, menzilli ve büyü yapma hızını %{1} artırır. {2} sn sürer. Bu etki tamamlandıktan sonra, etkilenenler Exhausted olur ve {3} dk boyunca tekrar Heroism'den yararlanamaz.",
   ["Increases melee, ranged, and spell casting speed by {1}% for all party and raid members. Lasts {2} sec. After the completion of this effect, those affected will become Sated and unable to benefit from Bloodlust again for {3} min."] = "Tüm grup ve akın üyeleri için yakın dövüş, menzilli ve büyü yapma hızını %{1} artırır. {2} sn sürer. Bu etki tamamlandıktan sonra, etkilenenler Sated olur ve {3} dk boyunca tekrar Bloodlust'tan yararlanamaz.",
   ["Increases movement and mounted movement speed by {1}%. This does not stack with other movement speed increasing effects."] = "Hareket ve binekli hareket hızını %{1} artırır. Bu, diğer hareket hızı artıran etkilerle üst üste birikmez.",
   ["Increases movement speed by {1}% while in Cat Form for {2} sec. Does not break prowling."] = "Cat Form'dayken hareket hızını {2} sn boyunca %{1} artırır. Prowl'u bozmaz.",
   ["Increases ranged attack speed by {1}% for {2} sec."] = "Menzilli saldırı hızını {2} sn boyunca %{1} artırır.",
   ["Increases spell critical chance by {1}%."] = "Büyü kritik vurma şansını %{1} artırır.",
   ["Increases spell damage and healing by up to {1}% of your total Spirit."] = "Büyü hasarını ve iyileştirmeyi toplam Ruhunun %{1} kadarına kadar artırır.",
   ["Increases swimming speed by {1}% and allow's the druid to breathe underwater."] = "Yüzme hızını %{1} artırır ve druidin su altında nefes almasını sağlar.",
   ["Increases the amount healed by your healing spells by {1}%."] = "İyileştirme büyülerinin iyileştirdiği miktarı %{1} artırır.",
   ["Increases the amount healed by your Holy Light and Flash of Light spells by {1}%."] = "Holy Light ve Flash of Light büyülerinin iyileştirdiği miktarı %{1} artırır.",
   ["Increases the amount healed by your Renew spell by {1}%."] = "Renew büyünün iyileştirdiği miktarı %{1} artırır.",
   ["Increases the amount of damage absorbed by your shield by {1}%."] = "Kalkanının emdiği hasar miktarını %{1} artırır.",
   ["Increases the amount of damage absorbed by your Spellstone by {1}%."] = "Spellstone'unun emdiği hasar miktarını %{1} artırır.",
   ["Increases the amount of damage reduced by your Stoneskin Totem and Windwall Totem by {1}% and reduces the cooldown of your Grounding Totem by {2} sec."] = "Stoneskin Totem ve Windwall Totem'inin azalttığı hasar miktarını %{1} artırır ve Grounding Totem'inin bekleme süresini {2} sn azaltır.",
   ["Increases the amount of Health restored by your Healthstone by {1}%."] = "Healthstone'unun yenilediği Can miktarını %{1} artırır.",
   ["Increases the amount of Health transferred by your Health Funnel spell by {1}%."] = "Health Funnel büyünün aktardığı Can miktarını %{1} artırır.",
   ["Increases the amount of Mana awarded by your Life Tap spell by {1}%."] = "Life Tap büyünün verdiği Mana miktarını %{1} artırır.",
   ["Increases the amount of rage generated by your Charge ability by {1}."] = "Charge yeteneğinin ürettiği rage miktarını {1} artırır.",
   ["Increases the amount of threat generated by your Righteous Fury spell by {1}%."] = "Righteous Fury büyünün oluşturduğu tehdit miktarını %{1} artırır.",
   ["Increases the area of effect and duration of your Battle Shout and Demoralizing Shout by {1}%."] = "Battle Shout ve Demoralizing Shout'unun etki alanını ve süresini %{1} artırır.",
   ["Increases the armor and resistances given by your Frost Armor and Ice Armor spells by {1}%. In addition, gives your Frost Ward a {2}% chance to reflect Frost spells and effects while active."] = "Frost Armor ve Ice Armor büyülerinin verdiği zırhı ve dirençleri %{1} artırır. Ayrıca Frost Ward'ına, aktifken Buz büyülerini ve etkilerini yansıtma şansını %{2} verir.",
   ["Increases the armor bonus of your Devotion Aura by {1}%."] = "Devotion Aura'nın zırh bonusunu %{1} artırır.",
   ["Increases the Armor bonus of your Inner Fire spell by {1}%."] = "Inner Fire büyünün Zırh bonusunu %{1} artırır.",
   ["Increases the Armor rating of your pets by {1}%."] = "Evcil hayvanlarının Zırh derecesini %{1} artırır.",
   ["Increases the armor reduced by your Expose Armor ability by {1}%."] = "Expose Armor yeteneğinin azalttığı zırhı %{1} artırır.",
   ["Increases the attack power of party members within {1} yards by {2}. Lasts {3} min."] = "{1} metre içindeki grup üyelerinin saldırı gücünü {2} artırır. {3} dk sürer.",
   ["Increases the Attack Power reduction of your Demoralizing Roar by {1}% and the damage caused by your Ferocious Bite by {2}%."] = "Demoralizing Roar'ının Saldırı Gücü azaltmasını %{1} ve Ferocious Bite'ının verdiği hasarı %{2} artırır.",
   ["Increases the bleed damage done by your Rend ability by {1}%."] = "Rend yeteneğinin verdiği kanama hasarını %{1} artırır.",
   ["Increases the bonus damage done by your Cleave ability by {1}%."] = "Cleave yeteneğinin verdiği bonus hasarı %{1} artırır.",
   ["Increases the bonus Fire damage from Firestones and the Firestone effect by {1}%."] = "Firestone'lardan ve Firestone etkisinden gelen bonus Ateş hasarını %{1} artırır.",
