   ["Increases your attack speed by {1}%. In addition, attacks strike an additional nearby opponent. Lasts {2} sec."] = "Saldırı hızını %{1} artırır. Buna ek olarak, saldırılar yakındaki ek bir rakibe de vurur. {2} sn sürer.",
   ["Increases your chance to block and block value by {1}% for {2} sec."] = "Engelleme şansınızı ve engelleme değerinizi {2} sn boyunca %{1} artırır.",
   ["Increases your chance to block attacks with a shield by {1}% and has a {2}% chance to generate {3} rage when a block occurs."] = "Kalkanla saldırıları bloklama şansını %{1} artırır ve bir bloklama gerçekleştiğinde %{2} ihtimalle {3} rage üretir.",
   ["Increases your chance to block attacks with a shield by {1}% and increases the amount blocked by {2}%."] = "Kalkanla saldırıları bloklama şansını %{1} artırır ve bloklanan miktarı %{2} artırır.",
   ["Increases your chance to block attacks with your shield by {1}% after being the victim of a critical strike. Lasts {2} sec or {3} blocks."] = "Bir kritik vurmanın kurbanı olduktan sonra kalkanınla saldırıları bloklama şansını %{1} artırır. {2} sn veya {3} bloklama sürer.",
   ["Increases your chance to dodge by an additional {1}%."] = "Sıyırma şansını ek olarak %{1} artırır.",
   ["Increases your chance to get a critical strike with Axes by {1}%."] = "Baltalarla kritik vurma yapma şansını %{1} artırır.",
   ["Increases your chance to get a critical strike with Daggers by {1}%."] = "Hançerlerle kritik vurma yapma şansını %{1} artırır.",
   ["Increases your chance to get a critical strike with Fist Weapons by {1}%."] = "Yumruk Silahlarıyla kritik vurma yapma şansını %{1} artırır.",
   ["Increases your chance to get a critical strike with melee weapons by {1}%."] = "Yakın dövüş silahlarıyla kritik vurma yapma şansını %{1} artırır.",
   ["Increases your chance to get a critical strike with Polearms by {1}%."] = "Kargılarla kritik vurma yapma şansını %{1} artırır.",
   ["Increases your chance to hit with melee attacks and spells by {1}%."] = "Yakın dövüş saldırıları ve büyülerle vurma şansını %{1} artırır.",
   ["Increases your chance to hit with melee weapons by {1}%."] = "Yakın dövüş silahlarıyla vurma şansını %{1} artırır.",
   ["Increases your chance to resist Fear and Disorient effects by an additional {1}%."] = "Fear ve Disorient etkilerine direnme şansını ek olarak %{1} artırır.",
   ["Increases your chance to resist Stun and Charm effects by an additional {1}%."] = "Stun ve Charm etkilerine direnme şansını ek olarak %{1} artırır.",
   ["Increases your chance to resist Stun, Fear, and Silence effects by an additional {1}%."] = "Stun, Fear ve Silence etkilerine direnme şansını ek olarak %{1} artırır.",
   ["Increases your critical strike chance by {1}%."] = "Kritik vurma şansını %{1} artırır.",
   ["Increases your critical strike chance while in Bear, Dire Bear or Cat Form by {1}%."] = "Bear, Dire Bear veya Cat Form'dayken kritik vurma şansını %{1} artırır.",
   ["Increases your critical strike chance with all attacks by {1}%."] = "Tüm saldırılarla kritik vurma şansını %{1} artırır.",
   ["Increases your critical strike chance with ranged weapons by {1}%."] = "Menzilli silahlarla kritik vurma şansını %{1} artırır.",
   ["Increases your critical strike chance with spells and gives you a chance when hit by a physical attack to reduce the cast time of your next Shadow Bolt or Incinerate spells."] = "Büyülerle kritik vurma şansınızı artırır ve fiziksel bir saldırıyla vurulduğunuzda sonraki Shadow Bolt veya Incinerate büyülerinizin okuma süresini azaltma şansı verir.",
   ["Increases your damage with Wands by {1}%."] = "Wand'larla verdiğin hasarı %{1} artırır.",
   ["Increases your Defense skill by {1}."] = "Defense becerini {1} artırır.",
   ["Increases your Dodge chance by {1}%."] = "Sıyırma şansını %{1} artırır.",
   ["Increases your Energy regeneration rate by {1}% for {2} sec."] = "{2} sn boyunca Enerji yenilenme hızını %{1} artırır.",
   ["Increases your Intellect by {1}%. In addition, while in Bear or Dire Bear Form your Stamina is increased by {2}% and while in Cat Form your Strength is increased by {3}%."] = "Zekanı %{1} artırır. Buna ek olarak, Bear veya Dire Bear Form'dayken Dayanıklılığın %{2} ve Cat Form'dayken Gücün %{3} artar.",
   ["Increases your maximum Energy by {1}."] = "Maksimum Enerjini {1} artırır.",
   ["Increases your maximum Mana by {1}%."] = "Maksimum Manani %{1} artırır.",
   ["Increases your melee attack power in Cat, Bear and Dire Bear Forms by {1}% of your level."] = "Cat, Bear ve Dire Bear Form'larında yakın dövüş saldırı gücünü seviyenin %{1}'i kadar artırır.",
   ["Increases your movement speed by {1}% while outdoors in Cat Form and increases your chance to dodge while in Cat Form by {2}%."] = "Cat Form'dayken açık alanda hareket hızını %{1} artırır ve Cat Form'dayken sıyırma şansını %{2} artırır.",
   ["Increases your Parry chance by {1}%."] = "Savuşturma şansını %{1} artırır.",
   ["Increases your Parry Rating by {1}% of your total Strength."] = "Savuşturma derecenizi toplam Strength'inizin %{1}'i kadar artırır.",
   ["Increases your ranged weapon critical strike damage bonus by {1}%."] = "Menzilli silah kritik vurma hasar bonusunu %{1} artırır.",
   ["Increases your resistance to all magic by {1} and allows {2}% of your mana regeneration to continue while casting. In addition, the duration of all harmful Magic effects used against you is reduced by {3}%. Only one type of Armor spell can be active on the Mage at any time. Lasts {4} min."] = "Tüm büyülere karşı direncinizi {1} artırır ve mana yenilenmenizin %{2}'sinin büyü yaparken devam etmesini sağlar. Ayrıca, size karşı kullanılan tüm zararlı büyü etkilerinin süresi %{3} azalır. Mage üzerinde aynı anda yalnızca bir tür Armor büyüsü etkin olabilir. {4} dk sürer.",
   ["Increases your resistance to all magic by {1} and allows {2}% of your mana regeneration to continue while casting. Only one type of Armor spell can be active on the Mage at any time. Lasts {3} min."] = "Tüm büyülere karşı direncinizi {1} artırır ve mana yenilenmenizin %{2}'sinin büyü yaparken devam etmesini sağlar. Mage üzerinde aynı anda yalnızca bir tür Armor büyüsü etkin olabilir. {3} dk sürer.",
   ["Increases your Shadow spell damage by {1}%."] = "Gölge büyü hasarını %{1} artırır.",
   ["Increases your skill with Maces by {1}, and gives you a {2}% chance to stun your target for {3} sec with a mace."] = "Topuzlarla becerini {1} artırır ve bir topuzla hedefini {3} sn sersemletme şansı %{2} verir.",
   ["Increases your skill with Sword, Fist and Dagger weapons by {1}."] = "Kılıç, Yumruk ve Hançer silahlarıyla becerini {1} artırır.",
   ["Increases your speed while stealthed by {1}% and reduces the cooldown of your Stealth ability by {2} sec."] = "Gizlenmişken hızını %{1} artırır ve Stealth yeteneğinin bekleme süresini {2} sn azaltır.",
   ["Increases your spell critical damage bonus with all spells but your spell criticals cost additional mana."] = "Tüm büyülerle büyü kritik hasar bonusunuzu artırır ancak büyü kritikleriniz ek mana harcar.",
   ["Increases your spell damage and critical strike chance by {1}%."] = "Büyü hasarını ve kritik vurma şansını %{1} artırır.",
   ["Increases your spell damage by {1}% and the critical strike chance of your offensive spells by {2}%."] = "Büyü hasarını %{1} ve saldırı büyülerinin kritik vurma şansını %{2} artırır.",
   ["Increases your spell power by {1}. Lasts {2} sec."] = "Büyü gücünüzü {1} artırır. {2} sn sürer.",
   ["Increases your Stealth detection and reduces the chance you are hit by spells and ranged attacks by {1}%."] = "Stealth tespitini artırır ve büyüler ve menzilli saldırılar tarafından vurulma şansını %{1} azaltır.",
   ["Increases your Stealth detection and reduces the chance you are hit by spells and ranged attacks by {1}%. More effective than Heightened Senses (Rank {2})."] = "Stealth tespitini artırır ve büyüler ve menzilli saldırılar tarafından vurulma şansını %{1} azaltır. Heightened Senses'tan (Seviye {2}) daha etkilidir.",
   ["Increases your Stealth detection."] = "Stealth tespit etme yeteneğinizi artırır.",
   ["Increases your Strength by {1}%."] = "Gücünü %{1} artırır.",
   ["Increases your target's armor by {1}% for {2} sec after getting a critical effect from your Flash Heal, Heal, Greater Heal, or Prayer of Healing spell."] = "Flash Heal, Heal, Greater Heal veya Prayer of Healing büyünden kritik etki aldıktan sonra hedefinin zırhını {2} sn boyunca %{1} artırır.",
   ["Increases your target's armor value by {1}% for {2} sec after getting a critical effect from one of your healing spells."] = "İyileştirme büyülerinden birinden kritik etki aldıktan sonra hedefinin zırh değerini {2} sn boyunca %{1} artırır.",
   ["Increases your total Intellect by {1}%."] = "Toplam Intellect değerini %{1} artırır.",
   ["Increases your total Spirit by {1}% and increases your spell haste by {2}%."] = "Toplam Spirit değerinizi %{1} ve büyü hızınızı %{2} artırır.",
   ["Increases your total Stamina by {1}% but reduces your total Spirit by {2}%."] = "Toplam Stamina değerini %{1} artırır ama toplam Spirit değerini %{2} azaltır.",
   ["Inflict searing pain on the enemy target, causing {1} to {2} Fire damage. Causes a high amount of threat."] = "Düşman hedefi yakıcı bir acıyla kavurarak {1} ila {2} Ateş hasarı verir. Yüksek miktarda tehdit oluşturur.",
   ["Infuses all party and raid members with brilliance, increasing their Intellect by {1} for {2} hour."] = "Tüm grup ve akın üyelerine parlaklık aşılayarak Intellect'lerini {2} saat boyunca {1} artırır.",
   ["Infuses the death knight with unholy fury, increasing attack speed by {1}%, movement speed by {2}% and reducing the global cooldown on all abilities by {3}.{4} sec. Only one Presence may be active at a time."] = "Death knight'a kutsal olmayan öfke aşılayarak saldırı hızını %{1}, hareket hızını %{2} artırır ve tüm yeteneklerdeki global bekleme süresini {3}.{4} sn azaltır. Aynı anda yalnızca bir Presence etkin olabilir.",
   ["Infuses the target with power, increasing their spell damage and healing by {1}%. Lasts {2} sec."] = "Hedefe güç aşılayarak büyü hasarını ve iyileştirmesini %{1} artırır. {2} sn sürer.",
   ["Instantly attack the target causing damage equal to {1}% of your attack power. In addition, the next {2} successful melee attacks will restore {3} health. This effect lasts {4} sec."] = "Hedefe anında saldırarak saldırı gücünün %{1} kadar hasar verir. Buna ek olarak, sonraki {2} başarılı yakın dövüş saldırısı {3} can yeniler. Bu etki {4} sn sürer.",
   ["Instantly attack the target causing {1} damage. Can only be used within {2} sec after you kill an enemy that yields experience or honor. Damage is based on your attack power."] = "Hedefe anında saldırarak {1} hasar verir. Yalnızca deneyim veya onur kazandıran bir düşmanı öldürdükten sonraki {2} sn içinde kullanılabilir. Hasar saldırı gücünüze bağlıdır.",
   ["Instantly attack the target causing {1} damage. In addition, the next {2} successful melee attacks will restore {3}% of max health. This effect lasts {4} sec. Damage is based on your attack power."] = "Hedefe anında saldırarak {1} hasar verir. Ayrıca, sonraki {2} başarılı yakın dövüş saldırısı azami canın %{3}'ünü geri kazandırır. Bu etki {4} sn sürer. Hasar saldırı gücünüze bağlıdır.",
   ["Instantly attack with both weapons. In addition, the next {1} sources of Nature damage dealt to the target are increased by {2}%. Lasts {3} sec."] = "Her iki silahla anında saldırır. Ayrıca, hedefe verilen sonraki {1} Doğa hasarı kaynağı %{2} artar. {3} sn sürer.",
   ["Instantly blasts the target for {1} to {2} Shadow damage. If the target dies within {3} sec of Shadowburn, and yields experience or honor, the caster gains a Soul Shard."] = "Hedefe anında {1} ila {2} Gölge hasarı patlatır. Hedef, Shadowburn sonrası {3} sn içinde ölürse ve deneyim ya da onur veriyorsa, büyüyü yapan bir Soul Shard kazanır.",
   ["Instantly blasts the target with a gust of wind, causing no damage but interrupting spellcasting and preventing any spell in that school from being cast for {1} sec. Also lowers your threat, making the enemy less likely to attack you."] = "Hedefi anında bir rüzgâr darbesiyle vurur; hasar vermez ancak büyü yapmayı kesintiye uğratır ve o okuldaki herhangi bir büyünün {1} sn boyunca yapılmasını engeller. Ayrıca tehdidinizi azaltarak düşmanın size saldırma olasılığını düşürür.",
   ["Instantly counterattack an enemy for {1} to {2} damage. Revenge is only usable after the warrior blocks, dodges or parries an attack."] = "Bir düşmana anında karşı saldırı yaparak {1} ila {2} hasar verir. Revenge yalnızca warrior bir saldırıyı engelledikten, sıyırdıktan veya savuşturduktan sonra kullanılabilir.",
   ["Instantly counterattack any enemy that strikes you in melee for {1} sec. Melee attacks made from behind cannot be counterattacked. A maximum of {2} attacks will cause retaliation."] = "{1} sn boyunca size yakın dövüşte vuran herhangi bir düşmana anında karşı saldırı yapar. Arkadan yapılan yakın dövüş saldırılarına karşı saldırı yapılamaz. En fazla {2} saldırı misillemeye yol açar.",
   ["Instantly overpower the enemy, causing weapon damage. Only useable after the target dodges. The Overpower cannot be blocked, dodged or parried."] = "Düşmanı anında alt ederek silah hasarı verir. Yalnızca hedef sıyırdıktan sonra kullanılabilir. Overpower engellenemez, sıyrılamaz veya savuşturulamaz.",
   ["Instantly removes all existing harmful spell effects and increases your chance to resist all spells by {1}% for {2} sec. Does not remove effects that prevent you from using Cloak of Shadows."] = "Mevcut tüm zararlı büyü etkilerini anında kaldırır ve tüm büyülere direnme şansınızı {2} sn boyunca %{1} artırır. Cloak of Shadows kullanmanızı engelleyen etkileri kaldırmaz.",
   ["Instantly sears the target with fire, causing {1} Fire damage immediately and {2} Fire damage over {3} sec. This periodic damage may critically strike and will occur more rapidly based on the caster's spell haste."] = "Hedefi anında ateşle kavurur; anında {1} Ateş hasarı ve {3} sn boyunca {2} Ateş hasarı verir. Bu periyodik hasar kritik vurabilir ve büyücünün büyü hızına bağlı olarak daha hızlı gerçekleşir.",
   ["Instantly sears the target with fire, causing {1} Fire damage immediately and {2} Fire damage over {3}.{4} sec. This periodic damage may critically strike and will occur more rapidly based on the caster's spell haste."] = "Hedefi anında ateşle kavurur; anında {1} Ateş hasarı ve {3}.{4} sn boyunca {2} Ateş hasarı verir. Bu periyodik hasar kritik vurabilir ve büyücünün büyü hızına bağlı olarak daha hızlı gerçekleşir.",
   ["Instantly shields you, absorbing {1} damage. Lasts {2} min. While the shield holds, spells will not be interrupted."] = "Seni anında kalkanla koruyarak {1} hasar emer. {2} dk sürer. Kalkan dayandığı sürece büyüler kesintiye uğramaz.",
   ["Instantly shocks the target with concussive force, causing {1} to {2} Nature damage and reducing melee attack speed by {3}% for {4} sec."] = "Hedefi anında sarsıcı bir kuvvetle şoklayarak {1} ila {2} Doğa hasarı verir ve yakın dövüş saldırı hızını {4} sn boyunca %{3} azaltır.",
   ["Instantly shocks the target with frost, causing {1} to {2} Frost damage and slowing movement speed by {3}%. Lasts {4} sec. Causes a high amount of threat."] = "Hedefi anında buzla şoklayarak {1} ila {2} Buz hasarı verir ve hareket hızını %{3} yavaşlatır. {4} sn sürer. Yüksek miktarda tehdit oluşturur.",
   ["Instantly strike the enemy, causing {1}% weapon damage plus {2}, total damage increased by {3}.{4}% for each of your diseases on the target."] = "Düşmana anında vurarak %{1} silah hasarı artı {2} verir; hedefteki her hastalığınız için toplam hasar %{3}.{4} artar.",
   ["Instantly strike the target and his nearest ally, causing {1}% weapon damage plus {2} on the primary target, and {3}% weapon damage plus {4} on the secondary target. Each target takes {5}% additional damage for each of your diseases active on that target."] = "Hedefe ve onun en yakınındaki müttefiğe anında vurur; birincil hedefe %{1} silah hasarı artı {2}, ikincil hedefe %{3} silah hasarı artı {4} verir. Her hedef, üzerindeki her aktif hastalığın için %{5} ek hasar alır.",
   ["Instantly throw both weapons at all targets within {1} yards, causing {2}% weapon damage with daggers, and {3}% weapon damage with all other weapons."] = "Her iki silahı {1} yard içindeki tüm hedeflere anında fırlatır; hançerlerle %{2} silah hasarı, diğer tüm silahlarla %{3} silah hasarı verir.",
   ["Lacerates the enemy target, dealing {1} damage and making them bleed for {2} damage over {3} sec and causing a high amount of threat. Damage increased by attack power. This effect stacks up to {4} times on the same target."] = "Düşman hedefi parçalayarak {1} hasar verir ve {3} sn boyunca {2} hasarla kanatır; yüksek miktarda tehdit oluşturur. Hasar saldırı gücüyle artar. Bu etki aynı hedefte {4} kata kadar birikir.",
   ["Launches a bolt of frost at the enemy, causing {1} to {2} Frost damage and slowing movement speed by {3}% for {4} sec."] = "Düşmana bir buz oku fırlatarak {1} ila {2} Buz hasarı verir ve hareket hızını {4} sn boyunca %{3} yavaşlatır.",
   ["Launches a bolt of frostfire at the enemy, causing {1} to {2} Frostfire damage, slowing movement speed by {3}% and causing an additional {4} Frostfire damage over {5} sec. This spell will be checked against the lower of the target's Frost and Fire resists."] = "Düşmana bir buzateş oku fırlatarak {1} ila {2} Buzateş hasarı verir, hareket hızını %{3} yavaşlatır ve {5} sn boyunca ek {4} Buzateş hasarı verir. Bu büyü, hedefin Buz ve Ateş dirençlerinden düşük olanına karşı kontrol edilir.",
   ["Launches Arcane Missiles at the enemy, causing {1} Arcane damage every {2} sec for {3} sec."] = "Düşmana Arcane Missiles fırlatarak {3} sn boyunca her {2} sn'de {1} Arcane hasarı verir.",
   ["Launches Arcane Missiles at the enemy, causing {1} Arcane damage every {2}.{3} sec for {4}.{5} sec."] = "Düşmana Arcane Missiles fırlatarak {4}.{5} sn boyunca her {2}.{3} sn'de {1} Arcane hasarı verir.",
   ["Maims the enemy, reducing movement speed by {1}% for {2} sec."] = "Düşmanı sakatlayarak hareket hızını {2} sn boyunca %{1} azaltır.",
   ["Maims the enemy, reducing the target's movement speed by {1}% for {2} sec."] = "Düşmanı sakatlayarak hedefin hareket hızını {2} sn boyunca %{1} azaltır.",
   ["Mangle the target for {1}% normal damage plus {2} and causes the target to take {3}% additional damage from bleed effects for {4} min."] = "Hedefi paralayarak %{1} normal hasar artı {2} verir ve {4} dk boyunca hedefin kanama etkilerinden %{3} ek hasar almasına neden olur.",
   ["Mangle the target for {1}% normal damage plus {2} and causes the target to take {3}% additional damage from bleed effects for {4} min. Awards {5} combo point."] = "Hedefi paralayarak %{1} normal hasar artı {2} verir ve {4} dk boyunca hedefin kanama etkilerinden %{3} ek hasar almasına neden olur. {5} combo puanı kazandırır.",
   ["Opens a gate which the Death Knight can use to return to Ebon Hold."] = "Death Knight'ın Ebon Hold'a dönmek için kullanabileceği bir geçit açar.",
   ["Performs a feint, causing no damage but lowering your threat by a large amount, making the enemy less likely to attack you."] = "Bir çalım yapar; hasar vermez ancak tehdidinizi büyük ölçüde azaltarak düşmanın size saldırma olasılığını düşürür.",
   ["Performs a feint, causing no damage but lowering your threat by a large amount, making the enemy less likely to attack you. In addition, reduces the damage you take from area of effect attacks by {1}% for {2} sec."] = "Bir çalım yapar; hasar vermez ancak tehdidinizi büyük ölçüde azaltarak düşmanın size saldırma olasılığını düşürür. Ayrıca, alan etkili saldırılardan aldığınız hasarı {2} sn boyunca %{1} azaltır.",
   ["Performs a feint, causing no damage but lowering your threat by a medium amount, making the enemy less likely to attack you."] = "Bir çalım yapar; hasar vermez ancak tehdidinizi orta ölçüde azaltarak düşmanın size saldırma olasılığını düşürür.",
   ["Performs a feint, causing no damage but lowering your threat by a small amount, making the enemy less likely to attack you."] = "Bir çalım yapar; hasar vermez ancak tehdidinizi küçük ölçüde azaltarak düşmanın size saldırma olasılığını düşürür.",
   ["Performs an instant off-hand weapon attack that automatically applies the poison from your off-hand weapon to the target. Slower weapons require more Energy. Neither Shiv nor the poison it applies can be a critical strike. Awards {1} combo point."] = "Off-hand silahınızdaki zehri hedefe otomatik olarak uygulayan anında bir off-hand silah saldırısı yapar. Daha yavaş silahlar daha fazla enerji gerektirir. Ne Shiv ne de uyguladığı zehir kritik vuramaz. {1} combo puanı kazandırır.",
   ["Pick the target's pocket."] = "Hedefin cebini karıştırır.",
   ["Place a fire trap that explodes when an enemy approaches, causing {1} to {2} Fire damage and burning all enemies for {3} additional Fire damage over {4} sec to all within {5} yards. Trap will exist for {6} sec. Only one trap can be active at a time."] = "Bir düşman yaklaştığında patlayan bir ateş tuzağı yerleştirir; {5} yard içindeki herkese {1} ila {2} Ateş hasarı verir ve tüm düşmanları {4} sn boyunca {3} ek Ateş hasarıyla yakar. Tuzak {6} sn boyunca var olur. Aynı anda yalnızca bir tuzak etkin olabilir.",
   ["Place a fire trap that will burn the first enemy to approach for {1} Fire damage over {2} sec. Trap will exist for {3} sec. Only one trap can be active at a time."] = "Yaklaşan ilk düşmanı {2} sn boyunca {1} Ateş hasarıyla yakacak bir ateş tuzağı yerleştirir. Tuzak {3} sn boyunca var olur. Aynı anda yalnızca bir tuzak etkin olabilir.",
   ["Place a frost trap that creates an ice slick around itself for {1} sec when the first enemy approaches it. All enemies within {2} yards will be slowed by {3}% while in the area of effect. Trap will exist for {4} sec. Only one trap can be active at a time."] = "İlk düşman yaklaştığında çevresinde {1} sn boyunca buzdan kaygan bir alan oluşturan bir buz tuzağı yerleştirir. Etki alanındaki {2} yard içindeki tüm düşmanlar %{3} yavaşlatılır. Tuzak {4} sn boyunca var olur. Aynı anda yalnızca bir tuzak etkin olabilir.",
   ["Place a frost trap that freezes the first enemy that approaches, preventing all action for up to {1} sec. Any damage caused will break the ice. Trap will exist for {2} sec. Only one trap can be active at a time."] = "Yaklaşan ilk düşmanı donduran ve {1} sn'ye kadar tüm eylemleri engelleyen bir buz tuzağı yerleştirir. Verilen herhangi bir hasar buzu kırar. Tuzak {2} sn boyunca var olur. Aynı anda yalnızca bir tuzak etkin olabilir.",
   ["Place a trap that will release several venomous snakes to attack the first enemy to approach. The snakes will die after {1} sec. Trap will exist for {2} sec. Only one trap can be active at a time."] = "Yaklaşan ilk düşmana saldırmak üzere birkaç zehirli yılan salacak bir tuzak yerleştirir. Yılanlar {1} sn sonra ölür. Tuzak {2} sn boyunca var olur. Aynı anda yalnızca bir tuzak etkin olabilir.",
   ["Places a Blessing on the friendly target, increasing attack power by {1} for {2} min. Players may only have one Blessing on them per Paladin at any one time."] = "Dost hedefe bir Blessing yerleştirerek saldırı gücünü {2} dk boyunca {1} artırır. Oyuncuların üzerinde her Paladin başına aynı anda yalnızca bir Blessing bulunabilir.",
   ["Places a Blessing on the friendly target, increasing total stats by {1}% for {2} min. Players may only have one Blessing on them per Paladin at any one time."] = "Dost hedefe bir Blessing yerleştirir ve toplam özelliklerini {2} dk boyunca %{1} artırır. Oyuncular herhangi bir anda her Paladin'den yalnızca bir Blessing taşıyabilir.",
   ["Places a Blessing on the friendly target, reducing damage dealt from all sources by up to {1} for {2} min. In addition, when the target blocks a melee attack the attacker will take {3} Holy damage. Players may only have one Blessing on them per Paladin at any one time."] = "Dost hedefe bir Blessing yerleştirir ve tüm kaynaklardan gelen hasarı {2} dk boyunca en fazla {1} azaltır. Buna ek olarak, hedef bir yakın dövüş saldırısını bloklarsa saldıran {3} Kutsal hasar alır. Oyuncular herhangi bir anda her Paladin'den yalnızca bir Blessing taşıyabilir.",
   ["Places a Blessing on the friendly target, restoring {1} mana every {2} seconds for {3} min. Players may only have one Blessing on them per Paladin at any one time."] = "Dost hedefe bir Blessing yerleştirerek {3} dk boyunca her {2} sn'de {1} mana geri kazandırır. Oyuncuların üzerinde her Paladin başına aynı anda yalnızca bir Blessing bulunabilir.",
   ["Places a Hand on the friendly target, granting immunity to movement impairing effects for {1} sec. Players may only have one Hand on them per Paladin at any one time."] = "Dost hedefe bir Hand yerleştirerek {1} sn boyunca hareket engelleyici etkilere bağışıklık kazandırır. Oyuncuların üzerinde her Paladin başına aynı anda yalnızca bir Hand bulunabilir.",
   ["Places a Hand on the party or raid member, reducing their total threat by {1}% every {2} sec. for {3} sec. Players may only have one Hand on them per Paladin at any one time."] = "Grup veya akın üyesine bir Hand yerleştirerek {3} sn boyunca her {2} sn'de toplam tehditlerini %{1} azaltır. Oyuncuların üzerinde her Paladin başına aynı anda yalnızca bir Hand bulunabilir.",
   ["Places a Hand on the party or raid member, transfering {1}% damage taken to the caster. Lasts {2} sec or until the caster has transfered {3}% of their maximum health. Players may only have one Hand on them per Paladin at any one time."] = "Grup veya akın üyesine bir Hand yerleştirerek alınan hasarın %{1}'ini büyücüye aktarır. {2} sn boyunca veya büyücü azami canının %{3}'ünü aktarana kadar sürer. Oyuncuların üzerinde her Paladin başına aynı anda yalnızca bir Hand bulunabilir.",
   ["Places a large, stationary Anti-Magic Zone that reduces spell damage done to party or raid members inside it by {1}%. The Anti-Magic Zone lasts for {2} sec or until it absorbs {3} spell damage."] = "İçindeki grup veya akın üyelerine verilen büyü hasarını %{1} azaltan büyük, sabit bir Anti-Magic Zone yerleştirir. Anti-Magic Zone {2} sn boyunca veya {3} büyü hasarı emene kadar sürer.",
   ["Places a spell on the target that heals them for {1} the next time they take damage. When the heal occurs, Prayer of Mending jumps to a party or raid member within {2} yards. Jumps up to {3} times and lasts {4} sec after each jump. This spell can only be placed on one target at a time."] = "Hedefe, bir sonraki hasar aldıklarında onları {1} iyileştiren bir büyü yerleştirir. İyileştirme gerçekleştiğinde, Prayer of Mending {2} yard içindeki bir grup veya akın üyesine sıçrar. {3} kata kadar sıçrar ve her sıçramadan sonra {4} sn sürer. Bu büyü aynı anda yalnızca bir hedefe yerleştirilebilir.",
   ["Places the Hunter's Mark on the target, increasing the ranged attack power of all attackers against that target by {1}. In addition, the target of this ability can always be seen by the hunter whether it stealths or turns invisible. The target also appears on the mini-map. Lasts for {2} min."] = "Hedefe Hunter's Mark yerleştirerek o hedefe karşı tüm saldıranların menzilli saldırı gücünü {1} artırır. Ayrıca, bu yeteneğin hedefi gizlense veya görünmez olsa bile hunter tarafından her zaman görülebilir. Hedef ayrıca mini haritada görünür. {2} dk sürer.",
   ["Pounce, stunning the target for {1} sec and causing {2} damage over {3} sec. Must be prowling. Awards {4} combo point."] = "Üzerine atlayarak hedefi {1} sn boyunca sersemletir ve {3} sn boyunca {2} hasar verir. Prowl halinde olmalısınız. {4} combo puanı kazandırır.",
   ["Power infuses all party and raid members, increasing their Stamina by {1} for {2} hour."] = "Tüm grup ve akın üyelerine güç aşılayarak Stamina'larını {2} saat boyunca {1} artırır.",
   ["Power infuses the target increasing their Stamina by {1} for {2} min."] = "Hedefe güç aşılayarak Stamina'sını {2} dk boyunca {1} artırır.",
   ["Power infuses the target's party and raid members, increasing their Shadow resistance by {1} for {2} min."] = "Hedefin grup ve akın üyelerine güç aşılayarak Gölge dirençlerini {2} dk boyunca {1} artırır.",
   ["Power infuses the target's party and raid members, increasing their Spirit by {1} for {2} hour."] = "Hedefin grup ve akın üyelerine güç aşılayarak Spirit'lerini {2} saat boyunca {1} artırır.",
   ["Power infuses the target, increasing their Stamina by {1} for {2} min."] = "Hedefe güç aşılayarak Stamina'sını {2} dk boyunca {1} artırır.",
   ["Protects the caster, increasing armor by {1}, and increasing the amount of health generated through spells and effects by {2}%. Only one type of Armor spell can be active on the Warlock at any time. Lasts {3} min."] = "Büyücüyü korur, zırhı {1} artırır ve büyüler ve etkiler aracılığıyla üretilen can miktarını %{2} artırır. Warlock üzerinde aynı anda yalnızca bir tür Armor büyüsü etkin olabilir. {3} dk sürer.",
   ["Protects the paladin from all damage and spells for {1} sec, but reduces all damage you deal by {2}%. Once protected, the target cannot be targeted by Divine Shield, Divine Protection, or Hand of Protection again for {3} min. Cannot be used within {4} sec. of using Avenging Wrath."] = "Paladin'i {1} sn boyunca tüm hasar ve büyülerden korur, ancak verdiğiniz tüm hasarı %{2} azaltır. Bir kez korunduğunda, hedef {3} dk boyunca tekrar Divine Shield, Divine Protection veya Hand of Protection ile hedeflenemez. Avenging Wrath kullanıldıktan sonraki {4} sn içinde kullanılamaz.",
   ["Protects the target with an earthen shield, giving a chance of ignoring spell interruption when damaged and causing attacks to heal the shielded target. This effect can only occur once every few seconds. Limited charges. Earth Shield can only be placed on one target at a time and only one Elemental Shield can be active on a target at a time."] = "Hedefi topraktan bir kalkanla korur; hasar aldığında büyü kesintisini görmezden gelme şansı verir ve saldırıların kalkanlı hedefi iyileştirmesini sağlar. Bu etki yalnızca birkaç saniyede bir gerçekleşebilir. Sınırlı kullanım hakkı. Earth Shield aynı anda yalnızca bir hedefe yerleştirilebilir ve bir hedefte aynı anda yalnızca bir Elemental Shield etkin olabilir.",
   ["Pummel the target, interrupting spellcasting and preventing any spell in that school from being cast for {1} sec."] = "Hedefi yumruklayarak büyü yapmayı kesintiye uğratır ve o okuldaki herhangi bir büyünün {1} sn boyunca yapılmasını engeller.",
   ["Purges the enemy target, removing {1} beneficial magic effect."] = "Düşman hedefi arındırarak {1} yararlı büyü etkisini kaldırır.",
   ["Purifies the friendly target, removing {1} disease effect and {2} poison effect."] = "Dost hedefi arındırarak {1} hastalık etkisini ve {2} zehir etkisini kaldırır.",
   ["Puts the enemy target in a state of meditation, incapacitating them for up to {1} sec. Any damage caused will awaken the target. Only works against Humanoids."] = "Düşman hedefi meditasyon haline sokarak en fazla {1} sn etkisiz hale getirir. Verilen herhangi bir hasar hedefi uyandırır. Yalnızca Humanoid'lere karşı işe yarar.",
   ["Raise your shield, reflecting the next spell cast on you. Lasts {1} sec."] = "Kalkanınızı kaldırarak size yapılan bir sonraki büyüyü yansıtır. {1} sn sürer.",
   ["Raises a Ghoul to fight by your side. If no humanoid corpse that yields experience or honor is available, you must supply Corpse Dust to complete the spell. You can have a maximum of one Ghoul at a time. Lasts {1} min."] = "Yanında savaşması için bir Ghoul diriltir. Deneyim ya da onur veren bir humanoid ceset yoksa, büyüyü tamamlamak için Corpse Dust sağlamalısın. Aynı anda en fazla bir Ghoul'un olabilir. {1} dk sürer.",
   ["Rake the target for {1} bleed damage and an additional {2} damage over {3} sec. Awards {4} combo point."] = "Hedefi tırmalayarak {1} kanama hasarı ve {3} sn boyunca ek {2} hasar verir. {4} combo puanı kazandırır.",
   ["Ravage the target, causing {1}% damage plus {2} to the target. Must be prowling and behind the target. Awards {3} combo point."] = "Hedefi harap ederek hedefe %{1} hasar artı {2} verir. Prowl halinde ve hedefin arkasında olmalısınız. {3} combo puanı kazandırır.",
