   ["Reduces all damage taken by {1}% for {2} sec."] = "Alınan tüm hasarı {2} sn boyunca %{1} azaltır.",
   ["Reduces all damage taken by {1}% for {2} sec. Once protected, the target cannot be targeted by Divine Shield, Divine Protection, or Hand of Protection again for {3} min. Cannot be used within {4} sec of using Avenging Wrath."] = "Alınan tüm hasarı {2} sn boyunca %{1} azaltır. Bir kez korunduğunda, hedef {3} dk boyunca tekrar Divine Shield, Divine Protection veya Hand of Protection ile hedeflenemez. Avenging Wrath kullanıldıktan sonraki {4} sn içinde kullanılamaz.",
   ["Reduces all physical damage taken by {1}%."] = "Alınan tüm fiziksel hasarı %{1} azaltır.",
   ["Reduces all spell damage taken by {1}%."] = "Alınan tüm büyü hasarını %{1} azaltır.",
   ["Reduces damage from falling."] = "Düşmeden alınan hasarı azaltır.",
   ["Reduces damage taken from Fire, Frost and Nature effects by {1}%."] = "Ateş, Buz ve Doğa etkilerinden alınan hasarı %{1} azaltır.",
   ["Reduces physical damage taken by {1}%. Lasts {2} sec."] = "Alınan fiziksel hasarı %{1} azaltır. {2} sn sürer.",
   ["Reduces the Attack Speed and Casting Speed penalty of your Enslave Demon spell by {1}% and reduces the resist chance by {2}%."] = "Enslave Demon büyünün Saldırı Hızı ve Büyü Hızı cezasını %{1} azaltır ve direnç şansını %{2} azaltır.",
   ["Reduces the cast time of Starfire by {1}.{2} sec and has a {3}% chance to stun the target for {4} sec."] = "Starfire'ın okuma süresini {1}.{2} sn azaltır ve hedefi {4} sn sersemletme için %{3} şansa sahiptir.",
   ["Reduces the cast time of your Ghost Wolf spell by {1} sec."] = "Ghost Wolf büyünün okuma süresini {1} sn azaltır.",
   ["Reduces the cast time of your Healing Touch spell by {1}.{2} sec."] = "Healing Touch büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the cast time of your Lightning Bolt and Chain Lightning spells by {1} sec."] = "Lightning Bolt ve Chain Lightning büyülerinin okuma süresini {1} sn azaltır.",
   ["Reduces the cast time of your Lightning Bolt and Chain Lightning spells by {1}.{2} sec."] = "Lightning Bolt ve Chain Lightning büyülerinin okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the cast time of your Wrath spell by {1}.{2} sec."] = "Wrath büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Corruption spell by {1} sec."] = "Corruption büyünün okuma süresini {1} sn azaltır.",
   ["Reduces the casting time of your Corruption spell by {1}.{2} sec."] = "Corruption büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Fireball spell by {1}.{2} sec."] = "Fireball büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Frostbolt spell by {1}.{2} sec."] = "Frostbolt büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Healing Wave spell by {1}.{2} sec."] = "Healing Wave büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Imp's Firebolt spell by {1} sec."] = "Imp'in Firebolt büyüsünün okuma süresini {1} sn azaltır.",
   ["Reduces the casting time of your Imp's Firebolt spell by {1}.{2} sec."] = "Imp'in Firebolt büyüsünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Imp, Voidwalker, Succubus, and Felhunter Summoning spells by {1} sec and the Mana cost by {2}%."] = "Imp, Voidwalker, Succubus ve Felhunter Çağırma büyülerinin okuma süresini {1} sn ve Mana maliyetini %{2} azaltır.",
   ["Reduces the casting time of your Mana Burn spell by {1}.{2} sec."] = "Mana Burn büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Mana Burn spell by {1}.{2} secs."] = "Mana Burn büyünün okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the casting time of your Shadow Bolt and Immolate spells by {1}.{2} sec and your Soul Fire spell by {3} sec."] = "Shadow Bolt ve Immolate büyülerinin okuma süresini {1}.{2} sn ve Soul Fire büyünü {3} sn azaltır.",
   ["Reduces the casting time of your Shadow Bolt and Immolate spells by {1}.{2} sec and your Soul Fire spell by {3}.{4} sec."] = "Shadow Bolt ve Immolate büyülerinin okuma süresini {1}.{2} sn ve Soul Fire büyünü {3}.{4} sn azaltır.",
   ["Reduces the casting time of your Smite, Holy Fire, Heal and Greater Heal spells by {1}.{2} sec."] = "Smite, Holy Fire, Heal ve Greater Heal büyülerinin okuma süresini {1}.{2} sn azaltır.",
   ["Reduces the chance enemies have to detect you while in Stealth mode."] = "Stealth modundayken düşmanların seni fark etme şansını azaltır.",
   ["Reduces the chance enemies have to detect you while in Stealth mode. More effective than Master of Deception (Rank {1})."] = "Stealth modundayken düşmanların seni fark etme şansını azaltır. Master of Deception'dan (Seviye {1}) daha etkilidir.",
   ["Reduces the chance enemies have to detect you while Shadowmelded or Stealthed."] = "Shadowmeld veya Stealth halindeyken düşmanların sizi tespit etme şansını azaltır.",
   ["Reduces the chance for enemies to resist your Affliction spells by {1}%."] = "Düşmanların Affliction büyülerine direnme şansını %{1} azaltır.",
   ["Reduces the chance that the opponent can resist your Arcane spells by {1}%."] = "Rakibin Arcane büyülerine direnebilme şansını %{1} azaltır.",
   ["Reduces the chance that the opponent can resist your Frost and Fire spells by {1}%."] = "Rakibin Buz ve Ateş büyülerine direnebilme şansını %{1} azaltır.",
   ["Reduces the chance you are critically hit by melee and ranged attacks by {1}% and increases the threat reduction of your Feint ability by {2}%."] = "Yakın dövüş ve menzilli saldırılarla kritik vurulma şansını %{1} azaltır ve Feint yeteneğinin tehdit azaltmasını %{2} artırır.",
   ["Reduces the chance you will be hit by Shadow spells by {1}%."] = "Gölge büyüleriyle vurulma şansınızı %{1} azaltır.",
   ["Reduces the chance your Feign Death ability will be resisted by {1}%."] = "Feign Death yeteneğinin direnilme şansını %{1} azaltır.",
   ["Reduces the cooldown of your Arcane Shot by {1} sec."] = "Arcane Shot'ının bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Arcane Shot by {1}.{2} sec."] = "Arcane Shot'ının bekleme süresini {1}.{2} sn azaltır.",
   ["Reduces the cooldown of your Blessing of Protection by {1} sec and increases the duration of your Blessing of Freedom by {2} sec."] = "Blessing of Protection'ının bekleme süresini {1} sn azaltır ve Blessing of Freedom'ının süresini {2} sn artırır.",
   ["Reduces the cooldown of your Fire Blast spell by {1} sec."] = "Fire Blast büyünün bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Fire Blast spell by {1}.{2} sec."] = "Fire Blast büyünün bekleme süresini {1}.{2} sn azaltır.",
   ["Reduces the cooldown of your Frost Nova spell by {1} sec."] = "Frost Nova büyünün bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Intercept ability by {1} sec."] = "Intercept yeteneğinin bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Mind Blast spell by {1} sec."] = "Mind Blast büyünün bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Mind Blast spell by {1}.{2} sec."] = "Mind Blast büyünün bekleme süresini {1}.{2} sn azaltır.",
   ["Reduces the cooldown of your Psychic Scream spell by {1} sec."] = "Psychic Scream büyünün bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Reincarnation spell by {1} min and increases the amount of health and mana you reincarnate with by an additional {2}%."] = "Reincarnation büyünün bekleme süresini {1} dk azaltır ve yeniden doğduğunda sahip olduğun can ve mana miktarını ek %{2} artırır.",
   ["Reduces the cooldown of your Shock spells by {1} sec."] = "Shock büyülerinin bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Shock spells by {1}.{2} sec."] = "Shock büyülerinin bekleme süresini {1}.{2} sn azaltır.",
   ["Reduces the cooldown of your Sprint and Evasion abilities by {1} sec."] = "Sprint ve Evasion yeteneklerinin bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Sprint and Evasion abilities by {1}.{2} min."] = "Sprint ve Evasion yeteneklerinin bekleme süresini {1}.{2} dk azaltır.",
   ["Reduces the cooldown of your Succubus' Lash of Pain spell by {1} sec."] = "Succubus'un Lash of Pain büyüsünün bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Taunt ability by {1} sec."] = "Taunt yeteneğinin bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Vanish and Blind abilities by {1} sec."] = "Vanish ve Blind yeteneklerinin bekleme süresini {1} sn azaltır.",
   ["Reduces the cooldown of your Vanish and Blind abilities by {1}.{2} min."] = "Vanish ve Blind yeteneklerinin bekleme süresini {1}.{2} dk azaltır.",
   ["Reduces the cost of your Heroic Strike ability by {1} rage point."] = "Heroic Strike yeteneğinin maliyetini {1} rage puanı azaltır.",
   ["Reduces the cost of your Heroic Strike ability by {1} rage points."] = "Heroic Strike yeteneğinin maliyetini {1} rage puanı azaltır.",
   ["Reduces the cost of your Maul, Swipe, Claw, and Rake abilities by {1} Rage or Energy."] = "Maul, Swipe, Claw ve Rake yeteneklerinin maliyetini {1} Rage veya Energy azaltır.",
   ["Reduces the cost of your Sunder Armor ability by {1} rage point."] = "Sunder Armor yeteneğinin maliyetini {1} rage puanı azaltır.",
   ["Reduces the cost of your Sunder Armor ability by {1} rage points."] = "Sunder Armor yeteneğinin maliyetini {1} rage puanı azaltır.",
   ["Reduces the cost of your Thunder Clap ability by {1} rage point."] = "Thunder Clap yeteneğinin maliyetini {1} rage puanı azaltır.",
   ["Reduces the cost of your Thunder Clap ability by {1} rage points."] = "Thunder Clap yeteneğinin maliyetini {1} rage puanı azaltır.",
   ["Reduces the delay before your Fire Nova Totem activates by {1} sec. and decreases the threat generated by your Magma Totem by {2}%."] = "Fire Nova Totem'in etkinleşmesinden önceki gecikmeyi {1} sn azaltır ve Magma Totem'in oluşturduğu tehdidi %{2} azaltır.",
   ["Reduces the Energy cost of your Cheap Shot and Garrote abilities by {1}."] = "Cheap Shot ve Garrote yeteneklerinin Energy maliyetini {1} azaltır.",
   ["Reduces the Energy cost of your Shred ability by {1}."] = "Shred yeteneğinin Energy maliyetini {1} azaltır.",
   ["Reduces the Energy cost of your Sinister Strike ability by {1}."] = "Sinister Strike yeteneğinin Energy maliyetini {1} azaltır.",
   ["Reduces the mana cost of all shapeshifting by {1}%."] = "Tüm şekil değiştirmenin mana maliyetini %{1} azaltır.",
   ["Reduces the mana cost of all spells by {1}% for {2} sec."] = "Tüm büyülerin mana maliyetini {2} sn boyunca %{1} azaltır.",
   ["Reduces the Mana cost of your Destruction spells by {1}%."] = "Destruction büyülerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the mana cost of your Frost spells by {1}% and reduces the threat caused by your Frost spells by {2}%."] = "Buz büyülerinin mana maliyetini %{1} azaltır ve Buz büyülerinin oluşturduğu tehdidi %{2} azaltır.",
   ["Reduces the mana cost of your healing over time spells by {1}% and grants the ability to shapeshift into the Tree of Life. While in this form you increase healing received by {2}% for all party and raid members within {3} yards, and you can only cast Restoration spells in addition to Innervate, Barkskin, Nature's Grasp and Thorns spells. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Süreli iyileştirme büyülerinizin mana maliyetini %{1} azaltır ve Tree of Life'a dönüşme yeteneği verir. Bu formdayken {3} yard içindeki tüm grup ve akın üyeleri için alınan iyileştirmeyi %{2} artırırsınız ve Innervate, Barkskin, Nature's Grasp ve Thorns büyülerine ek olarak yalnızca Restoration büyüleri yapabilirsiniz. Dönüşme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Reduces the Mana cost of your healing spells by {1}%."] = "İyileştirme büyülerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the mana cost of your Healing Touch and Tranquility spells by {1}%."] = "Healing Touch ve Tranquility büyülerinin mana maliyetini %{1} azaltır.",
   ["Reduces the mana cost of your instant cast spells by {1}%."] = "Anında okunan büyülerinin mana maliyetini %{1} azaltır.",
   ["Reduces the Mana cost of your Judgement and Seal spells by {1}%."] = "Judgement ve Seal büyülerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the Mana cost of your Lesser Heal, Heal, and Greater Heal spells by {1}%."] = "Lesser Heal, Heal ve Greater Heal büyülerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the Mana cost of your Moonfire, Starfire, Wrath, Healing Touch, Regrowth and Rejuvenation spells by {1}%."] = "Moonfire, Starfire, Wrath, Healing Touch, Regrowth ve Rejuvenation büyülerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the Mana cost of your Prayer of Healing spell by {1}%."] = "Prayer of Healing büyünün Mana maliyetini %{1} azaltır.",
   ["Reduces the mana cost of your Shock, Lightning Bolt and Chain Lightning spells by {1}%."] = "Shock, Lightning Bolt ve Chain Lightning büyülerinin mana maliyetini %{1} azaltır.",
   ["Reduces the Mana cost of your Shots and Stings by {1}%."] = "Shot ve Sting'lerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the Mana cost of your totems by {1}%."] = "Totemlerinin Mana maliyetini %{1} azaltır.",
   ["Reduces the melee attack power of all enemies within {1} yards by {2} for {3} sec."] = "{1} yard içindeki tüm düşmanların yakın dövüş saldırı gücünü {3} sn boyunca {2} azaltır.",
   ["Reduces the Rage cost of your Execute ability by {1}."] = "Execute yeteneğinin Rage maliyetini {1} azaltır.",
   ["Reduces the Stamina of targets affected by your Scorpid Sting by {1}% of the amount of Strength reduced."] = "Scorpid Sting'inden etkilenen hedeflerin Stamina değerini, azaltılan Strength miktarının %{1} kadar azaltır.",
   ["Reduces the target's movement speed by {1}% for {2} sec. Only one Curse per Warlock can be active on any one target."] = "Hedefin hareket hızını {2} sn boyunca %{1} azaltır. Herhangi bir hedefte her Warlock'tan yalnızca bir Curse aktif olabilir.",
   ["Reduces the threat generated by your Healing spells by {1}%."] = "İyileştirme büyülerinin oluşturduğu tehdidi %{1} azaltır.",
   ["Reduces the threat generated by your healing spells by {1}%."] = "İyileştirme büyülerinin oluşturduğu tehdidi %{1} azaltır.",
   ["Reduces the threat generated by your Shadow spells by {1}%."] = "Gölge büyülerinin oluşturduğu tehdidi %{1} azaltır.",
   ["Reduces the threat generated by your spells by {1}%."] = "Büyülerinin oluşturduğu tehdidi %{1} azaltır.",
   ["Reduces threat by {1}% for all enemies within {2} yards."] = "{2} yard içindeki tüm düşmanlar için tehdidi %{1} azaltır.",
   ["Reduces threat caused by Tranquility by {1}%."] = "Tranquility'nin oluşturduğu tehdidi %{1} azaltır.",
   ["Reduces your target's chance to resist your Shadow spells by {1}%."] = "Hedefinin Gölge büyülerine direnme şansını %{1} azaltır.",
   ["Reduces your target's resistance to all your spells by {1} and reduces the threat caused by your Arcane spells by {2}%."] = "Hedefinin tüm büyülerine direncini {1} azaltır ve Arcane büyülerinin oluşturduğu tehdidi %{2} azaltır.",
   ["Regenerates {1}% of your total health and mana over {2} sec."] = "{2} sn boyunca toplam can ve mananızın %{1}'ini yeniler.",
   ["Regenerates {1}% of your total Health over {2} sec after being the victim of a critical strike."] = "Bir kritik vuruşun kurbanı olduktan sonra toplam Can'ının %{1} kadarını {2} sn boyunca yeniler.",
   ["Removes all movement impairing effects and all effects which cause loss of control of your character. This effect shares a cooldown with other similar effects."] = "Tüm hareket engelleyici etkileri ve karakterinizin kontrolünü kaybetmesine neden olan tüm etkileri kaldırır. Bu etki, diğer benzer etkilerle ortak bir bekleme süresine sahiptir.",
   ["Removes {1} Curse from a friendly target."] = "Dost bir hedeften {1} lanet kaldırır.",
   ["Removes {1} disease from the friendly target."] = "Dost hedeften {1} hastalık kaldırır.",
   ["Reputation gains increased by {1}%."] = "İtibar kazanımı %{1} artar.",
   ["Requires Battle Stance, Berserker Stance"] = "Battle Stance, Berserker Stance gerektirir.",
   ["Requires Battle Stance, Defensive Stance"] = "Battle Stance, Defensive Stance gerektirir.",
   ["Requires Bear Form, Dire Bear Form"] = "Bear Form, Dire Bear Form gerektirir.",
   ["Requires Berserker Stance"] = "Berserker Stance gerektirir.",
   ["Requires Cat Form, Bear Form, Dire Bear Form"] = "Cat Form, Bear Form, Dire Bear Form gerektirir.",
   ["Requires Defensive Stance"] = "Defensive Stance gerektirir.",
   ["Requires One-Handed Axes, Two-Handed Axes, Fist Weapons"] = "Tek Elli Baltalar, İki Elli Baltalar, Yumruk Silahları gerektirir",
   ["Requires One-Handed Axes, Two-Handed Axes, One-Handed Maces, Two-Handed Maces, One-Handed Swords, Two-Handed Swords, Fist Weapons, Daggers"] = "Tek Elli Baltalar, İki Elli Baltalar, Tek Elli Topuzlar, İki Elli Topuzlar, Tek Elli Kılıçlar, İki Elli Kılıçlar, Yumruk Silahları, Hançerler gerektirir.",
   ["Requires One-Handed Axes, Two-Handed Axes, One-Handed Maces, Two-Handed Maces, Staves, Fist Weapons, Daggers"] = "Tek Elli Baltalar, İki Elli Baltalar, Tek Elli Topuzlar, İki Elli Topuzlar, Asalar, Yumruk Silahları, Hançerler gerektirir.",
   ["Requires One-Handed Maces, Two-Handed Maces"] = "Tek Elli Topuzlar, İki Elli Topuzlar gerektirir.",
   ["Requires One-Handed Melee Weapon"] = "Tek Elli Yakın Dövüş Silahı gerektirir.",
   ["Requires One-Handed Swords, Two-Handed Swords"] = "Tek Elli Kılıçlar, İki Elli Kılıçlar gerektirir.",
   ["Requires {1} point in Leader of the Pack"] = "Leader of the Pack yeteneğinde {1} puan gerektirir.",
   ["Requires {1} point in Mangle"] = "Mangle yeteneğinde {1} puan gerektirir.",
   ["Requires {1} point in Tree of Life"] = "Tree of Life yeteneğinde {1} puan gerektirir.",
   ["Requires {1} points in Feral Combat Talents"] = "Feral Combat yeteneklerinde {1} puan gerektirir.",
   ["Requires {1} points in Rend and Tear"] = "Rend and Tear yeteneğinde {1} puan gerektirir.",
   ["Requires {1} points in Restoration Talents"] = "Restoration yeteneklerinde {1} puan gerektirir.",
   ["Restore {1} health every {2} sec."] = "Her {2} sn'de bir {1} can yeniler.",
   ["Restores mana when a spell is fully resisted."] = "Bir büyüye tamamen direnildiğinde mana yeniler.",
   ["Retrieving item information"] = "Eşya bilgisi alınıyor",
   ["Returns the spirit to the body, restoring a dead target to life with {1} health and {2} mana."] = "Ruhu bedene geri gönderir; ölü bir hedefi {1} can ve {2} mana ile yeniden diriltir.",
   ["Returns the spirit to the body, restoring a dead target to life with {1} health and {2} mana. Cannot be cast when in combat."] = "Ruhu bedene geri gönderir; ölü bir hedefi {1} can ve {2} mana ile yeniden diriltir. Savaştayken büyü yapılamaz.",
   ["Returns your totems to the earth, giving you {1}% of the mana required to cast each totem destroyed by Totemic Recall."] = "Totemlerinizi toprağa geri döndürür; Totemic Recall ile yok edilen her totemi yapmak için gereken mananın %{1} kadarını size verir.",
   ["Revive Pet's casting time is reduced by {1} sec, mana cost is reduced by {2}%, and increases the health your pet returns with by an additional {3}%."] = "Revive Pet'in okuma süresi {1} sn azalır, mana maliyeti %{2} azalır ve evcil hayvanının döndüğü canı ek %{3} artırır.",
   ["Revive your pet, returning it to life with {1}% of its base health."] = "Evcil hayvanınızı diriltir; temel canının %{1} kadarıyla hayata döndürür.",
   ["Roots the target in place and causes {1} Nature damage over {2} sec. Damage caused may interrupt the effect."] = "Hedefi olduğu yere sabitler ve {2} sn boyunca {1} Doğa hasarı verir. Verilen hasar etkiyi kesebilir.",
   ["Run at high speed towards a party member, intercepting the next melee or ranged attack made against them as well as reducing their total threat by {1}%."] = "Bir grup üyesine doğru yüksek hızla koşar; ona yapılacak bir sonraki yakın dövüş veya menzilli saldırının önüne geçer ve toplam tehdidini %{1} azaltır.",
   ["Sacrifices an undead minion, healing the Death Knight for {1}% of her maximum health. This heal cannot be a critical."] = "Bir undead uşağını feda ederek Death Knight'ı maksimum canının %{1} kadarı iyileştirir. Bu iyileştirme kritik olamaz.",
   ["Sacrifices an undead minion, healing the Death Knight for {1}% of his maximum health. This heal cannot be a critical."] = "Bir undead uşağını feda ederek Death Knight'ı maksimum canının %{1} kadarı iyileştirir. Bu iyileştirme kritik olamaz.",
   ["Scares a beast, causing it to run in fear for up to {1} sec. Damage caused may interrupt the effect. Only one beast can be feared at a time."] = "Bir canavarı korkutarak en fazla {1} sn boyunca korku içinde kaçmasına neden olur. Verilen hasar etkiyi kesebilir. Aynı anda yalnızca bir canavar korkutulabilir.",
   ["Scorch the enemy for {1} to {2} Fire damage."] = "Düşmanı {1} ila {2} Ateş hasarıyla kavurur.",
   ["Search {1} ore of a base metal for precious gems. This will destroy the ore in the process."] = "Değerli taşlar için {1} adet baz metal cevherini araştırır. Bu işlem sırasında cevher yok olur.",
   ["Send your pet into a rage causing {1}% additional damage for {2} sec. While enraged, the beast does not feel pity or remorse or fear and it cannot be stopped unless killed."] = "Evcil hayvanını öfkeye sokarak {2} sn boyunca %{1} ek hasar verir. Öfkeliyken canavar acıma, pişmanlık ya da korku hissetmez ve öldürülmedikçe durdurulamaz.",
   ["Sends a shadowy bolt at the enemy, causing {1} to {2} Shadow damage."] = "Düşmana gölgeli bir ok göndererek {1} ila {2} Gölge hasarı verir.",
   ["Sends a wave of force in front of the warrior, causing {1} damage (based on attack power) and stunning all enemy targets within {2} yards in a frontal cone for {3} sec."] = "Warrior'ın önüne bir güç dalgası göndererek {1} hasar (saldırı gücüne dayalı) verir ve önündeki koni şeklinde {2} yard içindeki tüm düşman hedefleri {3} sn boyunca sersemletir.",
   ["Sends bolts of holy power in all directions, causing {1} to {2} Holy damage and stunning all Undead and Demon targets within {3} yds for {4} sec."] = "Tüm yönlere kutsal güç okları göndererek {1} ila {2} Kutsal hasar verir ve {3} yard içindeki tüm Undead ve Demon hedefleri {4} sn boyunca sersemletir.",
   ["Shackles the target undead enemy for up to {1} sec. The shackled unit is unable to move, attack or cast spells. Any damage caused will release the target. Only one target can be shackled at a time."] = "Hedef undead düşmanı en fazla {1} sn boyunca zincirler. Zincirlenen birim hareket edemez, saldıramaz veya büyü yapamaz. Verilen herhangi bir hasar hedefi serbest bırakır. Aynı anda yalnızca bir hedef zincirlenebilir.",
   ["Shackles the target with frozen chains, reducing their movement by {1}%, and infects them with Frost Fever. The target regains {2}% of their movement each second for {3} sec."] = "Hedefi donmuş zincirlerle bağlayarak hareketini %{1} azaltır ve ona Frost Fever bulaştırır. Hedef, {3} sn boyunca her saniye hareketinin %{2} kadarını geri kazanır.",
   ["Shadow energy slowly destroys the target. In addition, if the Unstable Affliction is dispelled it will cause damage to the dispeller and silence them for {1} sec. Only one Unstable Affliction or Immolate per Warlock can be active on any one target."] = "Gölge enerjisi hedefi yavaşça yok eder. Ayrıca, Unstable Affliction dağıtılırsa dağıtana hasar verir ve onu {1} sn boyunca susturur. Her Warlock için herhangi bir hedefte aynı anda yalnızca bir Unstable Affliction veya Immolate etkin olabilir.",
   ["Shapeshift into aquatic form, increasing swim speed by {1}% and allowing the druid to breathe underwater. Also protects the caster from Polymorph effects. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Aquatic Form'a dönüşerek yüzme hızını %{1} artırır ve Druid'in su altında nefes almasını sağlar. Ayrıca büyücüyü Polymorph etkilerinden korur. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into bear form, increasing melee attack power by {1}, armor contribution from cloth and leather items by {2}%, and Stamina by {3}%. Also protects the caster from Polymorph effects and allows the use of various bear abilities. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Bear Form'a dönüşerek yakın dövüş saldırı gücünü {1}, kumaş ve deri eşyalardan gelen zırh katkısını %{2} ve Stamina'yı %{3} artırır. Ayrıca büyücüyü Polymorph etkilerinden korur ve çeşitli ayı yeteneklerinin kullanılmasını sağlar. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into cat form, increasing melee attack power by {1} plus Agility. Also protects the caster from Polymorph effects and allows the use of various cat abilities. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Cat Form'a dönüşerek yakın dövüş saldırı gücünü {1} artı Agility kadar artırır. Ayrıca büyücüyü Polymorph etkilerinden korur ve çeşitli kedi yeteneklerinin kullanılmasını sağlar. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into dire bear form, increasing melee attack power by {1}, armor contribution from cloth and leather items by {2}%, and Stamina by {3}%. Also protects the caster from Polymorph effects and allows the use of various bear abilities. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Dire Bear Form'a dönüşerek yakın dövüş saldırı gücünü {1}, kumaş ve deri eşyalardan gelen zırh katkısını %{2} ve Stamina'yı %{3} artırır. Ayrıca büyücüyü Polymorph etkilerinden korur ve çeşitli ayı yeteneklerinin kullanılmasını sağlar. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into flight form, increasing movement speed by {1}% and allowing you to fly. Cannot use in combat. Can only use this form in Outland or Northrend. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Flight Form'a dönüşerek hareket hızını %{1} artırır ve uçmanızı sağlar. Savaşta kullanılamaz. Bu form yalnızca Outland veya Northrend'de kullanılabilir. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into swift flight form, increasing movement speed by {1}% and allowing you to fly. Cannot use in combat. Can only use this form in Outland or Northrend. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Swift Flight Form'a dönüşerek hareket hızını %{1} artırır ve uçmanızı sağlar. Savaşta kullanılamaz. Bu form yalnızca Outland veya Northrend'de kullanılabilir. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into the Tree of Life. While in this form you increase healing received by {1}% for all party and raid members within {2} yards, and you can only cast Restoration spells in addition to Innervate, Barkskin, Nature's Grasp and Thorns spells. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Tree of Life'a dönüşür. Bu formdayken, {2} yard içindeki tüm grup ve akın üyeleri için alınan iyileştirmeyi %{1} artırırsınız ve Innervate, Barkskin, Nature's Grasp ve Thorns büyülerine ek olarak yalnızca Restoration büyüleri yapabilirsiniz. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shapeshift into travel form, increasing movement speed by {1}%. Also protects the caster from Polymorph effects. Only useable outdoors. The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Travel Form'a dönüşerek hareket hızını %{1} artırır. Ayrıca büyücüyü Polymorph etkilerinden korur. Yalnızca açık alanda kullanılabilir. Şekil değiştirme eylemi, büyücüyü Polymorph ve hareket engelleyici etkilerden kurtarır.",
   ["Shows the location of all nearby beasts on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm canavarların konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby demons on the minimap until cancelled. Only one form of tracking can be active at a time."] = "Yakındaki tüm iblislerin konumunu, iptal edilene kadar mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby demons on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm iblislerin konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby dragonkin on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm Dragonkin'lerin konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby elementals on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm elementallerin konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby giants on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm devlerin konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby humanoids on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm insansıların konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby humanoids on the minimap. Only one type of thing can be tracked at a time."] = "Yakındaki tüm insansıların konumunu mini haritada gösterir. Aynı anda yalnızca tek bir tür izlenebilir.",
   ["Shows the location of all nearby undead on the minimap until cancelled. Only one form of tracking can be active at a time."] = "Yakındaki tüm undead'lerin konumunu, iptal edilene kadar mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shows the location of all nearby undead on the minimap. Only one form of tracking can be active at a time."] = "Yakındaki tüm undead'lerin konumunu mini haritada gösterir. Aynı anda yalnızca bir izleme türü etkin olabilir.",
   ["Shred the target, causing {1}% damage plus {2} to the target. Must be behind the target. Awards {3} combo point. Effects which increase Bleed damage also increase Shred damage."] = "Hedefi paralayarak hedefe %{1} hasar artı {2} verir. Hedefin arkasında olunmalıdır. {3} kombo puanı kazandırır. Kanama hasarını artıran etkiler Shred hasarını da artırır.",
   ["Silence all enemies within {1} yards for {2} sec and restores {3} of your Energy. Non-player victim spellcasting is also interrupted for {4} sec."] = "{1} yard içindeki tüm düşmanları {2} sn boyunca susturur ve {3} enerji yeniler. Oyuncu olmayan kurbanların büyü yapması da {4} sn boyunca kesilir.",
   ["Silence all enemies within {1} yards for {2} sec and restores {3} Runic Power. Non-player victim spellcasting is also interrupted for {4} sec."] = "{1} yard içindeki tüm düşmanları {2} sn boyunca susturur ve {3} Runic Power yeniler. Oyuncu olmayan kurbanların büyü yapması da {4} sn boyunca kesilir.",
   ["Silence all enemies within {1} yards for {2} sec and restores {3}% of your Mana. Non-player victim spellcasting is also interrupted for {4} sec."] = "{1} yard içindeki tüm düşmanları {2} sn boyunca susturur ve mananızın %{3} kadarını yeniler. Oyuncu olmayan kurbanların büyü yapması da {4} sn boyunca kesilir.",
   ["Silences the target, preventing them from casting spells for {1} sec."] = "Hedefi susturarak {1} sn boyunca büyü yapmasını engeller.",
   ["Slam the target with your shield, causing Holy damage based on your block value plus an additional {1}."] = "Kalkanınızla hedefe vurarak engelleme değerinize dayalı Kutsal hasar ve ek olarak {1} hasar verir.",
   ["Slam the target with your shield, causing {1} to {2} damage, modified by your shield block value, and dispels {3} magic effect on the target. Also causes a high amount of threat."] = "Kalkanınızla hedefe vurarak, kalkan engelleme değerinizle değiştirilen {1} ila {2} hasar verir ve hedefteki {3} büyü etkisini dağıtır. Ayrıca yüksek miktarda tehdit oluşturur.",
   ["Slam the target with your shield, causing {1} to {2} damage, modified by your shield block value, and has a {3}% chance of dispelling {4} magic effect on the target. Also causes a high amount of threat."] = "Hedefe kalkanınla vurarak {1} ila {2} hasar verir, kalkan bloklama değerine göre değişir ve hedef üzerindeki {4} büyü etkisini dağıtmak için %{3} şansa sahiptir. Ayrıca yüksek miktarda tehdit oluşturur.",
   ["Slams the opponent, causing weapon damage plus {1}."] = "Rakibe vurarak silah hasarı artı {1} verir.",
   ["Slows friendly party or raid target's falling speed for {1} sec."] = "Dost grup veya akın hedefinin düşme hızını {1} sn boyunca yavaşlatır.",
   ["Smash the target's mind with cold, interrupting spellcasting and preventing any spell in that school from being cast for {1} sec."] = "Hedefin zihnini soğukla ezerek büyü yapmasını keser ve {1} sn boyunca o okuldan herhangi bir büyünün yapılmasını engeller.",
   ["Smite an enemy for {1} to {2} Holy damage."] = "Bir düşmanı {1} ila {2} Kutsal hasarla vurur.",
   ["Soothes the target beast, reducing the range at which it will attack you by {1} yards. Only affects Beast and Dragonkin targets level {2} or lower. Lasts {3} sec."] = "Hedef canavarı yatıştırarak size saldıracağı menzili {1} yard azaltır. Yalnızca {2} ve daha düşük seviyedeki Beast ve Dragonkin hedefleri etkiler. {3} sn sürer.",
   ["Soothes the target, reducing the range at which it will attack you by {1} yards. Only affects Humanoid targets. Lasts {2} sec."] = "Hedefi yatıştırarak size saldıracağı menzili {1} yard azaltır. Yalnızca Humanoid hedefleri etkiler. {2} sn sürer.",
   ["Spreads existing Blood Plague and Frost Fever infections from your target to all other enemies within {1} yards."] = "Hedefindeki mevcut Blood Plague ve Frost Fever enfeksiyonlarını {1} yarda içindeki diğer tüm düşmanlara yayar.",
   ["Stings the target, causing {1} Nature damage over {2} sec. Only one Sting per Hunter can be active on any one target."] = "Hedefi sokarak {2} sn boyunca {1} Doğa hasarı verir. Her Hunter için herhangi bir hedefte aynı anda yalnızca bir Sting etkin olabilir.",
   ["Stings the target, draining {1}% mana over {2} sec (up to a maximum of {3}% of the caster's maximum mana), and energizing the Hunter equal to {4}% of the amount drained. Only one Sting per Hunter can be active on any one target."] = "Hedefi sokarak {2} sn boyunca %{1} mana emer (büyücünün maksimum manasının en fazla %{3} kadarı) ve emilen miktarın %{4} kadarınca Hunter'a enerji verir. Her Hunter için herhangi bir hedefte aynı anda yalnızca bir Sting etkin olabilir.",
   ["Stings the target, reducing chance to hit with melee and ranged attacks by {1}% for {2} sec. Only one Sting per Hunter can be active on any one target."] = "Hedefi sokarak yakın dövüş ve menzilli saldırılarla vurma şansını {2} sn boyunca %{1} azaltır. Her Hunter için herhangi bir hedefte aynı anda yalnızca bir Sting etkin olabilir.",
   ["Strangulates an enemy, silencing them for {1} sec. Non-player victim spellcasting is also interrupted for {2} sec."] = "Bir düşmanı boğarak {1} sn susturur. Oyuncu olmayan kurbanların büyü yapması da {2} sn kesilir.",
   ["Strengthens the Death Knight with the presence of blood, increasing damage by {1}% and healing the Death Knight by {2}% of damage dealt. Only one Presence may be active at a time."] = "Death Knight'ı kanın varlığıyla güçlendirerek hasarı %{1} artırır ve verilen hasarın %{2} kadarınca Death Knight'ı iyileştirir. Aynı anda yalnızca bir Presence etkin olabilir.",
   ["Strikes fear in the enemy, causing it to run in fear for up to {1} sec. Damage caused may interrupt the effect. Only {2} target can be feared at a time."] = "Düşmana korku salarak en fazla {1} sn boyunca korku içinde kaçmasına neden olur. Verilen hasar etkiyi kesebilir. Aynı anda yalnızca {2} hedef korkutulabilir.",
   ["Stuns the opponent for {1} sec."] = "Rakibi {1} sn sersemletir.",
   ["Stuns the target for {1} sec and interrupts non-player spellcasting for {2} sec."] = "Hedefi {1} sn boyunca sersemletir ve oyuncu olmayanların büyü yapmasını {2} sn boyunca keser.",
   ["Stuns the target for {1} sec."] = "Hedefi {1} sn boyunca sersemletir.",
   ["Stuns the target for {1} sec. Must be stealthed. Awards {2} combo points."] = "Hedefi {1} sn boyunca sersemletir. Gizlenmiş olunmalıdır. {2} kombo puanı kazandırır.",
   ["Summon an elemental totem that calls forth a greater earth elemental to protect the caster and her allies. Lasts {1} min."] = "Büyücüyü ve müttefiklerini korumak için büyük bir toprak elementali çağıran bir element totemi çağırır. {1} dk sürer.",
   ["Summon an elemental totem that calls forth a greater earth elemental to protect the caster and his allies. Lasts {1} min."] = "Büyücüyü ve müttefiklerini korumak için büyük bir toprak elementali çağıran bir element totemi çağırır. {1} dk sürer.",
   ["Summons a Charger, which serves as a mount. This is a very fast mount."] = "Binek görevi gören bir Charger çağırır. Bu çok hızlı bir binektir.",
   ["Summons a Cleansing Totem with {1} health at the feet of the caster that attempts to remove {2} disease and {3} poison effect from party members within {4} yards every {5} seconds. Lasts {6} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Cleansing Totem çağırır; bu totem her {5} saniyede {4} yard içindeki grup üyelerinden {2} hastalık ve {3} zehir etkisini kaldırmaya çalışır. {6} dk sürer.",
   ["Summons a Dreadsteed, which serves as a mount. This is a very fast mount."] = "Binek görevi gören bir Dreadsteed çağırır. Bu çok hızlı bir binektir.",
   ["Summons a Felhunter under the command of the Warlock."] = "Warlock'un komutası altında bir Felhunter çağırır.",
   ["Summons a Felsteed, which serves as a mount."] = "Binek görevi gören bir Felsteed çağırır.",
   ["Summons a Fire Resistance Totem with {1} health at the feet of the caster for {2} min that increases the fire resistance of party and raid members within {3} yards by {4}."] = "Büyücünün ayaklarının dibine {2} dk boyunca {1} cana sahip bir Fire Resistance Totem çağırır; bu totem {3} yard içindeki grup ve akın üyelerinin ateş direncini {4} artırır.",
   ["Summons a Flametongue Totem with {1} health at the feet of the caster. Party and raid members within {2} yards of the totem have their spell damage and healing increased by up to {3}. Lasts {4} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Flametongue Totem çağırır. Totemin {2} yard çevresindeki grup ve akın üyelerinin büyü hasarı ve iyileştirmesi en fazla {3} artar. {4} dk sürer.",
   ["Summons a Frost Resistance Totem with {1} health at the feet of the caster for {2} min. The totem increases party and raid members' frost resistance by {3}, if within {4} yards."] = "Büyücünün ayaklarının dibine {2} dk boyunca {1} cana sahip bir Frost Resistance Totem çağırır. Totem, {4} yard içindeyse grup ve akın üyelerinin buz direncini {3} artırır.",
   ["Summons a Grounding Totem with {1} health at the feet of the caster that will redirect one harmful spell cast on a nearby party member to itself, destroying the totem. Will not redirect area of effect spells. Lasts {2} sec."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Grounding Totem çağırır; bu totem, yakındaki bir grup üyesine yapılan zararlı bir büyüyü kendine yönlendirir ve bu sırada yok olur. Alan etkili büyüleri yönlendirmez. {2} sn sürer.",
   ["Summons a Healing Stream Totem with {1} health at the feet of the caster for {2} min that heals group members within {3} yards for {4} every {5} seconds."] = "Büyücünün ayaklarının dibine {2} dk boyunca {1} cana sahip bir Healing Stream Totem çağırır; bu totem her {5} saniyede {3} yard içindeki grup üyelerini {4} iyileştirir.",
   ["Summons a Magma Totem with {1} health at the feet of the caster for {2} sec that causes {3} Fire damage to creatures within {4} yards every {5} seconds."] = "Büyücünün ayaklarının dibine {2} sn boyunca {1} cana sahip bir Magma Totem çağırır; bu totem her {5} saniyede {4} yard içindeki yaratıklara {3} Ateş hasarı verir.",
   ["Summons a Mana Spring Totem with {1} health at the feet of the caster for {2} min that restores {3} mana every {4} seconds to all party and raid members within {5} yards."] = "Büyücünün ayaklarının dibine {2} dk boyunca {1} cana sahip bir Mana Spring Totem çağırır; bu totem her {4} saniyede {5} yard içindeki tüm grup ve akın üyelerine {3} mana yeniler.",
   ["Summons a Mana Tide Totem with {1} health at the feet of the caster for {2} sec that restores {3} mana every {4} seconds to group members within {5} yards."] = "Büyüyü yapanın ayaklarının dibine {2} sn boyunca {1} can'lı bir Mana Tide Totem çağırır; bu totem {5} yarda içindeki grup üyelerine her {4} saniyede bir {3} mana yeniler.",
   ["Summons a meteor from the Twisting Nether, causing {1} Fire damage and stunning all enemy targets in the area for {2} sec. An Infernal rises from the crater, under the command of the caster for {3} min."] = "Twisting Nether'dan bir göktaşı çağırarak {1} Ateş hasarı verir ve alandaki tüm düşman hedefleri {2} sn boyunca sersemletir. Kraterden bir Infernal yükselir ve {3} dk boyunca büyücünün komutası altında kalır.",
   ["Summons a Nature Resistance Totem with {1} health at the feet of the caster for {2} min that increases the nature resistance of party and raid members within {3} yards by {4}."] = "Büyücünün ayaklarının dibine {2} dk boyunca {1} cana sahip bir Nature Resistance Totem çağırır; bu totem {3} yard içindeki grup ve akın üyelerinin doğa direncini {4} artırır.",
   ["Summons a Searing Totem with {1} health at your feet for {2} min that repeatedly attacks an enemy within {3} yards for {4} to {5} Fire damage."] = "Ayaklarınızın dibine {2} dk boyunca {1} cana sahip bir Searing Totem çağırır; bu totem {3} yard içindeki bir düşmana tekrar tekrar saldırarak {4} ila {5} Ateş hasarı verir.",
   ["Summons a Searing Totem with {1} health at your feet for {2} sec that repeatedly attacks an enemy within {3} yards for {4} to {5} Fire damage."] = "Ayaklarınızın dibine {2} sn boyunca {1} cana sahip bir Searing Totem çağırır; bu totem {3} yard içindeki bir düşmana tekrar tekrar saldırarak {4} ila {5} Ateş hasarı verir.",
   ["Summons a Stoneclaw Totem with {1} health at the feet of the caster for {2} sec that taunts creatures within {3} yards to attack it. Enemies attacking the Stoneclaw Totem have a {4}% chance to be stunned for {5} sec. Stoneclaw totem also protects all your totems, causing them to absorb {6} damage."] = "Büyücünün ayaklarının dibine {2} sn boyunca {1} cana sahip bir Stoneclaw Totem çağırır; bu totem {3} yard içindeki yaratıkları kendine saldırmaları için kışkırtır. Stoneclaw Totem'e saldıran düşmanların {5} sn boyunca sersemletilme şansı %{4} olur. Stoneclaw totemi ayrıca tüm totemlerinizi koruyarak {6} hasar emmelerini sağlar.",
   ["Summons a Stoneskin Totem with {1} health at the feet of the caster. The totem protects party and raid members within {2} yards, increasing armor by {3}. Lasts {4} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Stoneskin Totem çağırır. Totem, {2} yard içindeki grup ve akın üyelerini koruyarak zırhı {3} artırır. {4} dk sürer.",
   ["Summons a Strength of Earth Totem with {1} health at the feet of the caster. The totem increases the strength and agility of all party and raid members within {2} yards by {3}. Lasts {4} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Strength of Earth Totem çağırır. Totem, {2} yard içindeki tüm grup ve akın üyelerinin Strength ve Agility değerini {3} artırır. {4} dk sürer.",
   ["Summons a Succubus under the command of the Warlock."] = "Warlock'un komutası altında bir Succubus çağırır.",
   ["Summons a Totem of Wrath with {1} health at the feet of the caster. The totem increases spell power by {2} for all party and raid members, and increases the critical strike chance of of all attacks by {3}% against all enemies within {4} yards. Lasts {5} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Totem of Wrath çağırır. Totem, tüm grup ve akın üyeleri için büyü gücünü {2} artırır ve {4} yard içindeki tüm düşmanlara karşı tüm saldırıların kritik vurma şansını %{3} artırır. {5} dk sürer.",
   ["Summons a Totem of Wrath with {1} health at the feet of the caster. The totem increases the spell power by {2} for all party and raid members, and increases the critical strike chance of all attacks by {3}% against all enemies within {4} yards. Lasts {5} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Totem of Wrath çağırır. Totem, tüm grup ve akın üyeleri için büyü gücünü {2} artırır ve {4} yard içindeki tüm düşmanlara karşı tüm saldırıların kritik vurma şansını %{3} artırır. {5} dk sürer.",
   ["Summons a Tremor Totem with {1} health at the feet of the caster that shakes the ground around it, removing Fear, Charm and Sleep effects from party members within {2} yards. Lasts {3} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Tremor Totem çağırır; bu totem çevresindeki zemini sarsarak {2} yard içindeki grup üyelerinden Fear, Charm ve Sleep etkilerini kaldırır. {3} dk sürer.",
   ["Summons a Voidwalker under the command of the Warlock."] = "Warlock'un komutası altında bir Voidwalker çağırır.",
   ["Summons a Warhorse, which serves as a mount."] = "Binek görevi gören bir Warhorse çağırır.",
   ["Summons a warhorse, which serves as a mount."] = "Binek görevi gören bir Warhorse çağırır.",
   ["Summons a Windfury Totem with {1} health at the feet of the caster. The totem provides {2}% melee haste to all party and raid members within {3} yards. Lasts {4} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Windfury Totem çağırır. Totem, {3} yard içindeki tüm grup ve akın üyelerine %{2} yakın dövüş hızı sağlar. {4} dk sürer.",
   ["Summons a Wrath of Air Totem with {1} health at the feet of the caster. The totem provides {2}% spell haste to all party and raid members within {3} yards. Lasts {4} min."] = "Büyücünün ayaklarının dibine {1} cana sahip bir Wrath of Air Totem çağırır. Totem, {3} yard içindeki tüm grup ve akın üyelerine %{2} büyü hızı sağlar. {4} dk sürer.",
   ["Summons an Earthbind Totem with {1} health at the feet of the caster for {2} sec that slows the movement speed of enemies within {3} yards."] = "Büyücünün ayaklarının dibine {2} sn boyunca {1} cana sahip bir Earthbind Totem çağırır; bu totem {3} yard içindeki düşmanların hareket hızını yavaşlatır.",
   ["Summons an entire legion of Ghouls to fight for the Death Knight. The Ghouls will swarm the area, taunting and fighting anything they can."] = "Death Knight için savaşacak koca bir Ghoul lejyonu çağırır. Ghoul'lar alanı sarar, ellerine geçen her şeyi kışkırtıp onlarla savaşır.",
   ["Summons an entire legion of Ghouls to fight for the Death Knight. The Ghouls will swarm the area, taunting and fighting anything they can. While channelling Army of the Dead, the Death Knight takes less damage equal to her Dodge plus Parry chance."] = "Death Knight için savaşacak koca bir Ghoul lejyonu çağırır. Ghoul'lar alanı sarar, ellerine geçen her şeyi kışkırtıp onlarla savaşır. Army of the Dead kanalize edilirken, Death Knight sıyırma artı savuşturma şansı kadar daha az hasar alır.",
   ["Summons an entire legion of Ghouls to fight for the Death Knight. The Ghouls will swarm the area, taunting and fighting anything they can. While channelling Army of the Dead, the Death Knight takes less damage equal to his Dodge plus Parry chance."] = "Death Knight için savaşacak koca bir Ghoul lejyonu çağırır. Ghoul'lar alanı sarar, ellerine geçen her şeyi kışkırtıp onlarla savaşır. Army of the Dead kanalize edilirken, Death Knight sıyırma artı savuşturma şansı kadar daha az hasar alır.",
   ["Summons an Eye of Kilrogg and binds your vision to it. The eye moves quickly but is very fragile."] = "Bir Eye of Kilrogg çağırır ve görüşünüzü ona bağlar. Göz hızlı hareket eder ancak çok kırılgandır.",
   ["Summons an immobile Sentry Totem with {1} health at your feet for {2} min that allows vision of nearby area and warns of enemies that attack it. Right-Click on buff to switch back and forth between totem sight and shaman sight."] = "Ayaklarınızın dibine {2} dk boyunca {1} cana sahip, hareketsiz bir Sentry Totem çağırır; bu totem yakındaki alanı görmenizi sağlar ve kendisine saldıran düşmanlar konusunda sizi uyarır. Totem görüşü ile shaman görüşü arasında geçiş yapmak için buff'a sağ tıklayın.",
   ["Summons an Imp under the command of the Warlock."] = "Warlock'un komutası altında bir Imp çağırır.",
   ["Summons and dismisses your rideable Acherus Deathcharger. This is a very fast mount."] = "Binilebilir Acherus Deathcharger'ınızı çağırır ve geri gönderir. Bu çok hızlı bir binektir.",
   ["Sunders the target's armor, reducing it by {1}% per Sunder Armor and causes a high amount of threat. Threat increased by attack power. Can be applied up to {2} times. Lasts {3} sec."] = "Hedefin zırhını parçalar; her Sunder Armor başına %{1} azaltır ve yüksek miktarda tehdit oluşturur. Tehdit saldırı gücüyle artar. En fazla {2} kez uygulanabilir. {3} sn sürer.",
   ["Surrounds the caster with fel energy, increasing spell power by {1} plus additional spell power equal to {2}% of your Spirit. In addition, you regain {3}% of your maximum health every {4} sec. Only one type of Armor spell can be active on the Warlock at any time. Lasts {5} min."] = "Büyücüyü fel enerjisiyle sarar; büyü gücünü {1} artırır ve Spirit'inizin %{2} kadarınca ek büyü gücü ekler. Ayrıca, her {4} sn'de maksimum canınızın %{3} kadarını geri kazanırsınız. Warlock üzerinde aynı anda yalnızca bir tür Armor büyüsü etkin olabilir. {5} dk sürer.",
   ["Surrounds the Death Knight in an Anti-Magic Shell, absorbing {1}% of the damage dealt by harmful spells (up to a maximum of {2}% of the Death Knight's health) and preventing application of harmful magical effects. Damage absorbed by Anti-Magic Shell energizes the Death Knight with additional runic power. Lasts {3} sec."] = "Death Knight'ı bir Anti-Magic Shell ile sarar; zararlı büyülerin verdiği hasarın %{1} kadarını emer (en fazla Death Knight'ın canının %{2} kadarı) ve zararlı büyüsel etkilerin uygulanmasını engeller. Anti-Magic Shell tarafından emilen hasar, Death Knight'a ek Runic Power verir. {3} sn sürer.",
   ["Swipe nearby enemies, inflicting {1} damage. Damage increased by attack power."] = "Yakındaki düşmanları pençeleyerek {1} hasar verir. Hasar saldırı gücüyle artar.",
   ["Swipe nearby enemies, inflicting {1}% weapon damage."] = "Yakındaki düşmanları pençeleyerek %{1} silah hasarı verir.",
   ["Switch to your Primary Talent Specialization."] = "Primary Talent Specialization'ınıza geçersiniz.",
   ["Switch to your Secondary Talent Specialization."] = "Secondary Talent Specialization'ınıza geçersiniz.",
   ["Take direct control of your pet and see through its eyes for {1} min."] = "Pet'inizin doğrudan kontrolünü ele alırsınız ve {1} dk boyunca onun gözünden görürsünüz.",
   ["Target's melee attack power is reduced by {1} and armor is reduced by {2}% for {3} min. Only one Curse per Warlock can be active on any one target."] = "Hedefin yakın dövüş saldırı gücü {1} ve zırhı {3} dk boyunca %{2} azalır. Her Warlock için herhangi bir hedefte aynı anda yalnızca bir Curse aktif olabilir.",
   ["Targets in a cone in front of the caster take {1} to {2} Frost damage and are slowed by {3}% for {4} sec."] = "Büyü yapanın önündeki koni içindeki hedefler {1} ila {2} Buz hasarı alır ve {4} sn boyunca %{3} yavaşlar.",
   ["Targets in a cone in front of the caster take {1} to {2} Shadow damage and an additional {3} Fire damage over {4} sec."] = "Büyü yapanın önündeki koni içindeki hedefler {1} ila {2} Gölge hasarı ve {4} sn boyunca ek {3} Ateş hasarı alır.",
   ["Taunts the target to attack you, but has no effect if the target is already attacking you."] = "Hedefi size saldırması için kışkırtır, ancak hedef zaten size saldırıyorsa etkisi olmaz.",
   ["Taunts the target to attack you. If the target is tauntable and not currently targeting you, causes {1} Holy damage."] = "Hedefi size saldırması için kışkırtır. Hedef kışkırtılabilir durumdaysa ve şu anda sizi hedeflemiyorsa, {1} Kutsal hasar verir.",
   ["Teleports the caster to Dalaran."] = "Büyü yapanı Dalaran'a ışınlar.",
   ["Teleports the caster to Darnassus."] = "Büyü yapanı Darnassus'a ışınlar.",
   ["Teleports the caster to Exodar."] = "Büyü yapanı Exodar'a ışınlar.",
   ["Teleports the caster to Ironforge."] = "Büyü yapanı Ironforge'a ışınlar.",
   ["Teleports the caster to Orgrimmar."] = "Büyü yapanı Orgrimmar'a ışınlar.",
   ["Teleports the caster to Shattrath."] = "Büyü yapanı Shattrath'a ışınlar.",
   ["Teleports the caster to Silvermoon."] = "Büyü yapanı Silvermoon'a ışınlar.",
   ["Teleports the caster to Stonard."] = "Büyü yapanı Stonard'a ışınlar.",
   ["Teleports the caster to Stormwind."] = "Büyü yapanı Stormwind'e ışınlar.",
   ["Teleports the caster to the Moonglade."] = "Büyü yapanı Moonglade'e ışınlar.",
   ["Teleports the caster to Theramore."] = "Büyü yapanı Theramore'a ışınlar.",
   ["Teleports the caster to Thunder Bluff."] = "Büyü yapanı Thunder Bluff'a ışınlar.",
   ["Teleports the caster to Undercity."] = "Büyü yapanı Undercity'ye ışınlar.",
   ["Teleports the caster {1} yards forward, unless something is in the way. Also frees the caster from stuns and bonds."] = "Önünde bir engel yoksa büyü yapanı {1} yard ileri ışınlar. Ayrıca büyü yapanı sersemletmelerden ve bağlardan kurtarır.",
   ["Teleports you to your Demonic Circle and removes all snare effects."] = "Sizi Demonic Circle'ınıza ışınlar ve tüm hareket engelleyici etkileri kaldırır.",
   ["The Berserker Rage ability will generate {1} rage when used."] = "Berserker Rage yeteneği kullanıldığında {1} rage oluşturur.",
   ["The caster is surrounded by {1} balls of lightning. When a spell, melee or ranged attack hits the caster, the attacker will be struck for {2} Nature damage. This expends one lightning ball. Only one ball will fire every few seconds. Lasts {3} min. Only one Elemental Shield can be active on the Shaman at any one time."] = "Büyü yapanın etrafı {1} adet yıldırım topuyla sarılır. Büyü yapan kişiye bir büyü, yakın dövüş veya menzilli saldırı isabet ettiğinde, saldıran {2} Doğa hasarı alır. Bu, bir yıldırım topunu tüketir. Birkaç saniyede yalnızca bir top ateşlenir. {3} dk sürer. Shaman üzerinde aynı anda yalnızca bir Elemental Shield aktif olabilir.",
   ["The caster is surrounded by {1} globes of water, granting {2} mana per {3} sec. When a spell, melee or ranged attack hits the caster, {4} mana is restored to the caster. This expends one water globe. Only one globe will activate every few seconds. Lasts {5} min. Only one Elemental Shield can be active on the Shaman at any one time."] = "Büyü yapanın etrafı {1} adet su küresiyle sarılır ve {3} sn'de {2} mana kazandırır. Büyü yapan kişiye bir büyü, yakın dövüş veya menzilli saldırı isabet ettiğinde, büyü yapana {4} mana geri kazandırılır. Bu, bir su küresini tüketir. Birkaç saniyede yalnızca bir küre etkinleşir. {5} dk sürer. Shaman üzerinde aynı anda yalnızca bir Elemental Shield aktif olabilir.",
   ["The caster lets out a psychic scream, causing {1} enemies within {2} yards to flee for {3} sec. Damage caused may interrupt the effect."] = "Büyü yapan psişik bir çığlık atar ve {2} yard içindeki {1} düşmanı {3} sn boyunca kaçmaya zorlar. Verilen hasar etkiyi kesebilir.",
   ["The current party or raid member becomes the target of your Tricks of the Trade. The threat caused by your next attack and all actions taken for {1} sec afterwards will be transferred to the target. In addition, all damage caused by the target is increased by {2}% during this time."] = "Mevcut grup veya raid üyesi, Tricks of the Trade'inizin hedefi olur. Bir sonraki saldırınızın ve sonraki {1} sn boyunca yaptığınız tüm eylemlerin oluşturduğu tehdit hedefe aktarılır. Ayrıca bu süre boyunca hedefin verdiği tüm hasar %{2} artar.",
   ["The current party or raid member becomes the target of your Tricks of the Trade. The threat caused by your next damaging attack and all actions taken for {1} sec afterwards will be transferred to the target. In addition, all damage caused by the target is increased by {2}% during this time."] = "Mevcut grup veya raid üyesi, Tricks of the Trade'inizin hedefi olur. Bir sonraki hasar veren saldırınızın ve sonraki {1} sn boyunca yaptığınız tüm eylemlerin oluşturduğu tehdit hedefe aktarılır. Ayrıca bu süre boyunca hedefin verdiği tüm hasar %{2} artar.",
   ["The current party or raid member targeted will receive the threat caused by your next damaging attack and all actions taken for {1} sec afterwards."] = "Hedeflenen mevcut grup veya raid üyesi, bir sonraki hasar veren saldırınızın ve sonraki {1} sn boyunca yaptığınız tüm eylemlerin oluşturduğu tehdidi alır.",
   ["The damage dealt by your Flame Shock can now be critical strikes."] = "Flame Shock'unuzun verdiği hasar artık kritik vuruş olabilir.",
   ["The Death Knight freezes her blood to become immune to Stun effects and reduce all damage taken by {1}% plus additional damage reduction based on Defense for {2} sec."] = "Death Knight kanını dondurarak sersemletme etkilerine karşı bağışıklık kazanır ve {2} sn boyunca aldığı tüm hasarı %{1} oranında, ayrıca Defense'e dayalı ek hasar azaltımıyla azaltır.",
   ["The Death Knight freezes his blood to become immune to Stun effects and reduce all damage taken by {1}% plus additional damage reduction based on Defense for {2} sec."] = "Death Knight kanını dondurarak sersemletme etkilerine karşı bağışıklık kazanır ve {2} sn boyunca aldığı tüm hasarı %{1} oranında, ayrıca Defense'e dayalı ek hasar azaltımıyla azaltır.",
   ["The death knight takes on the presence of frost, increasing Stamina by {1}%, armor contribution from cloth, leather, mail and plate items by {2}%, and reducing damage taken by {3}%. Increases threat generated. Only one Presence may be active at a time."] = "Death Knight buz duruşunu benimser; Stamina'yı %{1}, cloth, leather, mail ve plate eşyalardan gelen zırh katkısını %{2} artırır ve aldığı hasarı %{3} azaltır. Oluşturulan tehdidi artırır. Aynı anda yalnızca bir Presence aktif olabilir.",
   ["The Death Knight's freezing aura creates ice beneath his feet, allowing him and his party or raid to walk on water for {1} min. Works while mounted. Any damage will cancel the effect."] = "Death Knight'ın donduran aurası ayaklarının altında buz oluşturur; kendisinin ve grubunun ya da raid'inin {1} dk boyunca su üstünde yürümesini sağlar. Binekteyken de çalışır. Herhangi bir hasar bu etkiyi iptal eder.",
   ["The druid roars, decreasing nearby enemies' melee attack power by {1}. Lasts {2} sec."] = "Druid kükrer ve yakındaki düşmanların yakın dövüş saldırı gücünü {1} azaltır. {2} sn sürer.",
   ["The druid's skin becomes as tough as bark. All damage taken is reduced by {1}%. While protected, damaging attacks will not cause spellcasting delays. This spell is usable while stunned, frozen, incapacitated, feared or asleep. Usable in all forms. Lasts {2} sec."] = "Druid'in derisi ağaç kabuğu kadar sertleşir. Alınan tüm hasar %{1} azalır. Korunma sırasında hasar veren saldırılar büyü yapma gecikmesine yol açmaz. Bu büyü; sersemletilmiş, donmuş, etkisiz hâle getirilmiş, korkutulmuş veya uyutulmuş durumdayken kullanılabilir. Tüm formlarda kullanılabilir. {2} sn sürer.",
   ["The enemy target is swarmed by insects, decreasing their chance to hit by {1}% and causing {2} Nature damage over {3} sec."] = "Düşman hedef böceklerce sarılır, isabet şansını %{1} azaltır ve {3} sn boyunca {2} Doğa hasarı verir.",
   ["The enemy target is swarmed by insects, decreasing their chance to hit with melee and ranged attacks by {1}% and causing {2} Nature damage over {3} sec."] = "Düşman hedef böcekler tarafından sarılır; yakın dövüş ve menzilli saldırılarla isabet etme şansı %{1} azalır ve {3} sn boyunca {2} Doğa hasarı alır.",
   ["The Enrage ability now instantly generates {1} Rage."] = "Enrage yeteneği artık anında {1} Rage oluşturur.",
   ["The hunter and raid members within {1} yards take on the aspects of a pack of cheetahs, increasing movement speed by {2}%. If you are struck under the effect of this aspect, you will be dazed for {3} sec. Only one Aspect can be active at a time."] = "Hunter ve {1} yard içindeki raid üyeleri bir çita sürüsünün özelliklerini benimser; hareket hızı %{2} artar. Bu aspect'in etkisi altındayken vurulursanız {3} sn boyunca sersemlersiniz. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspect of the viper, causing ranged and melee attacks to regenerate mana but reducing your total damage done by {1}%. In addition, you gain {2}% of maximum mana every {3} sec. Mana gained is based on the speed of your ranged weapon. Requires a ranged weapon. Only one Aspect can be active at a time."] = "Hunter engereğin özelliklerini benimser; menzilli ve yakın dövüş saldırıları mana yeniler ancak verdiğiniz toplam hasar %{1} azalır. Ayrıca her {3} sn'de maksimum mananızın %{2}'sini kazanırsınız. Kazanılan mana, menzilli silahınızın hızına bağlıdır. Menzilli silah gerektirir. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspects of a beast, becoming untrackable and increasing melee attack power of the hunter and the hunter's pet by {1}%. Only one Aspect can be active at a time."] = "Hunter bir canavarın özelliklerini benimser; izlenemez hâle gelir ve hunter ile hunter'ın pet'inin yakın dövüş saldırı gücünü %{1} artırır. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspects of a cheetah, increasing movement speed by {1}%. If the hunter is struck, he will be dazed for {2} sec. Only one Aspect can be active at a time."] = "Hunter bir çitanın özelliklerini benimser; hareket hızı %{1} artar. Hunter vurulursa {2} sn boyunca sersemler. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspects of a cheetah, increasing movement speed by {1}%. If the hunter is struck, she will be dazed for {2} sec. Only one Aspect can be active at a time."] = "Hunter bir çitanın özelliklerini benimser; hareket hızı %{1} artar. Hunter vurulursa {2} sn boyunca sersemler. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspects of a dragonhawk, increasing ranged attack power by {1} and chance to dodge by {2}%. Only one Aspect can be active at a time."] = "Hunter bir dragonhawk'ın özelliklerini benimser; menzilli saldırı gücünü {1}, sıyırma şansını %{2} artırır. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspects of a hawk, increasing ranged attack power by {1}. Only one Aspect can be active at a time."] = "Hunter bir şahinin özelliklerini benimser; menzilli saldırı gücünü {1} artırır. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter takes on the aspects of a monkey, increasing chance to dodge by {1}%. Only one Aspect can be active at a time."] = "Hunter bir maymunun özelliklerini benimser; sıyırma şansını %{1} artırır. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The hunter, group and raid members within {1} yards take on the aspect of the wild, increasing Nature resistance by {2}. Only one Aspect can be active at a time."] = "Hunter ile {1} yard içindeki grup ve raid üyeleri vahşi doğanın özelliklerini benimser; Doğa direncini {2} artırır. Aynı anda yalnızca bir Aspect aktif olabilir.",
   ["The paladin sacrifices herself to remove the targeted party member from harm's way. Enemies will stop attacking the protected party member, who will be immune to all harmful attacks but will not be able to take any action for {1} min."] = "Paladin, hedeflenen grup üyesini tehlikeden uzaklaştırmak için kendini feda eder. Düşmanlar korunan grup üyesine saldırmayı bırakır; bu üye tüm zararlı saldırılara karşı bağışıklık kazanır ancak {1} dk boyunca hiçbir eylemde bulunamaz.",
   ["The paladin sacrifices himself to remove the targeted party member from harm's way. Enemies will stop attacking the protected party member, who will be immune to all harmful attacks but will not be able to take any action for {1} min."] = "Paladin, hedeflenen grup üyesini tehlikeden uzaklaştırmak için kendini feda eder. Düşmanlar korunan grup üyesine saldırmayı bırakır; bu üye tüm zararlı saldırılara karşı bağışıklık kazanır ancak {1} dk boyunca hiçbir eylemde bulunamaz.",
   ["The radius of your totems that affect friendly targets is increased to {1} yd."] = "Dost hedefleri etkileyen totemlerinin yarıçapı {1} yarda'ya çıkar.",
   ["The rogue's dodge chance will increase by {1}% for {2} sec."] = "Rogue'un sıyırma şansı {2} sn boyunca %{1} artar.",
   ["The target becomes a Beacon of Light to all targets within a {1} yard radius. Any heals you cast on those targets will also heal the Beacon for {2}% of the amount healed."] = "Hedef, {1} yard yarıçapındaki tüm hedefler için bir Beacon of Light hâline gelir. Bu hedeflere yaptığınız tüm iyileştirmeler, iyileştirilen miktarın %{2}'si kadar Beacon'ı da iyileştirir.",
   ["The target becomes a Beacon of Light to all targets within a {1} yard radius. Any heals you cast on those targets will also heal the Beacon for {2}% of the amount healed. Only one target can be the Beacon of Light at a time. Lasts {3} min."] = "Hedef, {1} yard yarıçapındaki tüm hedefler için bir Beacon of Light hâline gelir. Bu hedeflere yaptığınız tüm iyileştirmeler, iyileştirilen miktarın %{2}'si kadar Beacon'ı da iyileştirir. Aynı anda yalnızca bir hedef Beacon of Light olabilir. {3} dk sürer.",
   ["The targeted undead or demon enemy will be compelled to flee for up to {1} sec. Damage caused may interrupt the effect. Only one target can be turned at a time."] = "Hedeflenen undead veya demon düşman, en fazla {1} sn boyunca kaçmaya zorlanır. Verilen hasar etkiyi kesebilir. Aynı anda yalnızca bir hedef kaçmaya zorlanabilir.",
   ["The warrior enters a berserker rage, removing and granting immunity to Fear, Sap and Incapacitate effects and generating extra rage when taking damage. Lasts {1} sec."] = "Warrior bir berserker öfkesine girer; Fear, Sap ve Incapacitate etkilerini kaldırır ve bunlara karşı bağışıklık sağlar, ayrıca hasar alırken ek öfke üretir. {1} sn sürer.",
   ["The warrior shouts, causing up to {1} enemies within {2} yards to cower in fear. The targeted enemy will be unable to move while cowering. Lasts {3} sec."] = "Warrior bağırır ve {2} yard içindeki en fazla {1} düşmanı korkudan sindirir. Hedeflenen düşman sindiği sürece hareket edemez. {3} sn sürer.",
   ["The warrior shouts, increasing attack power of all raid and party members within {1} yards by {2}. Lasts {3} min."] = "Warrior bağırır ve {1} yard içindeki tüm raid ve grup üyelerinin saldırı gücünü {2} artırır. {3} dk sürer.",
   ["Thorns sprout from the friendly target causing {1} Nature damage to attackers when hit. Lasts {2} min."] = "Dost hedeften dikenler çıkar; vurulduğunda saldıranlara {1} Doğa hasarı verir. {2} dk sürer.",
   ["Throws a distraction, attracting the attention of all nearby monsters for {1} seconds. Does not break stealth."] = "Bir dikkat dağıtıcı fırlatır ve yakındaki tüm canavarların dikkatini {1} saniye boyunca çeker. Stealth'i bozmaz.",
   ["Throws your weapon at the enemy causing {1} damage (based on attack power), reducing the armor on the target by {2}% for {3} sec or removing any invulnerabilities."] = "Silahınızı düşmana fırlatarak {1} hasar (saldırı gücüne dayalı) verir, hedefin zırhını {3} sn boyunca %{2} azaltır veya varsa dokunulmazlıklarını kaldırır.",
   ["Throws your weapon at the enemy causing {1} damage (based on attack power). This ability causes high threat."] = "Silahınızı düşmana fırlatarak {1} hasar (saldırı gücüne dayalı) verir. Bu yetenek yüksek tehdit oluşturur.",
   ["Tosses the enemy target into the air, preventing all action but making them invulnerable for up to {1} sec. Only one target can be affected by your Cyclone at a time."] = "Düşman hedefi havaya fırlatır; tüm eylemlerini engeller ancak en fazla {1} sn boyunca onu dokunulmaz kılar. Aynı anda yalnızca bir hedef Cyclone'unuzdan etkilenebilir.",
   ["Transfers {1} health every {2} sec from the target to the caster. Lasts {3} sec."] = "Hedeften büyü yapana her {2} sn'de {1} sağlık aktarır. {3} sn sürer.",
   ["Transfers {1} health every {2}.{3} sec from the target to the caster. Lasts {4}.{5} sec."] = "Hedeften büyü yapana her {2}.{3} sn'de {1} sağlık aktarır. {4}.{5} sn sürer.",
   ["Transfers {1} health from the target to the caster every {2} sec. Lasts {3} sec."] = "Hedeften büyüyü yapana her {2} sn'de bir {1} can aktarır. {3} sn sürer.",
   ["Transfers {1}% of target's maximum mana every {2} sec from the target to the caster (up to a maximum of {3}% of the caster's maximum mana every {4} sec). Lasts {5} sec."] = "Hedeften büyü yapana, her {2} sn'de hedefin maksimum manasının %{1}'ini aktarır (her {4} sn'de büyü yapanın maksimum manasının en fazla %{3}'ü kadar). {5} sn sürer.",
   ["Transfers {1}% of target's maximum mana every {2}.{3} sec from the target to the caster (up to a maximum of {4}% of the caster's maximum mana every {5}.{6} sec). Lasts {7}.{8} sec."] = "Hedeften büyü yapana, her {2}.{3} sn'de hedefin maksimum manasının %{1}'ini aktarır (her {5}.{6} sn'de büyü yapanın maksimum manasının en fazla %{4}'ü kadar). {7}.{8} sn sürer.",
   ["Transforms the Druid into Moonkin Form. While in this form the armor contribution from items is increased by {1}% and all party members within {2} yards have their spell critical chance increased by {3}%. The Moonkin can only cast Balance spells while shapeshifted.The act of shapeshifting frees the caster of Polymorph and Movement Impairing effects."] = "Druid'i Moonkin Form'a dönüştürür. Bu formdayken eşyalardan gelen zırh katkısı %{1} artar ve {2} yarda içindeki tüm grup üyelerinin büyü kritik şansı %{3} artar. Moonkin şekil değiştirmişken yalnızca Balance büyüleri yapabilir. Şekil değiştirme eylemi büyüyü yapanı Polymorph ve Hareket Engelleyici etkilerden kurtarır.",
   ["Transforms the enemy into a harmless rabbit, forcing it to scamper around for up to {1} sec. While wandering, the rabbit cannot attack or cast spells but will regenerate very quickly. Any damage will transform the target back into its normal form. Only one target can be polymorphed at a time. Only works on Beasts, Humanoids and Critters."] = "Düşmanı zararsız bir tavşana dönüştürür ve en fazla {1} sn boyunca etrafta koşuşturmaya zorlar. Dolanırken tavşan saldıramaz veya büyü yapamaz, ancak çok hızlı şekilde yenilenir. Herhangi bir hasar hedefi normal hâline geri döndürür. Aynı anda yalnızca bir hedef polymorph edilebilir. Yalnızca Beast, Humanoid ve Critter'larda işe yarar.",
   ["Transforms the enemy into a pig, forcing it to wander around for up to {1} sec. While wandering, the pig cannot attack or cast spells but will regenerate very quickly. Any damage will transform the target back into its normal form. Only one target can be polymorphed at a time. Only works on Beasts, Humanoids and Critters."] = "Düşmanı bir domuza dönüştürür ve en fazla {1} sn boyunca etrafta dolanmaya zorlar. Dolanırken domuz saldıramaz veya büyü yapamaz, ancak çok hızlı şekilde yenilenir. Herhangi bir hasar hedefi normal hâline geri döndürür. Aynı anda yalnızca bir hedef polymorph edilebilir. Yalnızca Beast, Humanoid ve Critter'larda işe yarar.",
   ["Transforms the enemy into a sheep, forcing it to wander around for up to {1} sec. While wandering, the sheep cannot attack or cast spells but will regenerate very quickly. Any damage will transform the target back into its normal form. Only one target can be polymorphed at a time. Only works on Beasts, Humanoids and Critters."] = "Düşmanı bir koyuna dönüştürür ve en fazla {1} sn boyunca etrafta dolanmaya zorlar. Dolanırken koyun saldıramaz veya büyü yapamaz, ancak çok hızlı şekilde yenilenir. Herhangi bir hasar hedefi normal hâline geri döndürür. Aynı anda yalnızca bir hedef polymorph edilebilir. Yalnızca Beast, Humanoid ve Critter'larda işe yarar.",
   ["Transforms the enemy into a turtle, forcing it to wander around for up to {1} sec. While wandering, the turtle cannot attack or cast spells but will regenerate very quickly. Any damage will transform the target back into its normal form. Only one target can be polymorphed at a time. Only works on Beasts, Humanoids and Critters."] = "Düşmanı bir kaplumbağaya dönüştürür ve en fazla {1} sn boyunca etrafta dolanmaya zorlar. Dolanırken kaplumbağa saldıramaz veya büyü yapamaz, ancak çok hızlı şekilde yenilenir. Herhangi bir hasar hedefi normal hâline geri döndürür. Aynı anda yalnızca bir hedef polymorph edilebilir. Yalnızca Beast, Humanoid ve Critter'larda işe yarar.",
   ["Turns the Shaman into a Ghost Wolf, increasing speed by {1}%. As a Ghost Wolf, the Shaman is less hindered by effects that would reduce movement speed. Only useable outdoors."] = "Shaman'ı bir Ghost Wolf'a dönüştürür ve hızını %{1} artırır. Ghost Wolf hâlindeyken Shaman, hareket hızını azaltacak etkilerden daha az etkilenir. Yalnızca açık alanda kullanılabilir.",
   ["Unleashes the energy of a Seal spell to judge an enemy for {1} sec, giving each attack a chance to restore {2}% of the attacker's base mana. Refer to individual Seals for additional Judgement effect. Only one Judgement per Paladin can be active at any one time."] = "Bir Seal büyüsünün enerjisini açığa çıkararak bir düşmanı {1} sn boyunca Judgement etkisi altına alır; her saldırıya, saldıranın temel manasının %{2}'sini geri kazandırma şansı verir. Ek Judgement etkisi için ilgili Seal'lara bakın. Her Paladin için aynı anda yalnızca bir Judgement aktif olabilir.",
   ["Unleashes the energy of a Seal spell to judge an enemy for {1} sec, granting attacks made against the judged enemy a chance of healing the attacker for {2}% of their maximum health. Refer to individual Seals for additional Judgement effect. Only one Judgement per Paladin can be active at any one time."] = "Bir Seal büyüsünün enerjisini açığa çıkararak bir düşmanı {1} sn boyunca Judgement etkisi altına alır; bu düşmana yapılan saldırılara, saldıranı maksimum sağlığının %{2}'si kadar iyileştirme şansı verir. Ek Judgement etkisi için ilgili Seal'lara bakın. Her Paladin için aynı anda yalnızca bir Judgement aktif olabilir.",
   ["Unleashes the energy of a Seal spell to judge an enemy for {1} sec, preventing them from fleeing and limiting their movement speed. Refer to individual Seals for additional Judgement effect. Only one Judgement per Paladin can be active at any one time."] = "Bir Seal büyüsünün enerjisini açığa çıkararak bir düşmanı {1} sn boyunca Judgement etkisi altına alır; kaçmasını engeller ve hareket hızını sınırlar. Ek Judgement etkisi için ilgili Seal'lara bakın. Her Paladin için aynı anda yalnızca bir Judgement aktif olabilir.",
   ["Unleashes the energy of a Seal spell to judge an enemy, giving each attack a chance to restore {1}% of the attacker's base mana. Refer to individual Seals for additional Judgement effect. Only one Judgement per Paladin can be active at any one time."] = "Bir Seal büyüsünün enerjisini açığa çıkararak bir düşmanı Judgement etkisi altına alır; her saldırıya, saldıranın temel manasının %{1}'ini geri kazandırma şansı verir. Ek Judgement etkisi için ilgili Seal'lara bakın. Her Paladin için aynı anda yalnızca bir Judgement aktif olabilir.",
   ["Unleashing this Seal's energy will judge an enemy for {1} sec, preventing them from fleeing. Only one Judgement per Paladin can be active at any one time."] = "Bu Seal'ın enerjisini açığa çıkarmak bir düşmanı {1} sn boyunca Judgement etkisi altına alır ve kaçmasını engeller. Her Paladin için aynı anda yalnızca bir Judgement aktif olabilir.",
   ["Unleashing this Seal's energy will judge an enemy, instantly causing Holy damage at the cost of health equal to {1}% of the damage caused."] = "Bu Seal'ın enerjisini açığa çıkarmak bir düşmanı Judgement etkisi altına alır ve verilen hasarın %{1}'ine eşit sağlık karşılığında anında Kutsal hasar verir.",
   ["Unlike most casters, a Death Knight's spells cause double damage on critical hits."] = "Çoğu büyücünün aksine, bir Death Knight'ın büyüleri kritik vuruşlarda iki kat hasar verir.",
   ["Upon death, the priest becomes the Spirit of Redemption for {1} sec. The Spirit of Redemption cannot move, attack, be attacked or targeted by any spells or effects. While in this form the priest can cast any healing spell free of cost. When the effect ends, the priest dies."] = "Ölümde priest, {1} sn boyunca Spirit of Redemption olur. Spirit of Redemption hareket edemez, saldıramaz, saldırılamaz veya herhangi bir büyü ya da etkiyle hedeflenemez. Bu formdayken priest herhangi bir iyileştirme büyüsünü maliyetsiz yapabilir. Etki sona erdiğinde priest ölür.",
   ["Use: Target is cured of poisons up to level {1}. ({2} Min Cooldown)"] = "Kullanım: Hedef, {1}. seviyeye kadar olan zehirlerden arındırılır. ({2} dk Bekleme Süresi)",
   ["Wards the friendly target against Fear. The next Fear effect used against the target will fail, using up the ward. Lasts {1} min."] = "Dost hedefi Fear'a karşı korur. Hedefe karşı kullanılan bir sonraki Fear etkisi başarısız olur ve bu korumayı tüketir. {1} dk sürer.",
   ["When activated, gives your next Flash of Light, Holy Light, or Holy Shock spell a {1}% critical effect chance."] = "Etkinleştirildiğinde, sonraki Flash of Light, Holy Light veya Holy Shock büyüne %{1} kritik etki şansı verir.",
   ["When activated, increases the critical strike chance of your next Sinister Strike, Backstab, Ambush, or Eviscerate by {1}%."] = "Etkinleştirildiğinde, sonraki Sinister Strike, Backstab, Ambush veya Eviscerate'in kritik vurma şansını %{1} artırır.",
   ["When activated, increases your Dodge and Parry chance by {1}% for {2} sec."] = "Etkinleştirildiğinde, Dodge ve Parry şansını {2} sn boyunca %{1} artırır.",
   ["When activated, increases your physical damage by {1}% and makes you immune to Fear effects, but lowers your armor and all resistances by {2}%. Lasts {3} sec."] = "Etkinleştirildiğinde, fiziksel hasarını %{1} artırır ve seni Fear etkilerine karşı bağışık kılar ama zırhını ve tüm dirençlerini %{2} azaltır. {3} sn sürer.",
   ["When activated, reduces the Mana cost of your next spell by {1}% and increases its critical effect chance by {2}% if it is capable of a critical effect."] = "Etkinleştirildiğinde, sonraki büyünün Mana maliyetini %{1} azaltır ve kritik etki mümkünse kritik etki şansını %{2} artırır.",
   ["When activated, sacrifices your summoned demon to grant you an effect that lasts {1} min. The effect is canceled if any Demon is summoned.Imp: Increases your Fire damage by {2}%.Voidwalker: Restores {3}% of total Health every {4} sec.Succubus: Increases your Shadow damage by {5}%.Felhunter: Restores {6}% of total Mana every {7} sec."] = "Etkinleştirildiğinde, çağırdığın iblisi feda ederek sana {1} dk süren bir etki verir. Herhangi bir İblis çağrılırsa etki iptal olur. Imp: Ateş hasarını %{2} artırır. Voidwalker: Her {4} sn'de bir toplam Can'ın %{3} kadarını yeniler. Succubus: Gölge hasarını %{5} artırır. Felhunter: Her {7} sn'de bir toplam Mana'nın %{6} kadarını yeniler.",
   ["When activated, this ability immediately finishes the cooldown on your other Rogue abilities."] = "Etkinleştirildiğinde, bu yetenek diğer Rogue yeteneklerinin bekleme süresini anında bitirir.",
   ["When activated, this ability temporarily grants you {1}% of your maximum hit points for {2} seconds. After the effect expires, the hit points are lost."] = "Etkinleştirildiğinde, bu yetenek sana geçici olarak maksimum can puanının %{1} kadarını {2} saniye boyunca verir. Etki sona erdikten sonra can puanları kaybolur.",
   ["When activated, this spell causes each of your Fire damage spell hits to increase your critical strike chance with Fire damage spells by {1}%. This effect lasts until you have caused {2} critical strikes with Fire spells."] = "Etkinleştirildiğinde, bu büyü her Ateş hasar büyünün isabetinde Ateş hasar büyüleriyle kritik vurma şansını %{1} artırır. Bu etki, Ateş büyüleriyle {2} kritik vuruş yapana kadar sürer.",
   ["When activated, this spell finishes the cooldown on all of your Frost spells."] = "Etkinleştirildiğinde, bu büyü tüm Buz büyülerinin bekleme süresini bitirir.",
   ["When activated, this spell gives your next Fire, Frost, or Nature damage spell a {1}% critical strike chance and reduces the mana cost by {2}%."] = "Etkinleştirildiğinde, bu büyü sonraki Ateş, Buz veya Doğa hasar büyüne %{1} kritik vurma şansı verir ve mana maliyetini %{2} azaltır.",
   ["When activated, your next Mage spell with a casting time less than {1} sec becomes an instant cast spell."] = "Etkinleştirildiğinde, okuma süresi {1} sn'den az olan sonraki Mage büyün anında okunan bir büyü olur.",
   ["When activated, your next Nature spell becomes an instant cast spell."] = "Etkinleştirildiğinde, sonraki Doğa büyün anında okunan bir büyü olur.",
   ["When activated, your next Nature spell with a casting time less than {1} sec. becomes an instant cast spell."] = "Etkinleştirildiğinde, okuma süresi {1} sn'den az olan sonraki Doğa büyün anında okunan bir büyü olur.",
   ["When activated, your spells deal {1}% more damage while costing {2}% more mana to cast. This effect lasts {3} sec."] = "Etkinleştirildiğinde, büyülerin %{1} daha fazla hasar verir ama yapmak için %{2} daha fazla manaya mal olur. Bu etki {3} sn sürer.",
   ["When active, {1}% of all damage taken by the caster is taken by your Imp, Voidwalker, Succubus, or Felhunter demon instead. In addition, both the demon and master will inflict {2}% more damage. Lasts as long as the demon is active."] = "Aktifken, büyüyü yapanın aldığı tüm hasarın %{1} kadarı bunun yerine Imp, Voidwalker, Succubus veya Felhunter iblisin tarafından alınır. Buna ek olarak, hem iblis hem de efendi %{2} daha fazla hasar verir. İblis aktif olduğu sürece sürer.",
   ["When below {1}% health all damage taken is reduced by {2}% and your Pyroblast spell's cast time is reduced by {3}.{4} secs while the cooldown is increased by -{5}.{6} secs."] = "Sağlığınız %{1}'in altındayken alınan tüm hasar %{2} azalır ve Pyroblast büyünüzün okuma süresi {3}.{4} sn azalırken bekleme süresi -{5}.{6} sn artar.",
   ["When below {1}% health all damage taken is reduced by {2}% and your Pyroblast spell's cast time is reduced by {3}.{4} secs while the cooldown is increased by {5} secs."] = "Sağlığınız %{1}'in altındayken alınan tüm hasar %{2} azalır ve Pyroblast büyünüzün okuma süresi {3}.{4} sn azalırken bekleme süresi {5} sn artar.",
   ["When cast, you no longer lose casting time due to taking damage. Lasts {1} sec."] = "Büyü yapıldığında, hasar almaktan dolayı artık okuma süresi kaybetmezsiniz. {1} sn sürer.",
   ["When Interrupted or Silenced you have a chance to become immune to the next Interrupt or Silence effect. Lasts {1} sec."] = "Kesintiye uğradığınızda veya susturulduğunuzda, bir sonraki Kesinti veya Susturma etkisine karşı bağışıklık kazanma şansınız olur. {1} sn sürer.",
   ["When used, adds {1} combo points to your target. You must add to or use those combo points within {2} sec or the combo points are lost."] = "Kullanıldığında, hedefine {1} combo puanı ekler. Bu combo puanlarını {2} sn içinde eklemen veya kullanman gerekir, yoksa combo puanları kaybolur.",
   ["When you absorb damage your spell damage is increased by a percentage of the amount absorbed for {1} sec."] = "Hasar emdiğinizde, büyü hasarınız {1} sn boyunca emilen miktarın bir yüzdesi kadar artar.",
   ["When your pet is under the effects of Bestial Wrath, you also go into a rage causing {1}% additional damage and reducing mana costs of all spells by {2}% for {3} sec. While enraged, you do not feel pity or remorse or fear and you cannot be stopped unless killed."] = "Pet'iniz Bestial Wrath etkisi altındayken siz de bir öfkeye kapılırsınız; {3} sn boyunca %{1} ek hasar verir ve tüm büyülerin mana maliyetini %{2} azaltırsınız. Öfkeliyken acıma, pişmanlık veya korku hissetmezsiniz ve öldürülmediğiniz sürece durdurulamazsınız.",
   ["Whenever you dodge an attack you gain an Unfair Advantage, striking back for {1}% of your main hand weapon's damage."] = "Bir saldırıyı sıyırdığınızda bir Unfair Advantage kazanırsınız ve ana el silahınızın hasarının %{1}'i kadar karşılık verirsiniz.",
   ["Whenever you take damage from or block a melee attack you cause damage equal to {1}% of your block value."] = "Bir yakın dövüş saldırısından hasar aldığınızda veya onu bloklarsanız, blok değerinizin %{1}'ine eşit hasar verirsiniz.",
   ["While active, any time an enemy strikes the caster they have a {1}% chance to become afflicted by Entangling Roots (Rank {2}). Only useable outdoors. {3} charge. Lasts {4} sec."] = "Aktifken, bir düşman büyüyü yapana her vurduğunda Entangling Roots'a (Seviye {2}) yakalanma için %{1} şansa sahip olurlar. Yalnızca dış mekanda kullanılabilir. {3} şarj. {4} sn sürer.",
   ["While active, any time an enemy strikes the caster they have a {1}% chance to become afflicted by Entangling Roots (Rank {2}). {3} charges. Lasts {4} sec."] = "Etkin olduğu sürece, bir düşman büyü yapana her vurduğunda %{1} ihtimalle Entangling Roots (Rank {2}) ile etkilenir. {3} şarj. {4} sn sürer.",
   ["While affected by your Kidney Shot ability, the target receives an additional {1}% damage from all sources."] = "Kidney Shot yeteneğinden etkilenirken, hedef tüm kaynaklardan %{1} ek hasar alır.",
   ["While applied to target weapon it increases damage dealt by direct spells by {1}% and spell critical strike rating by {2}. Lasts for {3} hour."] = "Hedef silaha uygulandığında, doğrudan büyülerin verdiği hasarı %{1} ve büyü kritik vurma derecesini {2} artırır. {3} saat sürer.",
   ["While applied to target weapon it increases damage dealt by periodic spells by {1}% and spell haste rating by {2}. Lasts for {3} hour."] = "Hedef silaha uygulandığında, periyodik büyülerin verdiği hasarı %{1} ve büyü hız derecesini {2} artırır. {3} saat sürer.",
   ["While Aspect of the Hawk is active, all normal ranged attacks have a {1}% chance of increasing ranged attack speed by {2}% for {3} sec."] = "Aspect of the Hawk aktifken, tüm normal menzilli saldırılar {3} sn boyunca menzilli saldırı hızını %{2} artırmak için %{1} şansa sahiptir.",
   ["While in Cat, Bear or Dire Bear Form, the Leader of the Pack increases ranged and melee critical chance of all party members within {1} yards by {2}%."] = "Cat, Bear veya Dire Bear Form'dayken, Leader of the Pack {1} yarda içindeki tüm grup üyelerinin menzilli ve yakın dövüş kritik şansını %{2} artırır.",
   ["While your pet is active, you and your pet will regenerate {1}% of total health every {2} sec."] = "Evcil hayvanın aktifken, sen ve evcil hayvanın her {2} sn'de bir toplam canın %{1} kadarını yeniler.",
   ["Wounds the target causing them to bleed for {1} damage plus an additional {2} (based on weapon damage) over {3} sec."] = "Hedefi yaralar ve {3} sn boyunca {1} hasar artı ek {2} (silah hasarına dayalı) kanamasına neden olur.",
   ["Wounds the target causing them to bleed for {1} damage plus an additional {2} (based on weapon damage) over {3} sec. If used while your target is above {4}% health, Rend does {5}% more damage."] = "Hedefi yaralar ve {3} sn boyunca {1} hasar artı ek {2} (silah hasarına dayalı) kanamasına neden olur. Hedefiniz %{4} sağlığın üzerindeyken kullanılırsa, Rend %{5} daha fazla hasar verir.",
   ["Yanks the caster through the twisting nether back to Dalaran. Speak to an Innkeeper in a different place to change your home location."] = "Büyü yapanı twisting nether üzerinden Dalaran'a geri çeker. Ev konumunuzu değiştirmek için farklı bir yerdeki Innkeeper ile konuşun.",
   ["You attempt to disengage from combat, leaping backwards. Can only be used while in combat."] = "Geriye sıçrayarak savaştan uzaklaşmaya çalışırsınız. Yalnızca savaştayken kullanılabilir.",
   ["You attempt to finish the wounded target off, firing a long range attack dealing {1}% weapon damage plus {2}. Kill Shot can only be used on enemies that have {3}% or less health."] = "Yaralı hedefin işini bitirmeye çalışırsınız; %{1} silah hasarı artı {2} veren uzun menzilli bir saldırı yaparsınız. Kill Shot yalnızca %{3} veya daha az sağlığa sahip düşmanlarda kullanılabilir.",
   ["You become encased in a block of ice, protecting you from all physical attacks and spells for {1} sec, but during that time you cannot attack, move or cast spells."] = "Bir buz bloğunun içine hapsolarak {1} sn boyunca tüm fiziksel saldırılardan ve büyülerden korunursun ama bu süre boyunca saldıramaz, hareket edemez veya büyü yapamazsın.",
   ["You become encased in a block of ice, protecting you from all physical attacks and spells for {1} sec, but during that time you cannot attack, move or cast spells. Also causes Hypothermia, preventing you from recasting Ice Block for {2} sec."] = "Bir buz bloğunun içine hapsolursunuz; bu sizi {1} sn boyunca tüm fiziksel saldırılardan ve büyülerden korur, ancak bu süre boyunca saldıramaz, hareket edemez veya büyü yapamazsınız. Ayrıca Hypothermia'ya neden olur ve {2} sn boyunca Ice Block'u yeniden kullanmanızı engeller.",
   ["You devastate the area, causing Corruption (Rank {1}) to all targets within {2} yards. In addition, your Corruption spell will do {3} Shadow damage to the target when it finishes its duration."] = "Alanı harap edersiniz; {2} yard içindeki tüm hedeflere Corruption (Rank {1}) uygularsınız. Ayrıca, Corruption büyünüz süresi bittiğinde hedefe {3} Gölge hasarı verir.",
   ["You gain {1}% of your total mana over {2} sec, but the amount healed by your Flash of Light, Holy Light, and Holy Shock spells is reduced by {3}%."] = "{2} sn boyunca toplam mananızın %{1}'ini kazanırsınız, ancak Flash of Light, Holy Light ve Holy Shock büyülerinizin iyileştirdiği miktar %{3} azalır.",
   ["You hurl molten lava at the target, dealing {1} to {2} Fire damage. If your Flame Shock is on the target, Lava Burst will deal a critical strike."] = "Hedefe erimiş lav fırlatırsınız ve {1} ila {2} Ateş hasarı verirsiniz. Flame Shock'unuz hedefin üzerindeyse, Lava Burst kritik vuruş yapar.",
   ["You regenerate {1}% of your total health over {2} sec. This ability requires an Enrage effect, consumes all Enrage effects and prevents any from affecting you for the full duration."] = "{2} sn boyunca toplam sağlığınızın %{1}'ini yenilersiniz. Bu yetenek bir Enrage etkisi gerektirir, tüm Enrage etkilerini tüketir ve tüm süre boyunca herhangi birinin sizi etkilemesini engeller.",
   ["You retain up to {1} of your rage points when you change stances."] = "Duruş değiştirdiğinde rage puanlarının en fazla {1} kadarını korursun.",
   ["You summon a Demonic Circle at your feet, lasting {1} min. You can only have one Demonic Circle active at a time."] = "Ayaklarınızın dibinde bir Demonic Circle çağırırsınız; {1} dk sürer. Aynı anda yalnızca bir Demonic Circle aktif olabilir.",
   ["Your Ambush and Backstab hits have a chance to unbalance a target, increasing the time between their melee and ranged attacks by {1}%, and reducing movement speed by {2}% for {3} sec."] = "Ambush ve Backstab vuruşlarınızın hedefin dengesini bozma şansı vardır; yakın dövüş ve menzilli saldırıları arasındaki süreyi %{1} uzatır ve {3} sn boyunca hareket hızını %{2} azaltır.",
   ["Your Cleanse spell has a chance to increase the target's resistance to Disease, Magic and Poison."] = "Cleanse büyünüzün, hedefin hastalık, büyü ve zehre karşı direncini artırma şansı vardır.",
   ["Your critical strikes cause the opponent to bleed, dealing {1}% of your melee weapon's average damage over {2} sec."] = "Kritik vuruşların rakibin kanamasına yol açarak {2} sn boyunca yakın dövüş silahının ortalama hasarının %{1} kadarını verir.",
   ["Your critical strikes from abilities that add combo points have a {1}% chance to add an additional combo point."] = "Combo puanı ekleyen yeteneklerden gelen kritik vuruşların ek bir combo puanı eklemek için %{1} şansa sahiptir.",
   ["Your critical strikes from Cat Form abilities that add combo points have a {1}% chance to add an additional combo point."] = "Combo puanı ekleyen Cat Form yeteneklerinden gelen kritik vuruşların ek bir combo puanı eklemek için %{1} şansa sahiptir.",
   ["Your critical strikes from Fire damage spells cause the target to burn for an additional {1}% of your spell's damage over {2} sec."] = "Ateş hasar büyülerinden gelen kritik vuruşların hedefin {2} sn boyunca büyünün hasarının ek %{1} kadarıyla yanmasına yol açar.",
   ["Your damaging Blast Wave and Dragon's Breath spells have a chance to make your next Flamestrike spell instant cast and cost no mana."] = "Hasar veren Blast Wave ve Dragon's Breath büyülerinizin, bir sonraki Flamestrike büyünüzü anında okunur ve mana harcamayan hâle getirme şansı vardır.",
   ["Your finishing moves have a chance per combo point to restore {1} energy."] = "Bitirici hareketlerinizin, her combo point başına {1} enerji geri kazandırma şansı vardır.",
   ["Your finishing moves have a {1}% chance per combo point to restore {2} energy."] = "Bitirme hareketlerin combo puanı başına {2} energy yenilemek için %{1} şansa sahiptir.",
   ["Your Fire and Frost spell criticals will refund {1}% of their base mana cost."] = "Ateş ve Buz büyü kritiklerin temel mana maliyetinin %{1} kadarını geri verir.",
   ["Your Healing Wave spells have a {1}% chance to increase the effect of subsequent Healing Wave spells on that target by {2}% for {3} sec. This effect will stack up to {4} times."] = "Healing Wave büyülerin, o hedefteki sonraki Healing Wave büyülerinin etkisini {3} sn boyunca %{2} artırmak için %{1} şansa sahiptir. Bu etki en fazla {4} kez üst üste birikir.",
   ["Your Heroic Strike, Bloodthirst, and Whirlwind hits have a chance of making your next Slam instant for {1} sec."] = "Heroic Strike, Bloodthirst ve Whirlwind vuruşlarınızın, bir sonraki Slam'inizi {1} sn boyunca anında hâle getirme şansı vardır.",
   ["Your Holy Shock critical hits reduce the cast time of your next Flash of Light by {1}.{2} sec or increase the critical chance of your next Holy Light by {3}%."] = "Holy Shock kritik vuruşlarınız, bir sonraki Flash of Light'ınızın okuma süresini {1}.{2} sn azaltır veya bir sonraki Holy Light'ınızın kritik şansını %{3} artırır.",
   ["Your Leader of the Pack ability also causes affected targets to have a {1}% chance to heal themselves for a percentage of their total health when they critically hit with a melee or ranged attack. The healing effect cannot occur more than once every {2} sec."] = "Leader of the Pack yeteneğiniz, etkilenen hedeflerin yakın dövüş veya menzilli bir saldırıyla kritik vurduklarında %{1} ihtimalle toplam sağlıklarının bir yüzdesi kadar kendilerini iyileştirmesini de sağlar. İyileştirme etkisi her {2} sn'de bir defadan fazla gerçekleşemez.",
   ["Your melee critical strikes have a chance to give you energy."] = "Yakın dövüş kritik vuruşlarınızın size enerji verme şansı vardır.",
   ["Your next Imp, Voidwalker, Succubus, or Felhunter Summon spell has its casting time reduced by {1}.{2} sec and its Mana cost reduced by {3}%."] = "Sonraki Imp, Voidwalker, Succubus veya Felhunter Çağırma büyünün okuma süresi {1}.{2} sn azalır ve Mana maliyeti %{3} azalır.",
   ["Your next melee weapon swing strikes an additional nearby opponent."] = "Bir sonraki yakın dövüş silah savurmanız, yakındaki ek bir rakibe de vurur.",
   ["Your next {1} melee attacks strike an additional nearby opponent."] = "Sonraki {1} yakın dövüş saldırın yakındaki ek bir rakibe vurur.",
   ["Your next {1} special ability attacks have an additional {2}% to critically hit but all damage taken is increased by {3}%. Lasts {4} sec."] = "Bir sonraki {1} özel yetenek saldırınızın kritik vurma şansı %{2} daha fazladır, ancak alınan tüm hasar %{3} artar. {4} sn sürer.",
   ["Your normal melee critical strikes increase the effectiveness of Bleed effects on the target by {1}% for {2} min."] = "Normal yakın dövüş kritik vuruşlarınız, hedefteki kanama etkilerinin etkinliğini {2} dk boyunca %{1} artırır.",
   ["Your offensive spell crits will increase your chance to get a critical strike with melee attacks by {1}% for {2} sec."] = "Saldırı büyü kritiklerin yakın dövüş saldırılarıyla kritik vurma şansını {2} sn boyunca %{1} artırır.",
   ["Your ranged criticals have a chance to grant you Expose Weakness. Expose Weakness increases your attack power by {1}% of your Agility for {2} sec."] = "Menzilli kritik vuruşlarınızın size Expose Weakness kazandırma şansı vardır. Expose Weakness, saldırı gücünüzü {2} sn boyunca Agility'nizin %{1}'i kadar artırır.",
   ["Your Scorch spells have a chance to cause your target to be vulnerable to spell damage, increasing spell critical strike chance against that target."] = "Scorch büyülerinizin, hedefinizi büyü hasarına karşı savunmasız hâle getirme şansı vardır; bu hedefe karşı büyü kritik vurma şansını artırır.",
   ["Your Scorch spells have a {1}% chance to cause your target to be vulnerable to Fire damage. This vulnerability increases the Fire damage dealt to your target by {2}% and lasts {3} sec. Stacks up to {4} times."] = "Scorch büyülerin hedefini Ateş hasarına karşı savunmasız kılmak için %{1} şansa sahiptir. Bu savunmasızlık hedefine verilen Ateş hasarını %{2} artırır ve {3} sn sürer. En fazla {4} kez üst üste birikir.",
   ["Your Shadow Bolt and Haunt spells apply the Shadow Embrace effect, increasing all periodic shadow damage dealt to the target by you by {1}%, and reduces all periodic healing done to the target by {2}%. Lasts for {3} sec. Stacks up to {4} times."] = "Shadow Bolt ve Haunt büyüleriniz Shadow Embrace etkisini uygular; hedefe sizin tarafınızdan verilen tüm periyodik gölge hasarını %{1} artırır ve hedefe yapılan tüm periyodik iyileştirmeyi %{2} azaltır. {3} sn sürer. En fazla {4} kez üst üste binebilir.",
   ["Your Shadow Bolt critical strikes increase Shadow damage dealt to the target by {1}% until {2} non-periodic damage sources are applied. Effect lasts a maximum of {3} sec."] = "Shadow Bolt kritik vuruşların, {2} periyodik olmayan hasar kaynağı uygulanana kadar hedefe verilen Gölge hasarını %{1} artırır. Etki en fazla {3} sn sürer.",
   ["Your Shadow damage spells have a {1}% chance to cause your target to be vulnerable to Shadow damage. This vulnerability increases the Shadow damage dealt to your target by {2}% and lasts {3} sec. Stacks up to {4} times."] = "Gölge hasar büyülerin hedefini Gölge hasarına karşı savunmasız kılmak için %{1} şansa sahiptir. Bu savunmasızlık hedefine verilen Gölge hasarını %{2} artırır ve {3} sn sürer. En fazla {4} kez üst üste birikir.",
   ["Your Shadow Word: Pain, Mind Flay and Vampiric Touch spells also increase the chance for harmful spells to hit by {1}%."] = "Shadow Word: Pain, Mind Flay ve Vampiric Touch büyüleriniz, zararlı büyülerin isabet etme şansını da %{1} artırır.",
   ["Your spell criticals have a chance to cause your next Smite or Flash Heal spell to be instant cast, cost no mana but be incapable of a critical hit. This effect lasts {1} sec."] = "Büyü kritik vuruşlarınızın, bir sonraki Smite veya Flash Heal büyünüzü anında okunur ve mana harcamayan ancak kritik vuruş yapamayan hâle getirme şansı vardır. Bu etki {1} sn sürer.",
   ["Your spell criticals will refund a percentage of the base mana cost."] = "Büyü kritik vuruşlarınız, temel mana maliyetinin bir yüzdesini geri öder.",
   ["Your successful Chimera Shot and Multi-Shot attacks have a chance to Daze the target for {1} sec."] = "Başarılı Chimera Shot ve Multi-Shot saldırılarınızın, hedefi {1} sn boyunca sersemletme şansı vardır.",
   ["Your successful ranged attacks have a chance to increase your critical strike chance with all attacks by {1}% for {2} sec."] = "Başarılı menzilli saldırılarınızın, tüm saldırılarla kritik vurma şansınızı {2} sn boyunca %{1} artırma şansı vardır.",
   ["Zooms in the hunter's vision. Only usable outdoors. Lasts {1} min."] = "Hunter'ın görüşünü yakınlaştırır. Yalnızca açık alanda kullanılabilir. {1} dk sürer.",
   ["{1} Health, plus {2} per sec"] = "{1} Sağlık, artı sn başına {2}",
};
